import json
from collections import defaultdict
import sys

def solve(input_file: str, solution_file: str):
    sys.setrecursionlimit(1200000)
    with open(input_file, 'r') as f:
        data = json.load(f)

    nodes_data = data["nodes"]
    root_eclasses = list(data["root_eclasses"])

    node_cost = {}
    node_eclass = {}
    eclass_nodes = defaultdict(list)
    all_node_ids = set(nodes_data.keys())

    for nid, ninfo in nodes_data.items():
        node_cost[nid] = ninfo["cost"]
        ec = ninfo["eclass"]
        node_eclass[nid] = ec
        eclass_nodes[ec].append(nid)

    all_eclasses = set(eclass_nodes.keys())

    # Map children: they could be node_ids (map to eclass) or eclass ids directly
    node_children_eclasses = {}
    for nid, ninfo in nodes_data.items():
        child_eclasses = []
        for c in ninfo["children"]:
            if c in node_eclass:
                child_eclasses.append(node_eclass[c])
            elif c in all_eclasses:
                child_eclasses.append(c)
            else:
                child_eclasses.append(c)
                if c not in all_eclasses:
                    eclass_nodes[c] = []
                    all_eclasses.add(c)
        node_children_eclasses[nid] = child_eclasses

    # Deduplicate children eclasses per node (for cost computation)
    node_children_unique = {}
    for nid in node_children_eclasses:
        node_children_unique[nid] = list(set(node_children_eclasses[nid]))

    INF = float('inf')
    eclass_best_cost = defaultdict(lambda: INF)
    eclass_best_node = {}

    # Iterative relaxation
    changed = True
    iteration = 0
    while changed and iteration < 500:
        changed = False
        iteration += 1
        for ec in all_eclasses:
            for nid in eclass_nodes[ec]:
                children = node_children_unique[nid]
                cost = node_cost[nid]
                valid = True
                for cec in children:
                    c_cost = eclass_best_cost[cec]
                    if c_cost == INF:
                        valid = False
                        break
                    cost += c_cost
                if valid and cost < eclass_best_cost[ec] - 1e-15:
                    eclass_best_cost[ec] = cost
                    eclass_best_node[ec] = nid
                    changed = True

    result = []
    visited_eclasses = set()

    def extract(ec):
        if ec in visited_eclasses:
            return
        visited_eclasses.add(ec)
        nid = eclass_best_node.get(ec)
        if nid is None:
            return
        result.append(nid)
        for cec in node_children_unique[nid]:
            extract(cec)

    for rec in root_eclasses:
        extract(rec)

    with open(solution_file, 'w') as f:
        json.dump(result, f)

