def solve(input_file: str, solution_file: str):
    import json
    from collections import defaultdict, deque
    import time
    import random

    with open(input_file, 'r') as f:
        data = json.load(f)

    delay_map = data['delay']
    resource_map = data['resource']
    nodes = data['nodes']
    edges = data['edges']

    node_ids = [n[0] for n in nodes]
    node_set = set(node_ids)
    node_type = {n[0]: n[1] for n in nodes}
    node_delay = {n[0]: delay_map[n[1]] for n in nodes}
    node_resource = {n[0]: n[1] for n in nodes}

    num_nodes = len(nodes)

    successors = defaultdict(list)
    predecessors = defaultdict(list)
    for src, tgt, _ in edges:
        successors[src].append(tgt)
        predecessors[tgt].append(src)

    # Compute ASAP
    asap = {}
    in_deg = {nid: len(predecessors[nid]) for nid in node_ids}
    queue = deque()
    for nid in node_ids:
        if in_deg[nid] == 0:
            asap[nid] = 0
            queue.append(nid)
    topo_order = []
    while queue:
        nid = queue.popleft()
        topo_order.append(nid)
        for succ in successors[nid]:
            val = asap[nid] + node_delay[nid]
            if succ not in asap or asap[succ] < val:
                asap[succ] = val
            in_deg[succ] -= 1
            if in_deg[succ] == 0:
                queue.append(succ)

    L_asap = max(asap[nid] + node_delay[nid] for nid in node_ids)

    # Reverse topo order
    rev_topo_order = list(reversed(topo_order))

    # Compute longest path to sink from each node
    longest_to_sink = {}
    for nid in rev_topo_order:
        longest_to_sink[nid] = node_delay[nid]
        for succ in successors[nid]:
            val = node_delay[nid] + longest_to_sink[succ]
            if val > longest_to_sink[nid]:
                longest_to_sink[nid] = val

    def compute_alap(L):
        alap = {}
        for nid in rev_topo_order:
            if not successors[nid]:
                alap[nid] = L - node_delay[nid]
            else:
                alap[nid] = min(alap[succ] - node_delay[nid] for succ in successors[nid])
        return alap

    def try_schedule(L_bound, priority_key):
        alap = compute_alap(L_bound)
        for nid in node_ids:
            if alap[nid] < asap[nid]:
                return None

        schedule = {}
        rem_preds = {nid: len(predecessors[nid]) for nid in node_ids}
        earliest = {nid: asap[nid] for nid in node_ids}

        ready = []
        for nid in node_ids:
            if rem_preds[nid] == 0:
                ready.append(nid)

        resource_usage = defaultdict(lambda: defaultdict(int))
        scheduled_count = 0
        t = 0

        while scheduled_count < num_nodes:
            if t > L_bound:
                return None

            # Separate candidates that can start now
            can_now = []
            still_waiting = []
            for nid in ready:
                if earliest[nid] <= t:
                    can_now.append(nid)
                else:
                    still_waiting.append(nid)

            can_now.sort(key=lambda nid: priority_key(nid, alap))

            scheduled_now = []
            deferred = []
            for nid in can_now:
                r = node_resource[nid]
                d = node_delay[nid]
                can_do = True
                for dt in range(d):
                    if resource_usage[t + dt][r] >= resource_map[r]:
                        can_do = False
                        break
                if can_do:
                    schedule[nid] = t
                    for dt in range(d):
                        resource_usage[t + dt][r] += 1
                    scheduled_now.append(nid)
                    scheduled_count += 1
                else:
                    deferred.append(nid)

            ready = still_waiting + deferred
            for nid in scheduled_now:
                finish = t + node_delay[nid]
                for succ in successors[nid]:
                    if finish > earliest[succ]:
                        earliest[succ] = finish
                    rem_preds[succ] -= 1
                    if rem_preds[succ] == 0:
                        ready.append(succ)

            t += 1

        return schedule

    # Define multiple priority functions
    priority_funcs = [
        lambda nid, alap: (alap[nid] - asap[nid], alap[nid]),
        lambda nid, alap: (-longest_to_sink[nid],),
        lambda nid, alap: (alap[nid],),
        lambda nid, alap: (alap[nid] - asap[nid], -longest_to_sink[nid]),
        lambda nid, alap: (-node_delay[nid], alap[nid] - asap[nid]),
        lambda nid, alap: (alap[nid] - asap[nid], -len(successors[nid])),
    ]

    best_schedule = None
    best_latency = float('inf')

    start_time = time.time()

    for pf in priority_funcs:
        if time.time() - start_time > 8.0:
            break
        lo, hi = L_asap, L_asap * 3 + 100
        sched = try_schedule(hi, pf)
        if sched is None:
            continue
        cur_latency = max(sched[nid] + node_delay[nid] for nid in node_ids)
        if cur_latency < best_latency:
            best_latency = cur_latency
            best_schedule = sched
        hi = cur_latency

        while lo < hi:
            if time.time() - start_time > 8.5:
                break
            mid = (lo + hi) // 2
            result = try_schedule(mid, pf)
            if result is not None:
                lat = max(result[nid] + node_delay[nid] for nid in node_ids)
                if lat < best_latency:
                    best_latency = lat
                    best_schedule = result
                hi = mid
            else:
                lo = mid + 1

        lo = L_asap

    # Randomized perturbation phase
    random.seed(42)
    while time.time() - start_time < 9.0:
        # Try random tie-breaking with best priority
        noise = {nid: random.random() * 0.5 for nid in node_ids}
        pf_rand = lambda nid, alap, _n=noise: (alap[nid] - asap[nid] + _n[nid], -longest_to_sink[nid])

        lo, hi = L_asap, best_latency
        while lo < hi:
            if time.time() - start_time > 9.0:
                break
            mid = (lo + hi) // 2
            result = try_schedule(mid, pf_rand)
            if result is not None:
                lat = max(result[nid] + node_delay[nid] for nid in node_ids)
                if lat < best_latency:
                    best_latency = lat
                    best_schedule = result
                hi = mid
            else:
                lo = mid + 1

    with open(solution_file, 'w') as f:
        lines = [f"{nid}:{best_schedule[nid]}" for nid in node_ids]
        f.write('\n'.join(lines) + '\n')

