def solve(input_file: str, solution_file: str):
    individuals = []
    with open(input_file, 'r') as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            parts = line.split()
            individuals.append((int(parts[0]), int(parts[1]), int(parts[2]),
                                int(parts[3]), int(parts[4]), int(parts[5]), int(parts[6])))

    m = len(individuals)

    allele_set = set()
    for (_, _, _, _, _, a1, a2) in individuals:
        if a1 != 0:
            allele_set.add(a1)
        if a2 != 0:
            allele_set.add(a2)
    if not allele_set:
        allele_set = {1}

    n = max(allele_set)

    domain = []
    for a in range(1, n + 1):
        for b in range(a, n + 1):
            domain.append((a, b))
    D = len(domain)

    geno_to_idx = {}
    for idx, (a, b) in enumerate(domain):
        geno_to_idx[(a, b)] = idx

    id_to_idx = {}
    for i, (_, id_, _, _, _, _, _) in enumerate(individuals):
        id_to_idx[id_] = i

    father_idx = [None] * m
    mother_idx = [None] * m
    for i, (_, _, fa, mo, _, _, _) in enumerate(individuals):
        if fa != 0 and fa in id_to_idx:
            father_idx[i] = id_to_idx[fa]
        if mo != 0 and mo in id_to_idx:
            mother_idx[i] = id_to_idx[mo]

    children_of = [[] for _ in range(m)]
    for i in range(m):
        if father_idx[i] is not None:
            children_of[father_idx[i]].append(i)
        if mother_idx[i] is not None:
            children_of[mother_idx[i]].append(i)

    geno_alleles = []
    for d in range(D):
        a, b = domain[d]
        geno_alleles.append(frozenset((a, b)))

    allele_to_genos = {}
    for a in range(1, n + 1):
        allele_to_genos[a] = set()
    for d in range(D):
        a, b = domain[d]
        allele_to_genos[a].add(d)
        allele_to_genos[b].add(d)

    shares_with = [None] * D
    for d in range(D):
        a, b = domain[d]
        shares_with[d] = allele_to_genos[a] | allele_to_genos[b]

    mendel_children = {}
    for df in range(D):
        af, bf = domain[df]
        for dm in range(D):
            am, bm = domain[dm]
            s = set()
            for pa in (af, bf):
                for ma in (am, bm):
                    key = (min(pa, ma), max(pa, ma))
                    s.add(geno_to_idx[key])
            mendel_children[(df, dm)] = frozenset(s)

    valid_father_for_child = [set() for _ in range(D)]
    valid_mother_for_child = [set() for _ in range(D)]
    for (df, dm), cs in mendel_children.items():
        for dc in cs:
            valid_father_for_child[dc].add(df)
            valid_mother_for_child[dc].add(dm)

    unary_cost = []
    for i, (_, _, _, _, _, a1, a2) in enumerate(individuals):
        costs = [0] * D
        if a1 != 0 or a2 != 0:
            if a1 != 0 and a2 != 0:
                obs = (min(a1, a2), max(a1, a2))
                obs_idx = geno_to_idx[obs]
                for d in range(D):
                    if d != obs_idx:
                        costs[d] = 1
            elif a1 != 0:
                for d in range(D):
                    a, b = domain[d]
                    if a != a1 and b != a1:
                        costs[d] = 1
            else:
                for d in range(D):
                    a, b = domain[d]
                    if a != a2 and b != a2:
                        costs[d] = 1
        unary_cost.append(costs)

    cur_domains = [set(range(D)) for _ in range(m)]

    changed = True
    while changed:
        changed = False
        for i in range(m):
            fi = father_idx[i]
            mi = mother_idx[i]

            if fi is not None and mi is not None:
                new_child = set()
                for dc in cur_domains[i]:
                    vf = valid_father_for_child[dc] & cur_domains[fi]
                    if not vf:
                        continue
                    vm = valid_mother_for_child[dc] & cur_domains[mi]
                    if not vm:
                        continue
                    found = False
                    for df in vf:
                        mc = mendel_children[(df, -1)] if False else None
                        for dm in vm:
                            if dc in mendel_children.get((df, dm), frozenset()):
                                found = True
                                break
                        if found:
                            break
                    if found:
                        new_child.add(dc)
                if len(new_child) < len(cur_domains[i]):
                    cur_domains[i] = new_child
                    changed = True

                new_father = set()
                for df in cur_domains[fi]:
                    found = False
                    for dc in cur_domains[i]:
                        if df not in valid_father_for_child[dc]:
                            continue
                        for dm in cur_domains[mi]:
                            if dc in mendel_children.get((df, dm), frozenset()):
                                found = True
                                break
                        if found:
                            break
                    if found:
                        new_father.add(df)
                if len(new_father) < len(cur_domains[fi]):
                    cur_domains[fi] = new_father
                    changed = True

                new_mother = set()
                for dm in cur_domains[mi]:
                    found = False
                    for dc in cur_domains[i]:
                        if dm not in valid_mother_for_child[dc]:
                            continue
                        for df in cur_domains[fi]:
                            if dc in mendel_children.get((df, dm), frozenset()):
                                found = True
                                break
                        if found:
                            break
                    if found:
                        new_mother.add(dm)
                if len(new_mother) < len(cur_domains[mi]):
                    cur_domains[mi] = new_mother
                    changed = True

            elif fi is not None:
                new_c = set()
                for dc in cur_domains[i]:
                    if cur_domains[fi] & shares_with[dc]:
                        new_c.add(dc)
                if len(new_c) < len(cur_domains[i]):
                    cur_domains[i] = new_c
                    changed = True
                new_f = set()
                for df in cur_domains[fi]:
                    if cur_domains[i] & shares_with[df]:
                        new_f.add(df)
                if len(new_f) < len(cur_domains[fi]):
                    cur_domains[fi] = new_f
                    changed = True

            elif mi is not None:
                new_c = set()
                for dc in cur_domains[i]:
                    if cur_domains[mi] & shares_with[dc]:
                        new_c.add(dc)
                if len(new_c) < len(cur_domains[i]):
                    cur_domains[i] = new_c
                    changed = True
                new_m = set()
                for dm in cur_domains[mi]:
                    if cur_domains[i] & shares_with[dm]:
                        new_m.add(dm)
                if len(new_m) < len(cur_domains[mi]):
                    cur_domains[mi] = new_m
                    changed = True

    dom_lists = [sorted(cur_domains[i], key=lambda v: unary_cost[i][v]) for i in range(m)]

    generation = [0] * m
    visited = [False] * m

    def compute_gen(i):
        if visited[i]:
            return generation[i]
        visited[i] = True
        g = 0
        if father_idx[i] is not None:
            g = max(g, compute_gen(father_idx[i]) + 1)
        if mother_idx[i] is not None:
            g = max(g, compute_gen(mother_idx[i]) + 1)
        generation[i] = g
        return g

    for i in range(m):
        compute_gen(i)

    order = sorted(range(m), key=lambda i: (generation[i], len(dom_lists[i])))

    best_cost = [float('inf')]
    best_assignment = [None]
    assignment = [None] * m

    def check(i, v):
        fi, mi = father_idx[i], mother_idx[i]
        if fi is not None and mi is not None:
            if assignment[fi] is not None and assignment[mi] is not None:
                if v not in mendel_children.get((assignment[fi], assignment[mi]), frozenset()):
                    return False
            elif assignment[fi] is not None:
                if v not in shares_with[assignment[fi]]:
                    return False
            elif assignment[mi] is not None:
                if v not in shares_with[assignment[mi]]:
                    return False
        elif fi is not None and assignment[fi] is not None:
            if v not in shares_with[assignment[fi]]:
                return False
        elif mi is not None and assignment[mi] is not None:
            if v not in shares_with[assignment[mi]]:
                return False
        for c in children_of[i]:
            if assignment[c] is None:
                continue
            fc, mc = father_idx[c], mother_idx[c]
            if fc is not None and mc is not None:
                if fc == i:
                    if assignment[mc] is not None:
                        if assignment[c] not in mendel_children.get((v, assignment[mc]), frozenset()):
                            return False
                    else:
                        if assignment[c] not in shares_with[v]:
                            return False
                else:
                    if assignment[fc] is not None:
                        if assignment[c] not in mendel_children.get((assignment[fc], v), frozenset()):
                            return False
                    else:
                        if assignment[c] not in shares_with[v]:
                            return False
            else:
                if assignment[c] not in shares_with[v]:
                    return False
        return True

    def search(pos, cc):
        if cc >= best_cost[0]:
            return
        if pos == m:
            best_cost[0] = cc
            best_assignment[0] = assignment[:]
            return
        i = order[pos]
        for v in dom_lists[i]:
            c = unary_cost[i][v]
            if cc + c >= best_cost[0]:
                break
            if check(i, v):
                assignment[i] = v
                search(pos + 1, cc + c)
                assignment[i] = None

    search(0, 0)

    if best_assignment[0] is None:
        best_assignment[0] = [dom_lists[i][0] if dom_lists[i] else 0 for i in range(m)]

    with open(solution_file, 'w') as f:
        f.write(' '.join(str(best_assignment[0][i]) for i in range(m)) + '\n')

claude-opus-4-6.pickup_delivery_time_windows:
def solve(input_file: str, solution_file: str):

    from dataclasses import dataclass
    from typing import Dict, List
    import os
    import random
    import time

    @dataclass
    class Node:
        index: int
        x: float
        y: float
        demand: float
        earliest_time: float
        latest_time: float
        service_time: float
        pickup_sibling: int
        delivery_sibling: int
        is_pickup: bool

    @dataclass
    class Instance:
        name: str
        type: str
        dimension: int
        vehicles: int
        capacity: float
        edge_weight_type: str
        nodes: Dict[int, Node]
        depot_node: List[int]

    def read_instance(file_path: str) -> Instance:
        with open(file_path, "r") as file:
            lines = file.readlines()
        name = ""
        type_ = ""
        dimension = 0
        vehicles = 0
        capacity = 0.0
        edge_weight_type = ""
        nodes = {}
        depot_node = []
        section = None
        for line in lines:
            line = line.strip()
            if line.startswith("NAME"):
                name = line.split(":")[1].strip()
            elif line.startswith("TYPE"):
                type_ = line.split(":")[1].strip()
            elif line.startswith("DIMENSION"):
                dimension = int(line.split(":")[1].strip())
            elif line.startswith("VEHICLES"):
                vehicles = int(line.split(":")[1].strip())
            elif line.startswith("CAPACITY"):
                capacity = float(line.split(":")[1].strip())
            elif line.startswith("EDGE_WEIGHT_TYPE"):
                edge_weight_type = line.split(":")[1].strip()
            elif line.startswith("NODE_COORD_SECTION"):
                section = "NODE_COORD_SECTION"
            elif line.startswith("PICKUP_AND_DELIVERY_SECTION"):
                section = "PICKUP_AND_DELIVERY_SECTION"
            elif line.startswith("DEPOT_SECTION"):
                section = "DEPOT_SECTION"
            elif line.startswith("EOF"):
                break
            elif section == "NODE_COORD_SECTION":
                parts = line.split()
                index = int(parts[0])
                x, y = float(parts[1]), float(parts[2])
                nodes[index] = Node(index=index, x=x, y=y, demand=0.0,
                    earliest_time=0.0, latest_time=0.0, service_time=0.0,
                    pickup_sibling=0, delivery_sibling=0, is_pickup=False)
            elif section == "PICKUP_AND_DELIVERY_SECTION":
                parts = line.split()
                index = int(parts[0])
                if index in nodes:
                    nodes[index].demand = float(parts[1])
                    nodes[index].earliest_time = float(parts[2])
                    nodes[index].latest_time = float(parts[3])
                    nodes[index].service_time = float(parts[4])
                    nodes[index].pickup_sibling = int(parts[5])
                    nodes[index].delivery_sibling = int(parts[6])
                    nodes[index].is_pickup = (nodes[index].delivery_sibling != 0)
            elif section == "DEPOT_SECTION":
                if line != "-1":
                    depot_node.append(int(line))
        return Instance(name=name, type=type_, dimension=dimension, vehicles=vehicles,
            capacity=capacity, edge_weight_type=edge_weight_type, nodes=nodes, depot_node=depot_node)

    def calculate_distance(x1: float, y1: float, x2: float, y2: float) -> float:
        return round(((x2 - x1) ** 2 + (y1 - y2) ** 2) ** 0.5, 0)

    base_name = os.path.splitext(os.path.basename(input_file))[0]
    instance = read_instance(input_file)

    node_indices = sorted(instance.nodes.keys())
    depot = instance.depot_node[0]
    cap = instance.capacity
    num_vehicles = instance.vehicles

    nx_a = {}
    ny_a = {}
    dem = {}
    etw = {}
    ltw = {}
    srv = {}
    del_sib = {}
    pck_sib = {}

    for idx, node in instance.nodes.items():
        nx_a[idx] = node.x
        ny_a[idx] = node.y
        dem[idx] = node.demand
        etw[idx] = node.earliest_time
        ltw[idx] = node.latest_time
        srv[idx] = node.service_time
        del_sib[idx] = node.delivery_sibling
        pck_sib[idx] = node.pickup_sibling

    dist_mat = {}
    for i in node_indices:
        for j in node_indices:
            dist_mat[(i, j)] = calculate_distance(nx_a[i], ny_a[i], nx_a[j], ny_a[j])

    pairs = []
    for idx in node_indices:
        if idx == depot:
            continue
        if del_sib[idx] != 0:
            pairs.append((idx, del_sib[idx]))

    start_time = time.time()
    time_limit = 9.0

    def route_dist(route):
        d = 0.0
        for i in range(len(route) - 1):
            d += dist_mat[(route[i], route[i + 1])]
        return d

    def check_route(route):
        if len(route) <= 2:
            return True, 0.0
        load = 0.0
        t = etw[depot]
        td = 0.0
        visited = set()
        for i in range(1, len(route)):
            node = route[i]
            prev = route[i - 1]
            travel = dist_mat[(prev, node)]
            td += travel
            t += travel
            if node != depot:
                if t > ltw[node]:
                    return False, td
                if t < etw[node]:
                    t = etw[node]
                if pck_sib[node] != 0:
                    if pck_sib[node] not in visited:
                        return False, td
                load += dem[node]
                if load > cap + 1e-9 or load < -1e-9:
                    return False, td
                t += srv[node]
                visited.add(node)
            else:
                if t > ltw[depot]:
                    return False, td
        return True, td

    def try_insert(route, p, d):
        best_cost = float('inf')
        best_route = None
        rlen = len(route)
        for pi in range(1, rlen):
            for di in range(pi + 1, rlen + 1):
                nr = route[:pi] + [p] + route[pi:di] + [d] + route[di:]
                ok, cost = check_route(nr)
                if ok and cost < best_cost:
                    best_cost = cost
                    best_route = list(nr)
        return best_route, best_cost

    routes = [[depot, depot] for _ in range(num_vehicles)]
    rcosts = [0.0] * num_vehicles
    sorted_pairs = sorted(pairs, key=lambda p: etw[p[0]])
    unassigned = list(sorted_pairs)

    while unassigned:
        if time.time() - start_time > time_limit * 0.55:
            break
        best_pi = None
        best_ri = -1
        best_nr = None
        best_reg = -float('inf')
        best_cv = float('inf')
        for pi_idx, (p, d) in enumerate(unassigned):
            ins = []
            for ri in range(num_vehicles):
                nr, nc = try_insert(routes[ri], p, d)
                if nr is not None:
                    ins.append((nc - rcosts[ri], ri, nr, nc))
            if not ins:
                continue
            ins.sort(key=lambda x: x[0])
            reg = ins[1][0] - ins[0][0] if len(ins) > 1 else 1e9
            if reg > best_reg or (abs(reg - best_reg) < 1e-9 and ins[0][0] < best_cv):
                best_reg = reg
                best_pi = pi_idx
                best_ri = ins[0][1]
                best_nr = ins[0][2]
                best_cv = ins[0][0]
        if best_pi is not None:
            routes[best_ri] = best_nr
            rcosts[best_ri] = route_dist(best_nr)
            unassigned.pop(best_pi)
        else:
            break

    if unassigned:
        for p, d in list(unassigned):
            if time.time() - start_time > time_limit * 0.65:
                break
            best_ri = -1
            best_nr = None
            best_ci = float('inf')
            for ri in range(num_vehicles):
                nr, nc = try_insert(routes[ri], p, d)
                if nr is not None:
                    ci = nc - route_dist(routes[ri])
                    if ci < best_ci:
                        best_ci = ci
                        best_ri = ri
                        best_nr = nr
            if best_ri >= 0:
                routes[best_ri] = best_nr
                rcosts[best_ri] = route_dist(best_nr)
                unassigned.remove((p, d))

    for r_idx in range(len(routes)):
        if len(routes[r_idx]) <= 3:
            continue
        if time.time() - start_time > time_limit * 0.8:
            break
        improved = True
        while improved and time.time() - start_time < time_limit * 0.8:
            improved = False
            od = route_dist(routes[r_idx])
            for i in range(1, len(routes[r_idx]) - 1):
                if time.time() - start_time > time_limit * 0.8:
                    break
                node = routes[r_idx][i]
                rem = routes[r_idx][:i] + routes[r_idx][i + 1:]
                for j in range(1, len(rem)):
                    if j == i:
                        continue
                    nr = rem[:j] + [node] + rem[j:]
                    ok, nd = check_route(nr)
                    if ok and nd < od - 1e-9:
                        routes[r_idx] = nr
                        od = nd
                        improved = True
                        break
                if improved:
                    break

    for r in routes:
        if r[0] != depot:
            r.insert(0, depot)
        if r[-1] != depot:
            r.append(depot)

    final_routes = []
    for r in routes:
        if len(r) > 2:
            final_routes.append(r)

    if not final_routes:
        final_routes = [[depot, depot]]

    with open(solution_file, 'w') as f:
        f.write(f"{instance.name}\n")
        for route in final_routes:
            f.write(" ".join(map(str, route)) + "\n")

