def solve(input_file: str, solution_file: str):
    from collections import defaultdict, deque

    K = 6

    with open(input_file, 'r') as f:
        content = f.read()

    content = content.replace('\\\n', ' ')
    lines = content.split('\n')

    model_name = "mapped"
    pi_list = []
    primary_inputs = set()
    primary_outputs = []
    gates = {}
    gate_order = []

    i = 0
    while i < len(lines):
        line = lines[i].strip()
        if not line or line.startswith('#'):
            i += 1
            continue
        if line.startswith('.model'):
            parts = line.split(None, 1)
            model_name = parts[1].strip() if len(parts) > 1 else "mapped"
        elif line.startswith('.inputs'):
            pi_list = line.split()[1:]
            primary_inputs = set(pi_list)
        elif line.startswith('.outputs'):
            primary_outputs = line.split()[1:]
        elif line.startswith('.names'):
            tokens = line.split()[1:]
            output = tokens[-1]
            inputs = tokens[:-1]
            tt_rows = []
            i += 1
            while i < len(lines):
                tline = lines[i].strip()
                if not tline or tline.startswith('.') or tline.startswith('#'):
                    break
                tt_rows.append(tline)
                i += 1
            gates[output] = (inputs, tt_rows)
            gate_order.append(output)
            continue
        elif line.startswith('.end'):
            break
        i += 1

    po_set = set(primary_outputs)

    # Version tracking
    current_def = {}
    uid_counter = [0]
    def new_uid():
        uid_counter[0] += 1
        return uid_counter[0]

    uid_to_origname = {}
    uid_is_pi = set()
    uid_gate_inputs = {}
    uid_gate_info = {}
    uid_children = defaultdict(list)

    for pi in pi_list:
        uid = new_uid()
        current_def[pi] = uid
        uid_to_origname[uid] = pi
        uid_is_pi.add(uid)

    gate_uids = []
    for gate_name in gate_order:
        inputs, tt_rows = gates[gate_name]
        input_uids = []
        for inp in inputs:
            if inp in current_def:
                input_uids.append(current_def[inp])
            else:
                uid = new_uid()
                current_def[inp] = uid
                uid_to_origname[uid] = inp
                uid_is_pi.add(uid)
                input_uids.append(uid)
        uid = new_uid()
        current_def[gate_name] = uid
        uid_to_origname[uid] = gate_name
        uid_gate_info[uid] = (input_uids, gate_name, tt_rows)
        uid_gate_inputs[uid] = input_uids
        for inp_uid in input_uids:
            uid_children[inp_uid].append(uid)
        gate_uids.append(uid)

    po_uids = []
    for po in primary_outputs:
        po_uids.append((po, current_def.get(po, None)))

    all_pi_uids = uid_is_pi

    # Topological sort
    in_degree = {}
    for uid in gate_uids:
        cnt = sum(1 for p in uid_gate_inputs[uid] if p not in all_pi_uids)
        in_degree[uid] = cnt

    topo_order = []
    queue = deque(uid for uid in gate_uids if in_degree[uid] == 0)
    in_deg_copy = dict(in_degree)
    while queue:
        node = queue.popleft()
        topo_order.append(node)
        for ch in uid_children[node]:
            if ch in in_deg_copy:
                in_deg_copy[ch] -= 1
                if in_deg_copy[ch] == 0:
                    queue.append(ch)

    num_gates = len(topo_order)

    # Cut enumeration
    MAX_CUTS = 12 if num_gates < 30000 else 8

    cuts = {}
    for uid in all_pi_uids:
        cuts[uid] = [(uid,)]

    for gid in topo_order:
        pids = uid_gate_inputs[gid]
        if not pids:
            cuts[gid] = [()]
            continue

        trivial = (gid,)
        current = list(cuts.get(pids[0], [(pids[0],)]))

        for j in range(1, len(pids)):
            pid = pids[j]
            inp_cuts = cuts.get(pid, [(pid,)])
            new_current = set()
            for c1 in current:
                s1 = set(c1)
                for c2 in inp_cuts:
                    merged = s1 | set(c2)
                    if len(merged) <= K:
                        new_current.add(tuple(sorted(merged)))
            current = list(new_current)
            if len(current) > MAX_CUTS * 5:
                current.sort(key=len)
                filtered = []
                fsets = []
                for c in current:
                    cs = set(c)
                    dominated = any(fs <= cs for fs in fsets)
                    if not dominated:
                        filtered.append(c)
                        fsets.append(cs)
                current = filtered[:MAX_CUTS * 3]

        all_cuts_set = set(current)
        all_cuts_set.add(trivial)
        all_cuts = sorted(all_cuts_set, key=len)
        filtered = []
        fsets = []
        for c in all_cuts:
            cs = set(c)
            dominated = any(fs < cs for fs in fsets)
            if not dominated:
                filtered.append(c)
                fsets.append(cs)
        cuts[gid] = filtered[:MAX_CUTS]

    # Fanout
    fanout_count = defaultdict(int)
    for gid in topo_order:
        for pid in uid_gate_inputs[gid]:
            fanout_count[pid] += 1
    for _, po_uid in po_uids:
        if po_uid is not None:
            fanout_count[po_uid] += 1

    # Area flow
    area_flow = {}
    best_cut = {}
    for uid in all_pi_uids:
        area_flow[uid] = 0.0
        best_cut[uid] = (uid,)

    for gid in topo_order:
        if not uid_gate_inputs[gid]:
            area_flow[gid] = 1.0
            best_cut[gid] = ()
            continue
        best_af = float('inf')
        best_c = (gid,)
        for c in cuts[gid]:
            if len(c) == 1 and c[0] == gid:
                continue
            af = 1.0 + sum(area_flow.get(n, 0.0) for n in c)
            fo = max(fanout_count.get(gid, 1), 1)
            af /= fo
            if af < best_af or (af == best_af and len(c) < len(best_c)):
                best_af = af
                best_c = c
        area_flow[gid] = best_af
        best_cut[gid] = best_c

    # Refinement
    for iteration in range(3):
        needed = set()
        for _, po_uid in po_uids:
            if po_uid is not None and po_uid not in all_pi_uids:
                needed.add(po_uid)
        ref_count = defaultdict(int)
        for gid in reversed(topo_order):
            if gid not in needed:
                continue
            c = best_cut[gid]
            for n in c:
                if n not in all_pi_uids:
                    needed.add(n)
                ref_count[n] += 1
        for _, po_uid in po_uids:
            if po_uid is not None:
                ref_count[po_uid] += 1

        exact_area = {}
        for uid in all_pi_uids:
            exact_area[uid] = 0.0
        for gid in topo_order:
            if not uid_gate_inputs[gid]:
                exact_area[gid] = 1.0
                best_cut[gid] = ()
                continue
            best_ea = float('inf')
            best_c = best_cut.get(gid, (gid,))
            for c in cuts[gid]:
                if len(c) == 1 and c[0] == gid:
                    continue
                ea = 1.0
                for n in c:
                    rc = max(ref_count.get(n, 1), 1)
                    ea += exact_area.get(n, 0.0) / rc
                if ea < best_ea or (ea == best_ea and len(c) < len(best_c)):
                    best_ea = ea
                    best_c = c
            exact_area[gid] = best_ea
            best_cut[gid] = best_c

    # Final covering
    needed = set()
    for _, po_uid in po_uids:
        if po_uid is not None and po_uid not in all_pi_uids:
            needed.add(po_uid)
    lut_mapping = {}
    for gid in reversed(topo_order):
        if gid not in needed:
            continue
        c = best_cut[gid]
        lut_mapping[gid] = c
        for n in c:
            if n not in all_pi_uids:
                needed.add(n)

    # Evaluate gate
    def evaluate_gate_uid(uid, input_vals):
        input_uids, gate_name, tt_rows = uid_gate_info[uid]
        n_inp = len(input_uids)
        if n_inp == 0:
            if not tt_rows:
                return 0
            parts = tt_rows[0].split()
            return int(parts[0]) if parts else 0
        if not tt_rows:
            return 0
        parts0 = tt_rows[0].split()
        output_val = int(parts0[1]) if len(parts0) == 2 else 1
        default_val = 1 - output_val
        for row in tt_rows:
            parts = row.split()
            pattern = parts[0]
            out = int(parts[1]) if len(parts) == 2 else 1
            match = True
            for idx in range(len(pattern)):
                if pattern[idx] != '-' and int(pattern[idx]) != input_vals[idx]:
                    match = False
                    break
            if match:
                return out
        return default_val

    topo_pos = {gid: i for i, gid in enumerate(topo_order)}

    def get_cone_topo(root_uid, cut_set):
        if root_uid in cut_set or root_uid in all_pi_uids:
            return []
        cone = []
        visited = set()
        stack = [root_uid]
        while stack:
            nid = stack.pop()
            if nid in visited or nid in cut_set or nid in all_pi_uids:
                continue
            visited.add(nid)
            cone.append(nid)
            for pid in uid_gate_inputs.get(nid, []):
                if pid not in visited and pid not in cut_set and pid not in all_pi_uids:
                    stack.append(pid)
        cone.sort(key=lambda x: topo_pos.get(x, 0))
        return cone

    def compute_truth_table(root_uid, cut_tuple):
        cut_list = sorted(cut_tuple)
        cut_set = frozenset(cut_tuple)
        n = len(cut_list)
        cone_nodes = get_cone_topo(root_uid, cut_set)

        if n == 0:
            vals = {}
            for nid in cone_nodes:
                iv = [vals.get(u, 0) for u in uid_gate_inputs[nid]]
                vals[nid] = evaluate_gate_uid(nid, iv)
            v = vals.get(root_uid, evaluate_gate_uid(root_uid, []))
            return cut_list, v, None, None

        ones = []
        zeros = []
        for bits in range(1 << n):
            vals = {}
            pat = []
            for j in range(n):
                b = (bits >> (n - 1 - j)) & 1
                vals[cut_list[j]] = b
                pat.append(chr(48 + b))
            for nid in cone_nodes:
                iv = [vals.get(u, 0) for u in uid_gate_inputs[nid]]
                vals[nid] = evaluate_gate_uid(nid, iv)
            if vals.get(root_uid, 0) == 1:
                ones.append(''.join(pat))
            else:
                zeros.append(''.join(pat))

        if len(ones) <= len(zeros):
            return cut_list, None, ones, 1
        else:
            return cut_list, None, zeros, 0

    # Naming strategy:
    # Determine which mapped nodes are POs (can use PO name directly)
    # and which are only internal (need internal names).
    # A mapped node that is a PO can use the PO name as its output IF
    # it doesn't create a conflict. Conflict: the PO name is also a PI name
    # and the LUT's cut inputs include that PI.

    po_uid_to_ponames = defaultdict(list)
    for po_name, po_uid in po_uids:
        if po_uid is not None:
            po_uid_to_ponames[po_uid].append(po_name)

    # Which mapped nodes are used as cut inputs by other mapped nodes?
    cut_input_uids = set()
    for gid, c in lut_mapping.items():
        for n in c:
            if n not in all_pi_uids:
                cut_input_uids.add(n)

    # Assign names
    # For each mapped node, determine its output signal name
    # If it's a PO and not used as cut input by others, use PO name directly
    # If it's a PO and used as cut input, we need an internal name + buffer
    # If it's not a PO, use internal name

    # Collect all names that exist in the circuit (PIs + PO names)
    all_existing_names = set(pi_list) | po_set
    # Also collect all original gate names to avoid collisions
    for g in gate_order:
        all_existing_names.add(g)

    mapped_name = {}  # uid -> name used as LUT output
    needs_po_buffer = {}  # uid -> list of po_names that need buffers

    for gid in topo_order:
        if gid not in lut_mapping:
            continue

        po_names = po_uid_to_ponames.get(gid, [])
        is_cut_input = gid in cut_input_uids

        if po_names and not is_cut_input:
            # Use first PO name directly, buffer the rest
            mapped_name[gid] = po_names[0]
            if len(po_names) > 1:
                needs_po_buffer[gid] = po_names[1:]
        else:
            # Use internal name
            base = f"__n{gid}"
            name = base
            c = 0
            while name in all_existing_names:
                c += 1
                name = f"{base}x{c}"
            mapped_name[gid] = name
            all_existing_names.add(name)
            if po_names:
                needs_po_buffer[gid] = po_names

    def get_signal_name(uid):
        if uid in all_pi_uids:
            return uid_to_origname[uid]
        return mapped_name.get(uid, f"__n{uid}")

    with open(solution_file, 'w') as f:
        f.write(f".model {model_name}\n")

        def write_long(prefix, items):
            f.write(prefix)
            ll = len(prefix)
            for item in items:
                if ll + 1 + len(item) > 900:
                    f.write(" \\\n")
                    ll = 0
                f.write(f" {item}")
                ll += 1 + len(item)
            f.write("\n")

        write_long(".inputs", pi_list)
        write_long(".outputs", primary_outputs)

        for gid in topo_order:
            if gid not in lut_mapping:
                continue
            cut_tuple = lut_mapping[gid]
            cut_list, const_val, tt_patterns, tt_out = compute_truth_table(gid, cut_tuple)
            out_name = mapped_name[gid]
            n = len(cut_list)

            if n == 0:
                f.write(f".names {out_name}\n")
                if const_val == 1:
                    f.write("1\n")
            else:
                if tt_patterns is not None and len(tt_patterns) == 0:
                    # Constant function despite having inputs
                    f.write(f".names {out_name}\n")
                    if tt_out == 0:
                        f.write("1\n")
                    # tt_out == 1 means all zeros -> constant 0, no row needed
                elif tt_patterns is not None and len(tt_patterns) == (1 << n):
                    # All patterns match -> constant
                    f.write(f".names {out_name}\n")
                    if tt_out == 1:
                        f.write("1\n")
                else:
                    input_names = [get_signal_name(cid) for cid in cut_list]
                    # Verify no input name equals output name
                    safe = True
                    for iname in input_names:
                        if iname == out_name:
                            safe = False
                            break
                    if not safe:
                        # Rename output
                        new_name = out_name + "_r"
                        while new_name in all_existing_names:
                            new_name += "r"
                        old_name = out_name
                        mapped_name[gid] = new_name
                        all_existing_names.add(new_name)
                        out_name = new_name
                        # Update buffer needs
                        if gid in needs_po_buffer:
                            pass  # already has buffers
                        else:
                            # Check if old_name was a PO name
                            if old_name in po_set:
                                needs_po_buffer.setdefault(gid, []).append(old_name)

                    f.write(f".names {' '.join(input_names)} {out_name}\n")
                    for pattern in tt_patterns:
                        f.write(f"{pattern} {tt_out}\n")

            # Write buffers for additional PO names
            if gid in needs_po_buffer:
                for po_name in needs_po_buffer[gid]:
                    f.write(f".names {out_name} {po_name}\n")
                    f.write("1 1\n")

        # Handle POs that are PIs (passthrough)
        handled_pos = set()
        for gid in lut_mapping:
            mn = mapped_name[gid]
            if mn in po_set:
                handled_pos.add(mn)
            if gid in needs_po_buffer:
                for pn in needs_po_buffer[gid]:
                    handled_pos.add(pn)

        for po_name, po_uid in po_uids:
            if po_name in handled_pos:
                continue
            if po_uid is None:
                f.write(f".names {po_name}\n")
                handled_pos.add(po_name)
            elif po_uid in all_pi_uids:
                pi_name = uid_to_origname[po_uid]
                if pi_name != po_name:
                    f.write(f".names {pi_name} {po_name}\n")
                    f.write("1 1\n")
                # else implicit passthrough
                handled_pos.add(po_name)

        f.write(".end\n")

