import json
import heapq
from collections import defaultdict, deque

def solve(input_file: str, solution_file: str):
    with open(input_file, 'r') as f:
        data = json.load(f)

    nodes = data['nodes']
    root_eclasses = data['root_eclasses']

    node_id_to_idx = {}
    node_idx_to_id = []
    node_costs = []
    node_children_eclasses = []
    node_eclass = []

    eclass_to_nodes = defaultdict(list)

    for idx, (node_id, node_info) in enumerate(nodes.items()):
        node_id_to_idx[node_id] = idx
        node_idx_to_id.append(node_id)
        node_costs.append(node_info['cost'])
        node_eclass.append(node_info['eclass'])
        eclass_to_nodes[node_info['eclass']].append(idx)

    for node_id, node_info in nodes.items():
        idx = node_id_to_idx[node_id]
        children = []
        for child_eclass in node_info['children']:
            children.append(child_eclass)
        node_children_eclasses.append(children)

    N = len(node_idx_to_id)
    eclass_to_idx = {eclass: i for i, eclass in enumerate(eclass_to_nodes.keys())}
    M = len(eclass_to_idx)

    node_to_eclass_idx = [eclass_to_idx[eclass] for eclass in node_eclass]
    eclass_nodes = [[] for _ in range(M)]
    for node_idx, eclass_idx in enumerate(node_to_eclass_idx):
        eclass_nodes[eclass_idx].append(node_idx)

    root_eclass_idxs = [eclass_to_idx[root] for root in root_eclasses]

    child_eclasses = [[] for _ in range(N)]
    for i, children in enumerate(node_children_eclasses):
        for child_eclass in children:
            if child_eclass in eclass_to_idx:
                child_eclasses[i].append(eclass_to_idx[child_eclass])
            else:
                child_eclasses[i].append(-1)

    dp = [float('inf')] * N
    selected_child = [[] for _ in range(N)]

    for eclass_idx in range(M):
        for node_idx in eclass_nodes[eclass_idx]:
            if not child_eclasses[node_idx]:
