import heapq
from collections import defaultdict, deque
import math

def solve(cap_file: str, net_file: str, solution_file: str):
    with open(cap_file, 'r') as f:
        lines = [line.strip() for line in f if line.strip()]

    idx = 0
    nLayers, xSize, ySize = map(int, lines[idx].split())
    idx += 1
    cost_line = list(map(float, lines[idx].split()))
    UnitLengthWireCost, UnitViaCost = cost_line[0], cost_line[1]
    OFWeight = cost_line[2:]
    idx += 1
    HorizontalGCellEdgeLengths = list(map(int, lines[idx].split()))
    idx += 1
    VerticalGCellEdgeLengths = list(map(int, lines[idx].split()))
    idx += 1

    layer_directions = []
    layer_capacities = []
    for l in range(nLayers):
        name, dir_str, min_len = lines[idx].split()
        direction = 0 if dir_str == '0' else 1
        layer_directions.append(direction)
        idx += 1
        cap_grid = []
        for y in range(ySize):
            row = list(map(float, lines[idx].split()))
            cap_grid.append(row)
            idx += 1
        layer_capacities.append(cap_grid)

    with open(net_file, 'r') as f:
        net_lines = f.readlines()

    nets = []
    current_net = None
    current_pins = []
    for line in net_lines:
        line = line.strip()
        if not line:
            continue
        if line.startswith('('):
            continue
        if line.startswith(')'):
            if current_net is not None:
                nets.append((current_net, current_pins))
                current_net = None
                current_pins = []
            continue
        if current_net is None:
            current_net = line
            current_pins = []
        else:
            if line.startswith('['):
                points = []
                content = line[1:-1]
                if content:
                    tuples = content.split('),')
                    for t in tuples:
                        t = t.strip()
                        if t.startswith('('):
                            t = t[1:]
                        if t.endswith(')'):
                            t = t[:-1]
                        z, x, y = map(int, t.split(','))
                        points.append((z, x, y))
                current_pins.append(points)

    if current_net is not None:
        nets.append((current_net, current_pins))

    edge_capacity = {}
    edge_length = {}
    edge_layer = {}
    horizontal_edges = []
    vertical_edges = []
    via_edges = []

    for z in range(nLayers):
        direction = layer_directions[z]
        cap_grid = layer_capacities[z]
        if direction == 0:
            for x in range(xSize - 1):
                for y in range(ySize):
                    e = (x, y, z, x + 1, y, z)
                    c = cap_grid[y][x]
                    edge_capacity[e] = c
                    edge_length[e] = HorizontalGCellEdgeLengths[x]
                    edge_layer[e] = z
                    horizontal_edges.append(e)
        else:
            for x in range(xSize):
                for y in range(ySize - 1):
                    e = (x, y, z, x, y + 1, z)
                    c = cap_grid[y][x]
                    edge_capacity[e] = c
                    edge_length[e] = VerticalGCellEdgeLengths[y]
                    edge_layer[e] = z
                    vertical_edges.append(e)

    for x in range(xSize):
        for y in range(ySize):
            for z in range(nLayers - 1):
                e = (x, y, z, x, y, z + 1)
                edge_capacity[e] = float('inf')
                edge_length[e] = 0
                via_edges.append(e)

    all_edges = horizontal_edges + vertical_edges + via_edges
    edge_to_idx = {e: i for i, e in enumerate(all_edges)}
    idx_to_edge = {i: e for e, i in edge_to_idx.items()}

    def vertex_to_idx(v):
        x, y, z = v
        return z * (xSize * ySize) + y * xSize + x

    def idx_to_vertex(idx):
        z = idx // (xSize * ySize)
        rem = idx % (xSize * ySize)
        y = rem // xSize
        x = rem % xSize
        return (x, y, z)

    n_vertices = nLayers * xSize * ySize
    adjacency = [[] for _ in range(n_vertices)]
    for e in all_edges:
        x1, y1, z1, x2, y2, z2 = e
        u = vertex_to_idx((x1, y1, z1))
        v = vertex_to_idx((x2, y2, z2))
        e_idx = edge_to_idx[e]
        adjacency[u].append((v, e_idx))
        adjacency[v].append((u, e_idx))

    edge_usage = [0] * len(all_edges)

    def dijkstra(source, targets_set, edge_usage):
        dist = [float('inf')] * n_vertices
        prev = [-1] * n_vertices
        prev_edge = [-1] * n_vertices
        dist[source] = 0
        heap = [(0, source)]
        while heap:
            d, u = heapq.heappop(heap)
            if d > dist[u]:
                continue
            if u in targets_set:
                continue
            for v, e_idx in adjacency[u]:
                e = idx_to_edge[e_idx]
                x1, y1, z1, x2, y2, z2 = e
                if z1 == 0 and z1 == z2:
                    continue
                base_cost = 0
                if z1 == z2:
                    base_cost = UnitLengthWireCost * edge_length[e]
                else:
                    base_cost = UnitViaCost
                cap = edge_capacity[e]
                if cap < float('inf'):
                    usage = edge_usage[e_idx]
                    overflow = max(0, usage + 1 - cap)
                    penalty = OFWeight[z1] * math.exp(0.5 * overflow)
                    base_cost += penalty
                new_dist = dist[u] + base_cost
                if new_dist < dist[v]:
                    dist[v] = new_dist
                    prev[v] = u
                    prev_edge[v] = e_idx
                    heapq.heappush(heap, (new_dist, v))
        return dist, prev, prev_edge

    def reconstruct_path(target, prev, prev_edge):
        path_edges = []
        v = target
        while prev[v] != -1:
            e_idx = prev_edge[v]
            path_edges.append(e_idx)
            v = prev[v]
        return path_edges[::-1]

    net_solutions = []
    for net_name, pins in nets:
        pin_vertices = []
        for pin in pins:
            verts = [vertex_to_idx((x, y, z)) for z, x, y in pin]
            pin_vertices.append(verts)
        m = len(pin_vertices)
        if m == 0:
            net_solutions.append((net_name, []))
            continue
        terminals = []
        for verts in pin_vertices:
            terminals.append(verts[0])
        steiner_edges = set()
        connected = set([terminals[0]])
        remaining = set(terminals[1:])
        while remaining:
            best_dist = float('inf')
            best_target = None
            best_prev = None
            best_prev_edge = None
            for src in connected:
                dist, prev, prev_edge = dijkstra(src, connected, edge_usage)
                for tgt in remaining:
                    if dist[tgt] < best_dist:
                        best_dist = dist[tgt]
                        best_target = tgt
                        best_prev = prev
                        best_prev_edge = prev_edge
            if best_target is None:
                break
            path_edges = reconstruct_path(best_target, best_prev, best_prev_edge)
            for e_idx in path_edges:
                steiner_edges.add(e_idx)
            v = best_target
            while best_prev[v] != -1:
                connected.add(v)
                v = best_prev[v]
            connected.add(v)
            remaining.remove(best_target)
        net_solutions.append((net_name, list(steiner_edges)))
        for e_idx in steiner_edges:
            edge_usage[e_idx] += 1

    def edges_to_segments(edge_indices):
        if not edge_indices:
            return []
        edges = [idx_to_edge[i] for i in edge_indices]
        G = defaultdict(set)
        for e in edges:
            x1, y1, z1, x2, y2, z2 = e
            u = (x1, y1, z1)
            v = (x2, y2, z2)
            G[u].add(v)
            G[v].add(u)
        visited = set()
        segments = []
        for node in list(G.keys()):
            if node in visited:
                continue
            stack = [node]
            comp_nodes = []
            while stack:
                cur = stack.pop()
                if cur in visited:
                    continue
                visited.add(cur)
                comp_nodes.append(cur)
                for nb in G[cur]:
                    if nb not in visited:
                        stack.append(nb)
            if not comp_nodes:
                continue
            comp_nodes_set = set(comp_nodes)
            while comp_nodes_set:
                start = next(iter(comp_nodes_set))
                q = deque([start])
                visited_comp = set()
                while q:
                    cur = q.popleft()
                    if cur in visited_comp:
                        continue
                    visited_comp.add(cur)
                    for nb in G[cur]:
                        if nb in comp_nodes_set:
                            q.append(nb)
                comp_nodes_set -= visited_comp
                deg = {v: len([u for u in G[v] if u in visited_comp]) for v in visited_comp}
                leaves = [v for v, d in deg.items() if d == 1]
                if not leaves:
                    leaves = [next(iter(visited_comp))]
                for leaf in leaves:
                    cur = leaf
                    prev = None
                    while True:
                        neighbors = [n for n in G[cur] if n in visited_comp and n != prev]
                        if not neighbors:
                            break
                        next_node = neighbors[0]
                        x1, y1, z1 = cur
                        x2, y2, z2 = next_node
                        if z1 == z2:
                            if y1 == y2:
                                dx = abs(x2 - x1)
                                if dx > 0:
                                    xl, xh = min(x1, x2), max(x1, x2)
                                    segments.append((xl, y1, z1, xh, y1, z1))
                            elif x1 == x2:
                                dy = abs(y2 - y1)
                                if dy > 0:
                                    yl, yh = min(y1, y2), max(y1, y2)
                                    segments.append((x1, yl, z1, x1, yh, z1))
                        else:
                            dz = abs(z2 - z1)
                            if dz > 0:
                                zl, zh = min(z1, z2), max(z1, z2)
                                segments.append((x1, y1, zl, x1, y1, zh))
                        prev, cur = cur, next_node
        return segments

    with open(solution_file, 'w') as f:
        for net_name, edges in net_solutions:
            f.write(net_name + '\n')
            f.write('(\n')
            segments = edges_to_segments(edges)
            for seg in segments:
                f.write(' '.join(map(str, seg)) + '\n')
            f.write(')\n')

