import json
from collections import deque, defaultdict
import heapq

def solve(input_file: str, solution_file: str):
    with open(input_file, 'r') as f:
        data = json.load(f)

    delay = data['delay']
    resource = data['resource']
    nodes = data['nodes']
    edges = data['edges']

    node_to_idx = {}
    idx_to_node = []
    node_type = []

    for i, (node_id, node_res) in enumerate(nodes):
        node_to_idx[node_id] = i
        idx_to_node.append(node_id)
        node_type.append(node_res)

    n = len(nodes)
    adj = [[] for _ in range(n)]
    indegree = [0] * n
    outdegree = [0] * n

    for src, dst, _ in edges:
        u = node_to_idx[src]
        v = node_to_idx[dst]
        adj[u].append(v)
        indegree[v] += 1
        outdegree[u] += 1

    resource_types = list(resource.keys())
    type_to_idx = {rt: i for i, rt in enumerate(resource_types)}
    num_resources = len(resource_types)

    res_limits = [resource[rt] for rt in resource_types]
    delays = [delay[node_type[i]] for i in range(n)]

    node_res_idx = [type_to_idx[node_type[i]] for i in range(n)]

    def compute_est_lst(L):
        est = [0] * n
        indegree_copy = indegree[:]
        q = deque()
        for i in range(n):
            if indegree_copy[i] == 0:
                q.append(i)

        while q:
            u = q.popleft()
            for v in adj[u]:
                est[v] = max(est[v], est[u] + delays[u])
                indegree_copy[v] -= 1
                if indegree_copy[v] == 0:
                    q.append(v)

        lst = [L] * n
        outdegree_copy = outdegree[:]
        rev_adj = [[] for _ in range(n)]
        for u in range(n):
            for v in adj[u]:
                rev_adj[v].append(u)

        q = deque()
        for i in range(n):
            if outdegree_copy[i] == 0:
                lst[i] = L - delays[i]
                q.append(i)

        while q:
            v = q.popleft()
            for u in rev_adj[v]:
                lst[u] = min(lst[u], lst[v] - delays[u])
                outdegree_copy[u] -= 1
                if outdegree_copy[u] == 0:
                    q.append(u)

        for i in range(n):
            lst[i] = min(lst[i], L - delays[i])
            lst[i] = max(lst[i], est[i])

        return est, lst

    def try_schedule(L):
        est, lst = compute_est_lst(L)

        start_times = [-1] * n
        resource_usage = [[0] * (L + 1) for _ in range(num_resources)]
        unscheduled_preds = indegree[:]
        ready = set()

        for i in range(n):
            if unscheduled_preds[i] == 0:
                ready.add(i)

        def earliest_feasible_start(node):
            r = node_res_idx[node]
            limit = res_limits[r]
            d = delays[node]
            for start in range(est[node], lst[node] + 1):
                if start + d - 1 > L:
                    break
                feasible = True
                for t in range(start, start + d):
                    if resource_usage[r][t] >= limit:
                        feasible = False
                        break
                if feasible:
                    return start
            return None

        while ready:
            best_node = None
            best_eft = L + 1
            best_lst = L + 1

            for node in ready:
                eft = earliest_feasible_start(node)
                if eft is None:
                    continue
                if eft < best_eft or (eft == best_eft and lst[node] < best_lst):
                    best_eft = eft
                    best_lst = lst[node]
                    best_node = node

            if best_node is None:
                return False, None

            start_times[best_node] = best_eft
            r = node_res_idx[best_node]
            d = delays[best_node]
            for t in range(best_eft, best_eft + d):
                resource_usage[r][t] += 1

            ready.remove(best_node)
            for v in adj[best_node]:
                unscheduled_preds[v] -= 1
                if unscheduled_preds[v] == 0:
                    ready.add(v)

        if all(st != -1 for st in start_times):
            return True, start_times
        return False, None

    cpl = 0
    est_no_res = [0] * n
    indegree_copy = indegree[:]
    q = deque()
    for i in range(n):
        if indegree_copy[i] == 0:
            q.append(i)

    while q:
        u = q.popleft()
        est_no_res[u] = max(est_no_res[u], 0)
        for v in adj[u]:
            est_no_res[v] = max(est_no_res[v], est_no_res[u] + delays[u])
            indegree_copy[v] -= 1
            if indegree_copy[v] == 0:
                q.append(v)

    cpl = max(est_no_res[i] + delays[i] for i in range(n))

    low = cpl
    high = cpl + n * max(delays)

    best_schedule = None
    best_makespan = None

    while low <= high:
        mid = (low + high) // 2
        feasible, schedule = try_schedule(mid)
        if feasible:
            best_schedule = schedule
            best_makespan = mid
            high = mid - 1
        else:
            low = mid + 1

    if best_schedule is None:
        best_schedule = [0] * n

    with open(solution_file, 'w') as f:
        for i in range(n):
            f.write(f"{idx_to_node[i]}:{best_schedule[i]}\n")

