                                # Case 2: c2 from v, c1 from other
                                if (c2 == a1 or c2 == a2) and (c1 == b1 or c1 == b2):
                                    possible = True

                                if possible:
                                    cost = dp[child][g_child] + (0 if g_other in compatible[other_parent] else 1)
                                    if cost < min_child_cost:
                                        min_child_cost = cost
                                        best_child_genotype = g_child
                                        best_other_genotype = g_other

                        if min_child_cost < INF:
                            total_cost += min_child_cost
                            child_costs.append((best_child_genotype, best_other_genotype))
                        else:
                            total_cost = INF
                            break
                    else:
                        # Single parent constraint
                        min_child_cost = INF
                        best_g_child = -1
                        for g_child in range(n_genotypes):
                            # Check allele sharing
                            a1, a2 = genotypes[g_v]
                            b1, b2 = genotypes[g_child]
                            if a1 == b1 or a1 == b2 or a2 == b1 or a2 == b2:
                                cost = dp[child][g_child]
                                if cost < min_child_cost:
                                    min_child_cost = cost
                                    best_g_child = g_child

                        if min_child_cost < INF:
                            total_cost += min_child_cost
                            child_costs.append((best_g_child, -1))
                        else:
                            total_cost = INF
                            break

                if total_cost < INF:
                    dp[v][g_v] = total_cost
                    best_child[v][g_v] = child_costs

    # Find best root (individuals without parents)
    roots = [i for i in range(n_individuals) if i not in father_of and i not in mother_of]

    # Assign genotypes
    assignment = [-1] * n_individuals
    visited_assign = [False] * n_individuals

    def assign_genotype(person, genotype_idx):
        assignment[person] = genotype_idx
        visited_assign[person] = True

        # Assign to children
        child_info = best_child[person][genotype_idx]
        if child_info:
            for idx, child in enumerate(children[person]):
                if visited_assign[child]:
                    continue

                if child in nuclear_families:
                    father, mother = nuclear_families[child]
                    if person == father:
                        other_parent = mother
                        child_genotype, other_genotype = child_info[idx]

                        if not visited_assign[other_parent]:
                            assign_genotype(other_parent, other_genotype)
                        if not visited_assign[child]:
                            assign_genotype(child, child_genotype)
                    else:
                        other_parent = father
                        child_genotype, other_genotype = child_info[idx]

                        if not visited_assign[other_parent]:
                            assign_genotype(other_parent, other_genotype)
                        if not visited_assign[child]:
                            assign_genotype(child, child_genotype)
                else:
                    child_genotype, _ = child_info[idx]
                    if not visited_assign[child]:
                        assign_genotype(child, child_genotype)

    # Start from roots
    for root in roots:
        if visited_assign[root]:
            continue
        best_genotype = min(range(n_genotypes), key=lambda g: dp[root][g])
        assign_genotype(root, best_genotype)

    # For any unassigned (shouldn't happen), assign compatible genotype
    for i in range(n_individuals):
        if assignment[i] == -1:
            if compatible[i]:
                assignment[i] = next(iter(compatible[i]))
            else:
                assignment[i] = 0

    # Write output
    with open(solution_file, 'w') as f:
        f.write(' '.join(str(g) for g in assignment))

