import numpy as np
import random
from dataclasses import dataclass
from typing import Dict, List, Tuple

def calculate_distance(x1: float, y1: float, x2: float, y2: float) -> float:
    return round(((x2 - x1) ** 2 + (y1 - y2) ** 2) ** 0.5, 0)

@dataclass
class Node:
    index: int
    x: float
    y: float
    demand: float
    earliest_time: float
    latest_time: float
    service_time: float
    pickup_sibling: int
    delivery_sibling: int
    is_pickup: bool

@dataclass
class Instance:
    name: str
    type: str
    dimension: int
    vehicles: int
    capacity: float
    edge_weight_type: str
    nodes: Dict[int, Node]
    depot_node: List[int]

class PDPTWSolver:
    def __init__(self, instance):
        self.instance = instance
        self.n = instance.dimension
        self.capacity = instance.capacity
        self.max_vehicles = instance.vehicles
        self.nodes = instance.nodes
        self.depot = instance.depot_node[0]

        self.dist_matrix = self._compute_distance_matrix()
        self.pickup_to_delivery = {}
        self.delivery_to_pickup = {}
        for idx, node in self.nodes.items():
            if node.pickup_sibling != 0:
                self.delivery_to_pickup[idx] = node.pickup_sibling
            if node.delivery_sibling != 0:
                self.pickup_to_delivery[idx] = node.delivery_sibling

        self.all_customers = [i for i in range(2, self.n + 1)]

    def _compute_distance_matrix(self):
        dist = np.zeros((self.n + 1, self.n + 1))
        for i in range(1, self.n + 1):
            for j in range(1, self.n + 1):
                if i != j:
                    dist[i][j] = calculate_distance(
                        self.nodes[i].x, self.nodes[i].y,
                        self.nodes[j].x, self.nodes[j].y
                    )
        return dist

    def _check_time_window(self, current_time, node_idx):
        node = self.nodes[node_idx]
        arrival = current_time
        if arrival < node.earliest_time:
            arrival = node.earliest_time
        departure = arrival + node.service_time
        return departure <= node.latest_time, arrival, departure

    def _check_capacity(self, current_load, node_idx):
        demand = self.nodes[node_idx].demand
        new_load = current_load + demand
        return new_load >= 0 and new_load <= self.capacity, new_load

    def _check_precedence_in_route(self, route, node_idx, visited):
        if node_idx in self.pickup_to_delivery:
            delivery = self.pickup_to_delivery[node_idx]
            return delivery not in visited
        elif node_idx in self.delivery_to_pickup:
            pickup = self.delivery_to_pickup[node_idx]
            return pickup in visited
        return True

    def _evaluate_route(self, route):
        if not route:
            return True, 0

        current_time = 0
        current_load = 0
        total_distance = 0
        current_pos = self.depot

        visited = set()

        for i, node_idx in enumerate(route):
            if node_idx in visited:
                return False, 0
            visited.add(node_idx)

            travel_time = self.dist_matrix[current_pos][node_idx]
            current_time += travel_time

            feasible, arrival, departure = self._check_time_window(current_time, node_idx)
            if not feasible:
                return False, 0

            capacity_ok, new_load = self._check_capacity(current_load, node_idx)
            if not capacity_ok:
                return False, 0

            if not self._check_precedence_in_route(route[:i], node_idx, visited):
                return False, 0

            current_time = departure
            current_load = new_load
            total_distance += travel_time
            current_pos = node_idx

        total_distance += self.dist_matrix[current_pos][self.depot]
        return True, total_distance

    def _calculate_insertion_cost(self, route, pos, node_idx):
        if pos == 0:
            prev = self.depot
        else:
            prev = route[pos-1]
        if pos == len(route):
            next_node = self.depot
        else:
            next_node = route[pos]

        old_dist = self.dist_matrix[prev][next_node] if prev != next_node else 0
        new_dist = self.dist_matrix[prev][node_idx] + self.dist_matrix[node_idx][next_node]
        return new_dist - old_dist

    def _find_best_insertion(self, routes, node):
        best_route_idx = -1
        best_pos = -1
        best_cost = float('inf')

        for ridx, route in enumerate(routes):
            for pos in range(len(route) + 1):
                cost = self._calculate_insertion_cost(route, pos, node)
                if cost < best_cost:
                    new_route = route[:pos] + [node] + route[pos:]
                    feasible, _ = self._evaluate_route(new_route)
                    if feasible:
                        best_cost = cost
                        best_route_idx = ridx
                        best_pos = pos

        return best_route_idx, best_pos, best_cost

    def _greedy_insertion_all_nodes(self):
        unassigned = list(self.all_customers)
        random.shuffle(unassigned)
        routes = []

        for node in unassigned:
            if len(routes) < self.max_vehicles:
                new_route = [node]
                feasible, _ = self._evaluate_route(new_route)
                if feasible:
                    routes.append(new_route)
                    continue

            best_route_idx, best_pos, best_cost = self._find_best_insertion(routes, node)
            if best_route_idx != -1:
                routes[best_route_idx].insert(best_pos, node)
            elif len(routes) < self.max_vehicles:
                routes.append([node])
            else:
                best_route_idx = 0
                min_cost_increase = float('inf')
                for ridx, route in enumerate(routes):
                    for pos in range(len(route) + 1):
                        cost = self._calculate_insertion_cost(route, pos, node)
                        if cost < min_cost_increase:
                            min_cost_increase = cost
                            best_route_idx = ridx
                            best_pos = pos
                routes[best_route_idx].insert(best_pos, node)

        return routes

    def _two_opt(self, route):
        if len(route) < 2:
            return route

        best_route = route[:]
        feasible, best_dist = self._evaluate_route(route)
        if not feasible:
            return route

        improved = True
        while improved:
            improved = False
            for i in range(len(best_route) - 1):
                for j in range(i + 2, len(best_route)):
                    new_route = best_route[:]
                    new_route[i:j] = reversed(new_route[i:j])
                    feasible, dist = self._evaluate_route(new_route)
                    if feasible and dist < best_dist:
                        best_route = new_route
                        best_dist = dist
                        improved = True
                        break
                if improved:
                    break

        return best_route

    def _relocate(self, routes):
        improved = True
        iteration = 0
        max_iterations = 5

        while improved and iteration < max_iterations:
            improved = False
            iteration += 1

            for i in range(len(routes)):
                for j in range(len(routes)):
                    if i == j:
                        continue

                    route1 = routes[i]
                    route2 = routes[j]

                    if len(route1) == 0:
                        continue

                    for idx1 in range(len(route1)):
                        node = route1[idx1]
                        new_route1 = route1[:idx1] + route1[idx1+1:]

                        for idx2 in range(len(route2) + 1):
                            new_route2 = route2[:idx2] + [node] + route2[idx2:]

                            feasible1, dist1 = self._evaluate_route(new_route1)
                            feasible2, dist2 = self._evaluate_route(new_route2)

                            if feasible1 and feasible2:
                                old_dist = self._evaluate_route(route1)[1] + self._evaluate_route(route2)[1]
                                new_dist = dist1 + dist2

                                if new_dist < old_dist:
                                    routes[i] = new_route1
                                    routes[j] = new_route2
                                    improved = True
                                    break
                        if improved:
                            break
                    if improved:
                        break
                if improved:
                    break

        return routes

    def _exchange(self, routes):
        improved = True
        iteration = 0
        max_iterations = 5

        while improved and iteration < max_iterations:
            improved = False
            iteration += 1

            for i in range(len(routes)):
                for j in range(i + 1, len(routes)):
                    route1 = routes[i]
                    route2 = routes[j]

                    for idx1 in range(len(route1)):
                        for idx2 in range(len(route2)):
                            new_route1 = route1[:]
                            new_route2 = route2[:]
                            new_route1[idx1], new_route2[idx2] = new_route2[idx2], new_route1[idx1]

                            feasible1, dist1 = self._evaluate_route(new_route1)
                            feasible2, dist2 = self._evaluate_route(new_route2)

                            if feasible1 and feasible2:
                                old_dist = self._evaluate_route(route1)[1] + self._evaluate_route(route2)[1]
                                new_dist = dist1 + dist2

                                if new_dist < old_dist:
                                    routes[i] = new_route1
                                    routes[j] = new_route2
                                    improved = True
                                    break
                        if improved:
                            break
                    if improved:
                        break
                if improved:
                    break

        return routes

    def _ensure_all_nodes_visited(self, routes):
        visited = set()
        for route in routes:
            visited.update(route)

        all_nodes = set(self.all_customers)
        missing_nodes = all_nodes - visited

        for node in missing_nodes:
            best_route_idx, best_pos, _ = self._find_best_insertion(routes, node)
            if best_route_idx != -1:
                routes[best_route_idx].insert(best_pos, node)
            elif len(routes) < self.max_vehicles:
                routes.append([node])
            else:
                routes[0].append(node)

        return routes

    def solve(self):
        routes = self._greedy_insertion_all_nodes()

        routes = self._ensure_all_nodes_visited(routes)

        for i in range(len(routes)):
            routes[i] = self._two_opt(routes[i])

        routes = self._relocate(routes)
        routes = self._exchange(routes)

        for i in range(len(routes)):
            routes[i] = self._two_opt(routes[i])

        final_routes = []
        for route in routes:
            if route:
                final_routes.append([self.depot] + route + [self.depot])

        return final_routes

def solve(input_file: str, solution_file: str):
    from dataclasses import dataclass
