import json
from collections import defaultdict, deque

def list_schedule(nodes, predecessors, successors, node_resource, resource_delay, resource_limit, priorities):
    scheduled = {}
    finish_time = {}
    resource_busy = defaultdict(int)
    in_degree = {n: len(predecessors[n]) for n in nodes}
    ready = {n for n in nodes if in_degree[n] == 0}

    time = 0
    while len(scheduled) < len(nodes):
        current_ready = []
        for n in ready:
            earliest = 0
            for p in predecessors[n]:
                earliest = max(earliest, finish_time[p])
            if earliest <= time:
                current_ready.append(n)

        if not current_ready:
            possible_next = []
            for n in ready:
                earliest = 0
                for p in predecessors[n]:
                    earliest = max(earliest, finish_time[p])
                if earliest > time:
                    possible_next.append(earliest)
            if possible_next:
                time = min(possible_next)
            else:
                time += 1
            continue

        current_ready.sort(key=lambda n: priorities[n])

        any_started = False
        for n in current_ready:
            r = node_resource[n]
            d = resource_delay[r]
            limit = resource_limit[r]

            can_schedule = True
            for t in range(time, time + d):
                if resource_busy[(r, t)] >= limit:
                    can_schedule = False
                    break

            if can_schedule:
                scheduled[n] = time
                finish_time[n] = time + d
                for t in range(time, time + d):
                    resource_busy[(r, t)] += 1
                ready.remove(n)
                for s in successors[n]:
                    in_degree[s] -= 1
                    if in_degree[s] == 0:
                        ready.add(s)
                any_started = True

        if not any_started:
            possible_next = [ft for ft in finish_time.values() if ft > time]
            if possible_next:
                time = min(possible_next)
            else:
                time += 1
        else:
            time += 1

    latency = max(finish_time.values(), default=0)
    return scheduled, latency

def solve(input_file: str, solution_file: str):
    with open(input_file, 'r') as f:
        data = json.load(f)

    res_delay = data['delay']
    res_limit = data['resource']
    nodes_data = data['nodes']
    edges_data = data['edges']

    nodes = [n[0] for n in nodes_data]
    node_res = {n[0]: n[1] for n in nodes_data}

    succ = defaultdict(list)
    pred = defaultdict(list)
    for s, d, _ in edges_data:
        succ[s].append(d)
        pred[d].append(s)

    def get_metrics(nodes, succ, pred, node_res, res_delay):
        in_deg = {n: len(pred[n]) for n in nodes}
        topo = []
        stack = [n for n in nodes if in_deg[n] == 0]
        while stack:
            n = stack.pop()
            topo.append(n)
            for s in succ[n]:
                in_deg[s] -= 1
                if in_deg[s] == 0:
                    stack.append(s)

        cp = {}
        for n in reversed(topo):
            cp[n] = res_delay[node_res[n]] + max((cp[s] for s in succ[n]), default=0)

        desc = {n: set() for n in nodes}
        for n in reversed(topo):
            for s in succ[n]:
                desc[n].add(s)
                desc[n].update(desc[s])
        num_desc = {n: len(desc[n]) for n in nodes}

        num_succ = {n: len(succ[n]) for n in nodes}
        return cp, num_desc, num_succ

    cp_f, nd_f, ns_f = get_metrics(nodes, succ, pred, node_res, res_delay)
    cp_b, nd_b, ns_b = get_metrics(nodes, pred, succ, node_res, res_delay)

    best_schedule = None
    min_latency = float('inf')

    p_schemes_f = [
        {n: (-cp_f[n], -nd_f[n], -res_delay[node_res[n]], n) for n in nodes},
        {n: (-cp_f[n], -res_delay[node_res[n]], -nd_f[n], n) for n in nodes},
        {n: (-cp_f[n], -ns_f[n], -res_delay[node_res[n]], n) for n in nodes},
        {n: (-cp_f[n], n) for n in nodes}
    ]

    for ps in p_schemes_f:
        sched, lat = list_schedule(nodes, pred, succ, node_res, res_delay, res_limit, ps)
        if lat < min_latency:
            min_latency = lat
            best_schedule = sched

    p_schemes_b = [
        {n: (-cp_b[n], -nd_b[n], -res_delay[node_res[n]], n) for n in nodes},
        {n: (-cp_b[n], -res_delay[node_res[n]], -nd_b[n], n) for n in nodes},
        {n: (-cp_b[n], -ns_b[n], -res_delay[node_res[n]], n) for n in nodes},
        {n: (-cp_b[n], n) for n in nodes}
    ]

    for ps in p_schemes_b:
        sched_b, lat_b = list_schedule(nodes, succ, pred, node_res, res_delay, res_limit, ps)
        sched = {n: lat_b - (sched_b[n] + res_delay[node_res[n]]) for n in nodes}
        if lat_b < min_latency:
            min_latency = lat_b
            best_schedule = sched

    with open(solution_file, 'w') as f:
        for n in nodes:
            f.write(f"{n}:{best_schedule[n]}\n")

