import numpy as np
import sys

def solve(input_file: str, solution_file: str):
    pedigree_data = []
    alleles_set = set()
    with open(input_file, 'r') as f:
        for line in f:
            parts = list(map(int, line.split()))
            if not parts: continue
            pedigree_data.append(parts)
            if parts[5] > 0: alleles_set.add(parts[5])
            if parts[6] > 0: alleles_set.add(parts[6])

    if not pedigree_data:
        return

    m = len(pedigree_data)
    sorted_alleles = sorted(list(alleles_set))
    allele_map = {a: i + 1 for i, a in enumerate(sorted_alleles)}
    n_alleles = len(sorted_alleles)

    # Domain D: (a, b) with 1 <= a <= b <= n_alleles
    domain = []
    for a in range(1, n_alleles + 1):
        for b in range(a, n_alleles + 1):
            domain.append((a, b))
    d_size = len(domain)

    id_to_idx = {row[1]: i for i, row in enumerate(pedigree_data)}

    # Unary costs
    unary_costs = np.zeros((m, d_size), dtype=np.int32)
    for i, row in enumerate(pedigree_data):
        a1_obs = allele_map.get(row[5], 0)
        a2_obs = allele_map.get(row[6], 0)
        if a1_obs == 0 and a2_obs == 0:
            continue
        obs_set = sorted([a for a in [a1_obs, a2_obs] if a > 0])
        for j, (da, db) in enumerate(domain):
            if len(obs_set) == 1:
                if obs_set[0] != da and obs_set[0] != db:
                    unary_costs[i, j] = 1
            elif len(obs_set) == 2:
                if not (obs_set[0] == da and obs_set[1] == db):
                    unary_costs[i, j] = 1

    # Relationships
    parents = [[] for _ in range(m)]
    children = [[] for _ in range(m)]
    for i, row in enumerate(pedigree_data):
        f_id, m_id = row[2], row[3]
        if f_id in id_to_idx:
            f_idx = id_to_idx[f_id]
            parents[i].append(f_idx)
            children[f_idx].append(i)
        if m_id in id_to_idx:
            m_idx = id_to_idx[m_id]
            parents[i].append(m_idx)
            children[m_idx].append(i)

    # Precompute Mendelian consistency
    # C_jki(x_j, x_k, x_i) = 0 if (a in x_j and b in x_k) or (a in x_k and b in x_j)
    # where x_i = {a, b}
    mendel_mask = np.zeros((d_size, d_size, d_size), dtype=bool)
    for idx_i, (ai, bi) in enumerate(domain):
        for idx_j, (aj, bj) in enumerate(domain):
            for idx_k, (ak, bk) in enumerate(domain):
                if ((ai == aj or ai == bj) and (bi == ak or bi == bk)) or \
                   ((ai == ak or ai == bk) and (bi == aj or bi == bj)):
                    mendel_mask[idx_i, idx_j, idx_k] = True

    # Simple DP/Message Passing for Tree-like structures or small pedigrees
    # Since general pedigrees are NP-hard, we use a heuristic or simplified search
    # For this implementation, we'll use a greedy approach with local search or 
    # a simplified belief propagation if the structure allows.
    # Given the constraints and problem type, a state-space search (DFS with pruning)
    # or a basic iterative improvement might be more robust.

    best_assignment = [0] * m
    min_total_cost = float('inf')

    def get_cost(assignment):
        cost = 0
        for i in range(m):
            cost += unary_costs[i, assignment[i]]
            p = parents[i]
            if len(p) == 2:
                if not mendel_mask[assignment[i], assignment[p[0]], assignment[p[1]]]:
                    return float('inf')
            elif len(p) == 1:
                # Binary constraint: child shares at least one allele with parent
                xi = domain[assignment[i]]
                xj = domain[assignment[p[0]]]
                if not (xi[0] in xj or xi[1] in xj):
                    return float('inf')
        return cost

    # Initial greedy assignment
    current_assignment = [0] * m
    for i in range(m):
        best_u = 0
        min_u = 2
        for j in range(d_size):
            if unary_costs[i, j] < min_u:
                min_u = unary_costs[i, j]
                best_u = j
        current_assignment[i] = best_u

    # Refine using a simple hill climbing / local search
    import random
    best_total_cost = get_cost(current_assignment)

    # If initial is invalid, try to find a valid one
    if best_total_cost == float('inf'):
        for _ in range(2000):
            temp_assignment = [random.randint(0, d_size - 1) for _ in range(m)]
            c = get_cost(temp_assignment)
            if c < best_total_cost:
                best_total_cost = c
                current_assignment = temp_assignment
                if c == 0: break

    # Local search refinement
    if best_total_cost != float('inf'):
        improved = True
        while improved:
            improved = False
            for i in range(m):
                old_val = current_assignment[i]
                for j in range(d_size):
                    if j == old_val: continue
                    current_assignment[i] = j
                    c = get_cost(current_assignment)
                    if c < best_total_cost:
                        best_total_cost = c
                        improved = True
                        break
                    else:
                        current_assignment[i] = old_val
            if best_total_cost == 0: break

    with open(solution_file, 'w') as f:
        f.write(" ".join(map(str, current_assignment)) + "\n")

