import collections
import sys

def solve(input_file: str, solution_file: str):
    """
    Solve the technology mapping optimization problem for 6-LUTs.
    Optimized for performance and area-flow.
    """
    sys.setrecursionlimit(10000)

    def parse_blif(filename):
        with open(filename, 'r') as f:
            content = f.read()

        lines = []
        for line in content.split('\n'):
            line = line.split('#')[0].strip()
            if not line: continue
            lines.append(line)

        processed_lines = []
        if lines:
            curr = lines[0]
            for i in range(1, len(lines)):
                if curr.endswith('\\'):
                    curr = curr[:-1] + lines[i]
                else:
                    processed_lines.append(curr)
                    curr = lines[i]
            processed_lines.append(curr)

        model_name, inputs, outputs, nodes = "", [], [], {}
        i = 0
        while i < len(processed_lines):
            line = processed_lines[i]
            parts = line.split()
            if not parts: 
                i += 1
                continue
            if parts[0] == '.model':
                model_name = parts[1]
            elif parts[0] == '.inputs':
                inputs.extend(parts[1:])
            elif parts[0] == '.outputs':
                outputs.extend(parts[1:])
            elif parts[0] == '.names':
                out_node = parts[-1]
                in_nodes = parts[1:-1]
                table = []
                i += 1
                while i < len(processed_lines) and not processed_lines[i].startswith('.'):
                    table.append(processed_lines[i])
                    i += 1
                nodes[out_node] = {'inputs': in_nodes, 'table': table}
                continue
            i += 1
        return model_name, inputs, outputs, nodes

    model_name, pi_list, po_list, node_data = parse_blif(input_file)
    pi_set = set(pi_list)
    new_node_data = {}
    node_counter = 0

    def get_new_node_name():
        nonlocal node_counter
        name = f"__m{node_counter}"
        node_counter += 1
        return name

    # Decompose nodes with fanin > 6 into a tree of 6-input gates
    for node, data in node_data.items():
        inps, table = data['inputs'], data['table']
        if len(inps) <= 6:
            new_node_data[node] = data
            continue

        is_explicit_zero = any(row.endswith(' 0') for row in table)
        cube_outputs = []
        for row in table:
            parts = row.split()
            if not parts: continue
            pattern = parts[0]
            lits = []
            for idx, char in enumerate(pattern):
                if char == '1': lits.append((inps[idx], '1'))
                elif char == '0': lits.append((inps[idx], '0'))

            while len(lits) > 6:
                group, lits = lits[:6], lits[6:]
                tmp = get_new_node_name()
                new_node_data[tmp] = {'inputs': [l[0] for l in group], 'table': ["".join(l[1] for l in group) + " 1"]}
                lits.append((tmp, '1'))

            tmp = get_new_node_name()
            if not lits:
                new_node_data[tmp] = {'inputs': [], 'table': ["1"]}
            else:
                new_node_data[tmp] = {'inputs': [l[0] for l in lits], 'table': ["".join(l[1] for l in lits) + " 1"]}
            cube_outputs.append(tmp)

        if not cube_outputs:
            new_node_data[node] = {'inputs': [], 'table': []}
            continue

        while len(cube_outputs) > 6:
            group, cube_outputs = cube_outputs[:6], cube_outputs[6:]
            tmp = get_new_node_name()
            new_node_data[tmp] = {'inputs': group, 'table': [("-" * j + "1" + "-" * (len(group)-1-j) + " 1") for j in range(len(group))]}
            cube_outputs.append(tmp)

        if is_explicit_zero:
            tmp = get_new_node_name()
            new_node_data[tmp] = {'inputs': cube_outputs, 'table': [("-" * j + "1" + "-" * (len(cube_outputs)-1-j) + " 1") for j in range(len(cube_outputs))]}
            new_node_data[node] = {'inputs': [tmp], 'table': ["0 1"]}
        else:
            new_node_data[node] = {'inputs': cube_outputs, 'table': [("-" * j + "1" + "-" * (len(cube_outputs)-1-j) + " 1") for j in range(len(cube_outputs))]}

    # Build graph and topological order
    adj = collections.defaultdict(list)
    preds = collections.defaultdict(list)
    in_degree = collections.defaultdict(int)
    all_nodes = set(pi_list) | set(new_node_data.keys())
    for node, data in new_node_data.items():
        for inp in data['inputs']:
            adj[inp].append(node)
            preds[node].append(inp)
            in_degree[node] += 1

    topo_order = []
    q = collections.deque([n for n in all_nodes if in_degree[n] == 0])
    while q:
        u = q.popleft()
        topo_order.append(u)
        for v in adj[u]:
            in_degree[v] -= 1
            if in_degree[v] == 0: q.append(v)

    topo_index = {node: idx for idx, node in enumerate(topo_order)}

    # Forward pass: Area-Flow Mapping
    best_cut, node_flow = {}, {node: 0.0 for node in pi_set}
    for node in topo_order:
        if node in pi_set:
            best_cut[node] = frozenset([node])
            continue
        curr_preds = new_node_data[node]['inputs']
        if not curr_preds:
            best_cut[node], node_flow[node] = frozenset(), 1.0
            continue
        cut = set(curr_preds)
        for _ in range(12):
            expandable = [n for n in cut if n not in pi_set]
            if not expandable: break
            target = max(expandable, key=lambda n: node_flow[n])
            new_cut = (cut - {target}) | set(new_node_data[target]['inputs'])
            if len(new_cut) <= 6: cut = new_cut
            else: break
        best_cut[node] = frozenset(cut)
        node_flow[node] = 1.0 + sum(node_flow[n] for n in cut)

    # Backward pass: Select LUTs and generate truth tables
    selected_roots, lut_defs = set(), {}
    required = collections.deque([po for po in po_list if po not in pi_set])
    visited_req = set(required)

    while required:
        curr = required.popleft()
        selected_roots.add(curr)
        cut = best_cut[curr]
        cut_list = sorted(list(cut))
        k = len(cut_list)
        if k == 0:
            val = 0
            if curr in new_node_data:
                t = new_node_data[curr]['table']
                if t and t[0].strip() in ["1", "1 1"]: val = 1
            lut_defs[curr] = ([], (["1"] if val == 1 else []))
        else:
            cone, stack, visited = [], [curr], set(cut_list)
            while stack:
                u = stack.pop()
                if u in visited: continue
                visited.add(u)
                cone.append(u)
                for p in preds[u]:
                    if p not in visited: stack.append(p)
            cone.sort(key=topo_index.get)
            sim, full_mask = {}, (1 << (1 << k)) - 1
            for i, node in enumerate(cut_list):
                m = 0
                for bit in range(1 << k):
                    if (bit >> (k - 1 - i)) & 1: m |= (1 << bit)
                sim[node] = m
            for n in cone:
                data = new_node_data[n]
                inps, table = data['inputs'], data['table']
                if not table: res = 0
                elif table == ["1"]: res = full_mask
                else:
                    is_neg = any(row.endswith(' 0') for row in table)
                    res = 0
                    for row in table:
                        parts = row.split()
                        if not parts: continue
                        row_v = full_mask
                        for char, inp in zip(parts[0], inps):
                            if char == '1': row_v &= sim[inp]
                            elif char == '0': row_v &= ~sim[inp]
                        res |= row_v
                    if is_neg: res = ~res
                sim[n] = res & full_mask
            final_val, rows = sim[curr], []
            for bit in range(1 << k):
                if (final_val >> bit) & 1: rows.append(bin(bit)[2:].zfill(k) + " 1")
            lut_defs[curr] = (cut_list, rows)
        for n in cut:
            if n not in pi_set and n not in visited_req:
                visited_req.add(n)
                required.append(n)

    # Write output BLIF
    with open(solution_file, 'w') as f:
        f.write(f".model {model_name}\n.inputs {' '.join(pi_list)}\n.outputs {' '.join(po_list)}\n")
        for po in po_list:
            if po in pi_set: f.write(f".names {po} {po}_out\n1 1\n")
        for node, (inps, table) in lut_defs.items():
            f.write(f".names {' '.join(inps)} {node}\n")
            for row in table: f.write(f"{row}\n")
        f.write(".end\n")

gemini-3.1-pro-preview.egraph_extraction:
import json
import heapq
import random
import time
from collections import defaultdict

def solve(input_file: str, solution_file: str):
    start_time = time.time()

    # Read input
    with open(input_file, 'r') as f:
        data = json.load(f)

    nodes = data['nodes']
    root_eclasses = [str(r) for r in data['root_eclasses']]

    eclass_of_node = {}
    cost_of_node = {}

    # Pass 1: Map node_id to eclass and cost
    for node_id, node_data in nodes.items():
        eclass_of_node[node_id] = str(node_data['eclass'])
        cost_of_node[node_id] = float(node_data['cost'])

    unique_children = {}
    parent_nodes = defaultdict(list)

    # Pass 2: Resolve children node_ids to eclasses and build reverse graph
    for node_id, node_data in nodes.items():
        child_eclasses = set()
        for child_ref in node_data.get('children', []):
            child_ref = str(child_ref)
            if child_ref in eclass_of_node:
                child_eclasses.add(eclass_of_node[child_ref])
            else:
                child_eclasses.add(child_ref)

        child_eclasses = tuple(child_eclasses)
        unique_children[node_id] = child_eclasses

        for child_eclass in child_eclasses:
            parent_nodes[child_eclass].append(node_id)

    # Initialize unresolved counts for cycle-breaking topological sort
    unresolved = {n: len(unique_children[n]) for n in nodes}
    pq = []
    for n in nodes:
        if unresolved[n] == 0:
            heapq.heappush(pq, (cost_of_node[n], 1, n))

    cost_m = {}
    depth_m = {}
    best_n = {}
    topo_rank = {}
    rank = 0

    # Dijkstra-like algorithm on the hypergraph to find optimal tree costs and a strict topological order
    while pq:
        c, d, n = heapq.heappop(pq)
        m = eclass_of_node[n]

        if m not in cost_m:
            cost_m[m] = c
            depth_m[m] = d
            best_n[m] = n
            topo_rank[m] = rank
            rank += 1

            for parent in parent_nodes[m]:
                unresolved[parent] -= 1
                if unresolved[parent] == 0:
                    pc = cost_of_node[parent]
                    pd = 1
                    for child in unique_children[parent]:
                        pc += cost_m[child]
                        pd = max(pd, depth_m[child] + 1)
                    heapq.heappush(pq, (pc, pd, parent))

    # Verify that all roots can be resolved without cycles
    valid_roots = list(set([r for r in root_eclasses if r in topo_rank]))
    if len(valid_roots) < len(set(root_eclasses)):
        with open(solution_file, 'w') as f:
            json.dump([], f)
        return

    # Identify safe candidates to strictly prevent cycles during DAG extraction
    safe_candidates = defaultdict(list)
    for n in nodes:
        m = eclass_of_node[n]
        if m not in topo_rank:
            continue
        m_rank = topo_rank[m]
        is_safe = True
        for c in unique_children[n]:
            if c not in topo_rank or topo_rank[c] >= m_rank:
                is_safe = False
                break
        if is_safe:
            safe_candidates[m].append(n)

    def generate_extraction(iteration):
        selected_choices = {}
        required_eclasses = set(valid_roots)

        # Process e-classes in decreasing order of topo_rank to ensure parents are processed before children
        active_q = [(-topo_rank[r], r) for r in valid_roots]
        heapq.heapify(active_q)

        while active_q:
            _, m = heapq.heappop(active_q)
            if m in selected_choices:
