        return sum(cost_of_node[n] for n in choices.values())

    def local_search(choices, current_cost):
        best_choices = choices.copy()
        best_cost = current_cost

        eclasses_to_try = list(best_choices.keys())
        random.shuffle(eclasses_to_try)

