import json
import time
import random
import os

class SegmentTree:
    def __init__(self, size):
        if size == 0:
            self.n = 0
            self.tree = []
            self.lazy = []
            return
        self.n = 1
        while self.n < size:
            self.n *= 2
        self.tree = [0] * (2 * self.n)
        self.lazy = [0] * self.n

    def apply(self, p, value):
        self.tree[p] += value
        if p < self.n:
            self.lazy[p] += value

    def build(self, p):
        while p > 1:
            p >>= 1
            self.tree[p] = max(self.tree[p<<1], self.tree[p<<1|1]) + self.lazy[p]

    def push(self, p):
        h = self.n.bit_length() - 1
        for s in range(h, 0, -1):
            i = p >> s
            if self.lazy[i] != 0:
                self.apply(i<<1, self.lazy[i])
                self.apply(i<<1|1, self.lazy[i])
                self.lazy[i] = 0

    def add(self, l, r, value):
        if self.n == 0 or l >= r: return
        l += self.n
        r += self.n
        l0, r0 = l, r

        while l < r:
            if l & 1:
                self.apply(l, value)
                l += 1
            if r & 1:
                r -= 1
                self.apply(r, value)
            l >>= 1
            r >>= 1

        self.build(l0)
        self.build(r0 - 1)

    def get_max(self, l, r):
        if self.n == 0 or l >= r: return 0
        l += self.n
        r += self.n
        self.push(l)
        self.push(r - 1)

        res = -1
        while l < r:
            if l & 1:
                if self.tree[l] > res: res = self.tree[l]
                l += 1
            if r & 1:
                r -= 1
                if self.tree[r] > res: res = self.tree[r]
            l >>= 1
            r >>= 1
        return res

    def copy(self):
        new_tree = SegmentTree(0)
        new_tree.n = self.n
        new_tree.tree = self.tree[:]
        new_tree.lazy = self.lazy[:]
        return new_tree

def solve(input_file: str, solution_file: str):
    start_time = time.time()
    time_limit = 9.5

    with open(input_file, 'r') as f:
        data = json.load(f)

    problem = data['problem']
    usage_limit = problem['usage_limit']

    nodes_data = problem['nodes']
    intervals = nodes_data['intervals']
    node_costs = nodes_data['costs']
    node_usages = nodes_data['usages']

    edges_data = problem.get('edges', {})
    edge_nodes = edges_data.get('nodes', [])
    edge_costs = edges_data.get('costs', [])

    num_nodes = len(intervals)

    def write_solution(st):
        temp_file = solution_file + ".tmp"
        with open(temp_file, 'w') as f:
            json.dump(st, f)
        os.replace(temp_file, solution_file)

    if num_nodes == 0:
        write_solution([])
        return

    edge_dict = {}
    for (u, v), c in zip(edge_nodes, edge_costs):
        if (u, v) in edge_dict:
            edge_dict[(u, v)] = tuple(a + b for a, b in zip(edge_dict[(u, v)], c))
        else:
            edge_dict[(u, v)] = tuple(c)

    edges_info = []
    adj = [[] for _ in range(num_nodes)]
    for edge_idx, ((u, v), flat_costs) in enumerate(edge_dict.items()):
        num_u_strats = len(node_costs[u])
        num_v_strats = len(node_costs[v])
        edges_info.append((u, v, flat_costs, num_u_strats, num_v_strats))
        adj[u].append((v, edge_idx, True))
        adj[v].append((u, edge_idx, False))

    num_edges = len(edges_info)

    time_points = set()
    for l, r in intervals:
        if l < r:
            time_points.add(l)
            time_points.add(r)
    sorted_times = sorted(list(time_points))
    time_to_idx = {t: i for i, t in enumerate(sorted_times)}

    num_times = len(sorted_times) - 1 if len(sorted_times) > 0 else 0
    node_intervals = []
    for l, r in intervals:
        if l < r:
            node_intervals.append((time_to_idx[l], time_to_idx[r]))
        else:
            node_intervals.append(None)

    always_valid = False
    max_possible_usage = sum(max(u) for u in node_usages if len(u) > 0)
    if max_possible_usage <= usage_limit:
        always_valid = True
    else:
        tracker_max = SegmentTree(num_times)
        for i in range(num_nodes):
            l, r = node_intervals[i] if node_intervals[i] is not None else (0, 0)
            if l < r and len(node_usages[i]) > 0:
                tracker_max.add(l, r, max(node_usages[i]))
        if tracker_max.get_max(0, num_times) <= usage_limit:
            always_valid = True

    msg_to_v = [[0.0] * edges_info[i][4] for i in range(num_edges)]
    msg_to_u = [[0.0] * edges_info[i][3] for i in range(num_edges)]

    total_bp_ops = sum(info[3] * info[4] for info in edges_info)
    if total_bp_ops == 0:
        num_bp_iters = 0
    else:
        num_bp_iters = min(5, max(0, 5_000_000 // total_bp_ops))

    if num_bp_iters == 0:
        for edge_idx in range(num_edges):
            u, v, flat_costs, num_u_strats, num_v_strats = edges_info[edge_idx]
            for s_v in range(num_v_strats):
                if num_u_strats > 0:
                    msg_to_v[edge_idx][s_v] = min(flat_costs[s_u * num_v_strats + s_v] for s_u in range(num_u_strats))
            for s_u in range(num_u_strats):
                if num_v_strats > 0:
                    idx_base = s_u * num_v_strats
                    msg_to_u[edge_idx][s_u] = min(flat_costs[idx_base : idx_base + num_v_strats])
    else:
        for _ in range(num_bp_iters):
            for i in range(num_nodes):
                num_strats = len(node_costs[i])
                if num_strats == 0: continue

                T_i = list(node_costs[i])
                for neighbor, edge_idx, is_pred in adj[i]:
                    if is_pred:
                        in_msg = msg_to_u[edge_idx]
                    else:
                        in_msg = msg_to_v[edge_idx]
                    if len(in_msg) == num_strats:
                        for s in range(num_strats):
                            T_i[s] += in_msg[s]

                for neighbor, edge_idx, is_pred in adj[i]:
                    if is_pred:
                        in_msg = msg_to_u[edge_idx]
                        num_v_strats = edges_info[edge_idx][4]
                        if num_v_strats == 0: continue
                        out_msg = [float('inf')] * num_v_strats
                        flat_costs = edges_info[edge_idx][2]

                        for s_u in range(num_strats):
                            val_u = T_i[s_u] - in_msg[s_u]
                            idx_base = s_u * num_v_strats
                            for s_v in range(num_v_strats):
                                val = val_u + flat_costs[idx_base + s_v]
                                if val < out_msg[s_v]:
                                    out_msg[s_v] = val

                        min_val = min(out_msg)
                        msg_to_v[edge_idx] = [x - min_val for x in out_msg]
                    else:
                        in_msg = msg_to_v[edge_idx]
                        num_u_strats = edges_info[edge_idx][3]
                        if num_u_strats == 0: continue
                        out_msg = [float('inf')] * num_u_strats
                        flat_costs = edges_info[edge_idx][2]
                        num_v_strats = num_strats

                        for s_u in range(num_u_strats):
                            idx_base = s_u * num_v_strats
                            for s_v in range(num_v_strats):
                                val = T_i[s_v] - in_msg[s_v] + flat_costs[idx_base + s_v]
                                if val < out_msg[s_u]:
                                    out_msg[s_u] = val

                        min_val = min(out_msg)
                        msg_to_u[edge_idx] = [x - min_val for x in out_msg]

    confidences = []
    for i in range(num_nodes):
        num_strats = len(node_costs[i])
        T_i = list(node_costs[i])
        for neighbor, edge_idx, is_pred in adj[i]:
            if is_pred:
                in_msg = msg_to_u[edge_idx]
            else:
                in_msg = msg_to_v[edge_idx]
            if len(in_msg) == num_strats:
                for s in range(num_strats):
                    T_i[s] += in_msg[s]

        if len(T_i) == 0:
            confidences.append(0)
        elif len(T_i) == 1:
            confidences.append(float('inf'))
        else:
            sorted_b = sorted(T_i)
            confidences.append(sorted_b[1] - sorted_b[0])

    def compute_total_cost(st):
        total = 0
        for i in range(num_nodes):
            if len(node_costs[i]) > 0:
                total += node_costs[i][st[i]]
        for edge_idx in range(num_edges):
            u, v, flat_costs, num_u_strats, num_v_strats = edges_info[edge_idx]
            if num_u_strats > 0 and num_v_strats > 0:
                total += flat_costs[st[u] * num_v_strats + st[v]]
        return total

    def generate_state(order):
        tracker_init = SegmentTree(num_times) if not always_valid else None
        state_init = [-1] * num_nodes
        assigned = [False] * num_nodes
        valid = True

        for i in order:
            num_strats = len(node_costs[i])
            if num_strats == 0:
                assigned[i] = True
                continue

            l, r = node_intervals[i] if node_intervals[i] is not None else (0, 0)
            if always_valid:
                current_max = 0
            else:
                if l < r:
                    current_max = tracker_init.get_max(l, r)
                else:
                    current_max = 0

            best_s = -1
            best_score = float('inf')
            min_u_s = -1
            min_u = float('inf')

            for s in range(num_strats):
                u = node_usages[i][s]
                if u < min_u:
                    min_u = u
                    min_u_s = s

