                    score = node_costs[i][s]
                    for neighbor, edge_idx, is_pred in adj[i]:
                        if assigned[neighbor]:
                            s_j = state_init[neighbor]
                            flat_costs = edges_info[edge_idx][2]
                            if is_pred:
                                num_v_strats = edges_info[edge_idx][4]
                                if num_v_strats > 0:
                                    score += flat_costs[s * num_v_strats + s_j]
                            else:
                                num_v_strats = num_strats
                                num_u_strats = edges_info[edge_idx][3]
                                if num_u_strats > 0:
                                    score += flat_costs[s_j * num_v_strats + s]
                        else:
                            if is_pred:
                                if len(msg_to_u[edge_idx]) > s:
                                    score += msg_to_u[edge_idx][s]
                            else:
                                if len(msg_to_v[edge_idx]) > s:
                                    score += msg_to_v[edge_idx][s]

                    if score < best_score:
                        best_score = score
                        best_s = s

            if best_s == -1:
                best_s = min_u_s
                valid = False

            state_init[i] = best_s
            assigned[i] = True
            if not always_valid and l < r:
                tracker_init.add(l, r, node_usages[i][best_s])

