            flat_costs = edges_info[edge_idx][2]
            if is_pred:
                num_v_strats = edges_info[edge_idx][4]
                if num_v_strats > 0:
                    base_edge_cost = flat_costs[old_s * num_v_strats + neighbor_s]
                    for s in range(num_strats):
                        if s != old_s:
                            delta_costs[s] += flat_costs[s * num_v_strats + neighbor_s] - base_edge_cost
            else:
                num_v_strats = num_strats
                num_u_strats = edges_info[edge_idx][3]
                if num_u_strats > 0:
