def solve(input_file: str, solution_file: str):
    import json
    import time
    import heapq
    import random
    from collections import deque
    import os
    import tempfile

    start_time = time.time()
    time_limit = 9.5
    end_time = start_time + time_limit

    with open(input_file, 'r') as f:
        data = json.load(f)

    nodes_list = data.get('nodes', [])
    edges = data.get('edges', [])

    n = len(nodes_list)
    if n == 0:
        with open(solution_file, 'w') as f:
            pass
        return

    node_names = [node[0] for node in nodes_list]
    node_to_id = {name: i for i, name in enumerate(node_names)}
    id_to_node = {i: name for name, i in node_to_id.items()}

    in_degree = [0] * n
    out_degree = [0] * n
    succs = [[] for _ in range(n)]
    preds = [[] for _ in range(n)]

    for u_name, v_name, _ in edges:
        if u_name in node_to_id and v_name in node_to_id:
            u = node_to_id[u_name]
            v = node_to_id[v_name]
            succs[u].append(v)
            preds[v].append(u)
            in_degree[v] += 1
            out_degree[u] += 1

    all_res_names = set()
    if 'resource' in data:
        all_res_names.update(data['resource'].keys())
    if 'delay' in data:
        all_res_names.update(data['delay'].keys())
    for _, r_name in nodes_list:
        all_res_names.add(r_name)

    res_name_to_id = {name: i for i, name in enumerate(all_res_names)}
    num_res = len(res_name_to_id)
    res_limit = [1000000] * num_res
    res_delay = [1] * num_res

    if 'resource' in data:
        for r_name, limit in data['resource'].items():
            res_limit[res_name_to_id[r_name]] = limit
    if 'delay' in data:
        for r_name, d in data['delay'].items():
            res_delay[res_name_to_id[r_name]] = d

    node_res = [0] * n
    node_delay = [0] * n
    for name, r_name in nodes_list:
        u = node_to_id[name]
        r = res_name_to_id[r_name]
        node_res[u] = r
        node_delay[u] = res_delay[r]

    topo = []
    q = deque([i for i in range(n) if in_degree[i] == 0])
    in_d = in_degree.copy()
    while q:
        u = q.popleft()
        topo.append(u)
        for v in succs[u]:
            in_d[v] -= 1
            if in_d[v] == 0:
                q.append(v)

    cp = [0] * n
    for u in reversed(topo):
        max_succ = 0
        for v in succs[u]:
            if cp[v] > max_succ:
                max_succ = cp[v]
        cp[u] = node_delay[u] + max_succ

    asap = [0] * n
    for u in topo:
