                asap[v] = asap[u] + node_delay[u]

    max_asap = max((asap[i] + node_delay[i] for i in range(n)), default=0)

    alap = [max_asap] * n
    for u in reversed(topo):
        min_succ = max_asap
        for v in succs[u]:
