        alap[u] = min_succ - node_delay[u]

    mobility = [alap[i] - asap[i] for i in range(n)]

    demand = [0] * num_res
    for i in range(n):
        demand[node_res[i]] += node_delay[i]

    scarcity = [0] * num_res
    for r in range(num_res):
        if res_limit[r] > 0 and res_limit[r] != 1000000:
