    base_11 = [-d for d in node_delay]
    base_12 = [-(alap[i] + node_delay[i]) for i in range(n)]
    base_13 = [-(asap[i] + node_delay[i]) for i in range(n)]

    bases = [base_0, base_1, base_2, base_3, base_4, base_5, base_6, base_7, base_8, base_9, base_10, base_11, base_12, base_13]
    max_cp = max(cp) if n > 0 else 1
    if max_cp == 0:
        max_cp = 1

    def generate_schedule(priority, n, in_degree, succs, preds, node_res, node_delay, res_limit, num_res):
        in_deg = in_degree.copy()
        ready = [[] for _ in range(num_res)]
        for i in range(n):
            if in_deg[i] == 0:
                heapq.heappush(ready[node_res[i]], (-priority[i], i))

        running = []
        res_free = list(res_limit)

        t = 0
        scheduled_count = 0
        makespan = 0
        schedule = [0] * n

        while scheduled_count < n:
            while running and running[0][0] <= t:
                finish_time, u = heapq.heappop(running)
                res_free[node_res[u]] += 1
                for v in succs[u]:
                    in_deg[v] -= 1
                    if in_deg[v] == 0:
                        heapq.heappush(ready[node_res[v]], (-priority[v], v))

            for r in range(num_res):
                if res_free[r] > 0 and ready[r]:
                    while res_free[r] > 0 and ready[r]:
                        p_neg, u = heapq.heappop(ready[r])
                        schedule[u] = t
                        res_free[r] -= 1
                        finish = t + node_delay[u]
                        if finish > makespan:
                            makespan = finish
                        heapq.heappush(running, (finish, u))
                        scheduled_count += 1

            if scheduled_count < n:
                if running:
                    t = running[0][0]
                else:
                    return None, float('inf')

        return schedule, makespan

    def generate_schedule_backward(priority, n, out_degree, succs, preds, node_res, node_delay, res_limit, num_res):
        out_deg = out_degree.copy()
        ready = [[] for _ in range(num_res)]
        for i in range(n):
            if out_deg[i] == 0:
                heapq.heappush(ready[node_res[i]], (-priority[i], i))

        running = []
        res_free = list(res_limit)

        t = 0
        scheduled_count = 0
        makespan = 0
        schedule = [0] * n

        while scheduled_count < n:
            while running and running[0][0] <= t:
                finish_time, u = heapq.heappop(running)
                res_free[node_res[u]] += 1
                for v in preds[u]:
                    out_deg[v] -= 1
                    if out_deg[v] == 0:
                        heapq.heappush(ready[node_res[v]], (-priority[v], v))

            for r in range(num_res):
                if res_free[r] > 0 and ready[r]:
                    while res_free[r] > 0 and ready[r]:
                        p_neg, u = heapq.heappop(ready[r])
                        schedule[u] = t
                        res_free[r] -= 1
                        finish = t + node_delay[u]
                        if finish > makespan:
                            makespan = finish
                        heapq.heappush(running, (finish, u))
                        scheduled_count += 1

            if scheduled_count < n:
                if running:
                    t = running[0][0]
                else:
                    return None, float('inf')

        forward_schedule = [makespan - schedule[i] - node_delay[i] for i in range(n)]
        return forward_schedule, makespan

    def FBI(initial_priority, max_steps, n, in_degree, out_degree, succs, preds, node_res, node_delay, res_limit, num_res):
        best_ms = float('inf')
        best_s = None

        p_f = initial_priority
        for step in range(max_steps):
            s_f, ms_f = generate_schedule(p_f, n, in_degree, succs, preds, node_res, node_delay, res_limit, num_res)
            if s_f is None:
                break
            if ms_f < best_ms:
                best_ms = ms_f
                best_s = s_f

            p_b = [s_f[i] + node_delay[i] for i in range(n)]
            s_b, ms_b = generate_schedule_backward(p_b, n, out_degree, succs, preds, node_res, node_delay, res_limit, num_res)
            if s_b is None:
                break
            if ms_b < best_ms:
                best_ms = ms_b
                best_s = s_b

            p_f = [-s_b[i] for i in range(n)]

        return best_s, best_ms

    def run_search(end_time, bases, n, in_degree, out_degree, succs, preds, node_res, node_delay, res_limit, num_res, max_cp, worker_id):
        best_ms = float('inf')
        best_s = None

        elite_pool = []

        max_base_steps = 6 if worker_id == 0 else 2

        for base in bases:
            s, ms = FBI(base, max_base_steps, n, in_degree, out_degree, succs, preds, node_res, node_delay, res_limit, num_res)
            if ms < best_ms:
                best_ms = ms
                best_s = s
            if s is not None:
                if not elite_pool or ms <= elite_pool[-1][0] or len(elite_pool) < 10:
                    is_duplicate = False
                    for e in elite_pool:
                        if e[0] == ms and e[1] == s:
                            is_duplicate = True
                            break
                    if not is_duplicate:
                        elite_pool.append((ms, s))
                        elite_pool.sort(key=lambda x: x[0])
                        elite_pool = elite_pool[:10]

        iters = 0
        while True:
            iters += 1
            if iters % 50 == 0 and time.time() >= end_time:
                break

            explore_prob = 0.2 + 0.1 * worker_id

            if random.random() > explore_prob and elite_pool:
                idx = random.randint(0, min(len(elite_pool)-1, 3))
                base_p = [-x for x in elite_pool[idx][1]]
            else:
                idx = random.randint(0, len(bases)-1)
                base_p = bases[idx]

            noise_scale = 0.05 + 0.1 * worker_id
            noise_level = random.uniform(0, noise_scale) * max_cp
            p = [base_p[i] + random.uniform(-noise_level, noise_level) for i in range(n)]

            s, ms = FBI(p, 2, n, in_degree, out_degree, succs, preds, node_res, node_delay, res_limit, num_res)
            if ms < best_ms:
                best_ms = ms
                best_s = s

            if s is not None:
