                    is_duplicate = False
                    for e in elite_pool:
                        if e[0] == ms and e[1] == s:
                            is_duplicate = True
                            break
                    if not is_duplicate:
                        elite_pool.append((ms, s))
                        elite_pool.sort(key=lambda x: x[0])
                        elite_pool = elite_pool[:10]

        return best_s, best_ms

    use_fork = False
    if hasattr(os, 'fork'):
        try:
            pid = os.fork()
            if pid == 0:
                os._exit(0)
            else:
                os.waitpid(pid, 0)
                use_fork = True
        except Exception:
            use_fork = False

    if use_fork:
        num_workers = 8
        with tempfile.TemporaryDirectory() as tmpdir:
            pids = []
            for i in range(num_workers):
                try:
                    pid = os.fork()
                    if pid == 0:
                        random.seed((int(time.time() * 1000) + i * 12345) % (2**32 - 1))

                        best_s, best_ms = run_search(end_time, bases, n, in_degree, out_degree, succs, preds, node_res, node_delay, res_limit, num_res, max_cp, i)

                        with open(os.path.join(tmpdir, f'{i}.json'), 'w') as f:
                            json.dump({'ms': best_ms, 's': best_s}, f)
                        os._exit(0)
                    else:
                        pids.append(pid)
                except Exception:
                    pass

            for pid in pids:
