import sys
from collections import deque

sys.setrecursionlimit(5000)

def solve(input_file: str, solution_file: str):
    individuals = []
    with open(input_file, 'r') as f:
        for line in f:
            parts = line.strip().split()
            if not parts: continue
            individuals.append({
                'id': int(parts[1]),
                'father': int(parts[2]),
                'mother': int(parts[3]),
                'a1': int(parts[5]),
                'a2': int(parts[6])
            })

    max_allele = 0
    for ind in individuals:
        if ind['a1'] > max_allele: max_allele = ind['a1']
        if ind['a2'] > max_allele: max_allele = ind['a2']
    n = max_allele if max_allele > 0 else 1

    genotypes = []
    for a in range(1, n + 1):
        for b in range(a, n + 1):
            genotypes.append((a, b))
    G = len(genotypes)

    allele_mask = [0] * G
    for g_idx, (a, b) in enumerate(genotypes):
        allele_mask[g_idx] = (1 << a) | (1 << b)

    num_bytes = (G + 7) // 8
    lookups = [[0] * 256 for _ in range(num_bytes)]
    for byte_idx in range(num_bytes):
        for byte_val in range(256):
            A = 0
            for bit in range(8):
                if (byte_val & (1 << bit)):
                    g_idx = byte_idx * 8 + bit
                    if g_idx < G:
                        A |= allele_mask[g_idx]
            lookups[byte_idx][byte_val] = A

    genotypes_with_allele = [0] * (n + 1)
    for g_idx, (a, b) in enumerate(genotypes):
        genotypes_with_allele[a] |= (1 << g_idx)
        genotypes_with_allele[b] |= (1 << g_idx)

    g_idx_matrix = [[0] * (n + 1) for _ in range(n + 1)]
    for g_idx, (a, b) in enumerate(genotypes):
        g_idx_matrix[a][b] = g_idx
        g_idx_matrix[b][a] = g_idx

    id_to_var = {}
    var_to_id = []
    for ind in individuals:
        if ind['id'] not in id_to_var:
            id_to_var[ind['id']] = len(var_to_id)
            var_to_id.append(ind['id'])
        if ind['father'] != 0 and ind['father'] not in id_to_var:
            id_to_var[ind['father']] = len(var_to_id)
            var_to_id.append(ind['father'])
        if ind['mother'] != 0 and ind['mother'] not in id_to_var:
            id_to_var[ind['mother']] = len(var_to_id)
            var_to_id.append(ind['mother'])
    N = len(var_to_id)

    D0 = [0] * N
    D1 = [0] * N
    for ind in individuals:
        var = id_to_var[ind['id']]
        obs_a, obs_b = ind['a1'], ind['a2']
        for g_idx, (ga, gb) in enumerate(genotypes):
            cost = 1
            if obs_a == 0 and obs_b == 0:
                cost = 0
            elif obs_a != 0 and obs_b != 0:
                if (ga == obs_a and gb == obs_b) or (ga == obs_b and gb == obs_a):
                    cost = 0
            else:
                obs = obs_a if obs_a != 0 else obs_b
                if ga == obs or gb == obs:
                    cost = 0
            if cost == 0:
                D0[var] |= (1 << g_idx)
            else:
                D1[var] |= (1 << g_idx)

    for var in range(N):
        if D0[var] == 0 and D1[var] == 0:
            D0[var] = (1 << G) - 1

    families = set()
    half_families = set()
    for ind in individuals:
        c = id_to_var[ind['id']]
        f_id = ind['father']
        m_id = ind['mother']
