            half_families.add((f, c))
        elif m_id != 0:
            m = id_to_var[m_id]
            half_families.add((m, c))

    families_with = [[] for _ in range(N)]
    half_families_with = [[] for _ in range(N)]
    for f, m, c in families:
        fam = (f, m, c)
        families_with[f].append(fam)
        families_with[m].append(fam)
        families_with[c].append(fam)
    for p, c in half_families:
        hfam = (p, c)
        half_families_with[p].append(hfam)
        half_families_with[c].append(hfam)

    adj = [[] for _ in range(N)]
    for f, m, c in families:
        adj[f].append(m); adj[m].append(f)
        adj[f].append(c); adj[c].append(f)
        adj[m].append(c); adj[c].append(m)
    for p, c in half_families:
        adj[p].append(c); adj[c].append(p)

    visited = [False] * N
    components = []
    for i in range(N):
