                        ap_mask &= ap_mask - 1
                    new_Dc = D[c] & valid_Dc
                    if new_Dc != D[c]:
                        if new_Dc == 0: return False
                        if trail is not None: trail.append((c, D[c]))
                        D[c] = new_Dc
                        if not in_queue[c]:
                            queue.append(c)
                            in_queue[c] = True
                if v == c:
                    Ac = 0
                    mask = D[c]
                    byte_idx = 0
                    while mask:
                        Ac |= lookups[byte_idx][mask & 0xFF]
                        mask >>= 8
                        byte_idx += 1

                    valid_Dp = 0
                    ac_mask = Ac
                    while ac_mask:
                        lsb = ac_mask & -ac_mask
                        x = lsb.bit_length() - 1
                        valid_Dp |= genotypes_with_allele[x]
                        ac_mask &= ac_mask - 1
                    new_Dp = D[p] & valid_Dp
                    if new_Dp != D[p]:
                        if new_Dp == 0: return False
                        if trail is not None: trail.append((p, D[p]))
                        D[p] = new_Dp
                        if not in_queue[p]:
                            queue.append(p)
                            in_queue[p] = True
        return True

    def solve_component(comp_vars):
        max_cost = len(comp_vars)

        degree = [0] * N
        for f, m, c in families:
            degree[f] += 1; degree[m] += 1; degree[c] += 1
        for p, c in half_families:
            degree[p] += 1; degree[c] += 1

        search_vars = sorted(comp_vars, key=lambda x: -degree[x])

        for budget in range(max_cost + 1):
            D = [0] * N
            for i in comp_vars:
                D[i] = D0[i] | D1[i]

            queue = deque(comp_vars)
            in_queue = [False] * N
            for i in comp_vars: in_queue[i] = True

            if not propagate(queue, in_queue, D, None):
                continue

            found = False
            best_assignment = {}

            def dfs(var_idx, current_cost):
                nonlocal found, best_assignment
                if found: return

                lb = current_cost
                for i in range(var_idx, len(search_vars)):
                    v = search_vars[i]
                    if not (D[v] & D0[v]):
                        lb += 1
                if lb > budget:
                    return

                if var_idx == len(search_vars):
                    found = True
                    for v in comp_vars:
                        mask = D[v]
                        lsb = mask & -mask
                        best_assignment[v] = lsb.bit_length() - 1
                    return

                v = search_vars[var_idx]

                val_mask = D[v]
                vals0 = val_mask & D0[v]
                vals1 = val_mask & D1[v]

                for val_set, cost_inc in [(vals0, 0), (vals1, 1)]:
                    if not val_set: continue
                    if current_cost + cost_inc > budget: continue

                    mask = val_set
                    while mask:
                        if found: return
                        lsb = mask & -mask
                        val = lsb.bit_length() - 1
                        mask &= mask - 1

                        trail = [(v, D[v])]
                        D[v] = (1 << val)

                        q = deque([v])
                        in_q = [False] * N
                        in_q[v] = True

                        if propagate(q, in_q, D, trail):
                            dfs(var_idx + 1, current_cost + cost_inc)

                        for var, old_D in reversed(trail):
                            D[var] = old_D

            dfs(0, 0)
            if found:
                return best_assignment

        return {v: (D0[v] | D1[v]).bit_length() - 1 for v in comp_vars}

    final_assignment = {}
    for comp in components:
        comp_assignment = solve_component(comp)
        final_assignment.update(comp_assignment)

    output_indices = []
    for ind in individuals:
        var = id_to_var[ind['id']]
        assigned_idx = final_assignment[var]
        output_indices.append(assigned_idx)

    with open(solution_file, 'w') as f:
        f.write(" ".join(map(str, output_indices)) + "\n")

