def solve(input_file: str, solution_file: str):
    import math

    residues = []
    current_res_id = None
    current_res_atoms = []

    with open(input_file, 'r') as f:
        for line in f:
            if line.startswith("ENDMDL"):
                break
            if line.startswith("ATOM  "):
                chain_id = line[21]
                res_seq = line[22:27]
                full_res_id = chain_id + res_seq
                atom_name = line[12:16].strip()

                try:
                    x = float(line[30:38])
                    y = float(line[38:46])
                    z = float(line[46:54])
                except ValueError:
                    continue

                if full_res_id != current_res_id:
                    if current_res_id is not None:
                        residues.append((current_res_id, current_res_atoms))
                    current_res_id = full_res_id
                    current_res_atoms = []

                current_res_atoms.append((atom_name, (x, y, z)))

        if current_res_id is not None:
            residues.append((current_res_id, current_res_atoms))

    n = len(residues)
    if n == 0:
        with open(solution_file, 'w') as f:
            f.write("")
        return

    centers = []
    for res_id, atoms in residues:
        cb_atoms = [coords for name, coords in atoms if name == 'CB']
        if cb_atoms:
            centers.append(cb_atoms[0])
        else:
            ca_atoms = [coords for name, coords in atoms if name == 'CA']
            if ca_atoms:
                centers.append(ca_atoms[0])
            else:
                centers.append(atoms[0][1])

    contact_numbers = []
    for i in range(n):
        count = 0
        xi, yi, zi = centers[i]
        for j in range(n):
            if i == j:
                continue
            xj, yj, zj = centers[j]
            dist_sq = (xi-xj)**2 + (yi-yj)**2 + (zi-zj)**2
            if dist_sq < 100.0:
                count += 1
        contact_numbers.append(count)

    if not contact_numbers:
        with open(solution_file, 'w') as f:
            f.write("")
        return

    sorted_contacts = sorted(contact_numbers)
    median_contact = sorted_contacts[len(sorted_contacts) // 2]

    sequence = []
    for c in contact_numbers:
        if c >= median_contact:
            sequence.append('H')
        else:
            sequence.append('P')

    optimal_sequence = "".join(sequence)

    with open(solution_file, 'w') as f:
        f.write(optimal_sequence + "\n")

