import itertools

def solve(input_file: str, solution_file: str):
    """
    Solve the optimization problem.

    Please do NOT change the function name and arguments.
    Inputs should be read from input_file and outputs should be written to solution_file.
    Input and output formats have been specified in the problem statement.
    """
    # 1. Parse BLIF
    with open(input_file, 'r') as f:
        lines = f.readlines()

    processed_lines = []
    current_line = ""
    for line in lines:
        if '#' in line:
            line = line.split('#')[0]
        line = line.strip()
        if not line:
            continue
        if line.endswith('\\'):
            current_line += line[:-1] + " "
        else:
            current_line += line
            processed_lines.append(current_line)
            current_line = ""

    model_name = "mapped"
    inputs = []
    outputs = []
    parsed_nodes = {}

    current_node = None
    for line in processed_lines:
        tokens = line.split()
        if not tokens: continue
        if tokens[0] == '.model':
            model_name = tokens[1]
        elif tokens[0] == '.inputs':
            inputs.extend(tokens[1:])
        elif tokens[0] == '.outputs':
            outputs.extend(tokens[1:])
        elif tokens[0] == '.names':
            out_node = tokens[-1]
            in_nodes = tokens[1:-1]
            parsed_nodes[out_node] = {'inputs': in_nodes, 'cubes': [], 'out_val': 0}
            current_node = out_node
        elif tokens[0] == '.end':
            break
        else:
            if len(tokens) == 1:
                parsed_nodes[current_node]['out_val'] = int(tokens[0])
            else:
                cube, out_val = tokens[0], tokens[1]
                parsed_nodes[current_node]['cubes'].append(cube)
                parsed_nodes[current_node]['out_val'] = int(out_val)

    inputs = list(dict.fromkeys(inputs))
    outputs = list(dict.fromkeys(outputs))

    # 2. Topo sort with cycle detection
    topo_order = []
    visited = set()
    visiting = set()
    for name in parsed_nodes:
        if name in visited:
            continue
        stack = [name]
        while stack:
            curr = stack[-1]
            if curr in visited:
                stack.pop()
                continue

            if curr not in visiting:
                visiting.add(curr)
                pushed = False
                if curr in parsed_nodes:
                    for inp in parsed_nodes[curr]['inputs']:
                        if inp not in visited and inp not in visiting:
                            stack.append(inp)
                            pushed = True
                if pushed:
                    continue

            visited.add(curr)
            visiting.remove(curr)
            topo_order.append(curr)
            stack.pop()

    # 3. Build AIG
    aig_type = [1] # 0: PI, 1: CONST, 2: AND
    aig_in1 = [0]
    aig_in2 = [0]
    aig_inv1 = [False]
    aig_inv2 = [False]

    blif_to_aig = {}
    strash = {}

    for pi in inputs:
        aig_id = len(aig_type)
        aig_type.append(0)
        aig_in1.append(0)
        aig_in2.append(0)
        aig_inv1.append(False)
        aig_inv2.append(False)
        blif_to_aig[pi] = (aig_id, False)

    def add_and(id1, inv1, id2, inv2):
        if id1 == 0:
            if not inv1: return 0, False
            else: return id2, inv2
        if id2 == 0:
            if not inv2: return 0, False
            else: return id1, inv1
        if id1 == id2:
            if inv1 == inv2: return id1, inv1
            else: return 0, False

        if id1 > id2:
            id1, id2 = id2, id1
            inv1, inv2 = inv2, inv1

        key = (id1, inv1, id2, inv2)
        if key in strash:
            return strash[key], False

        new_id = len(aig_type)
        aig_type.append(2)
        aig_in1.append(id1)
        aig_in2.append(id2)
        aig_inv1.append(inv1)
        aig_inv2.append(inv2)
        strash[key] = new_id
        return new_id, False

    def build_and_tree(lits_list):
        if not lits_list:
            return (0, True)
        if len(lits_list) == 1:
            return lits_list[0]
        mid = len(lits_list) // 2
        left = build_and_tree(lits_list[:mid])
        right = build_and_tree(lits_list[mid:])
        return add_and(left[0], left[1], right[0], right[1])

    def build_or_tree(lits_list):
        if not lits_list:
            return (0, False)
        if len(lits_list) == 1:
            return lits_list[0]
        mid = len(lits_list) // 2
        left = build_or_tree(lits_list[:mid])
        right = build_or_tree(lits_list[mid:])
        and_id, and_inv = add_and(left[0], not left[1], right[0], not right[1])
        return and_id, not and_inv

    for name in topo_order:
        if name not in parsed_nodes:
            continue
        data = parsed_nodes[name]
        inps = data['inputs']
        cubes = data['cubes']
        out_val = data['out_val']

        if not cubes:
            if out_val == 1:
                blif_to_aig[name] = (0, True)
            else:
                blif_to_aig[name] = (0, False)
            continue

        cube_aigs = []
        for cube in cubes:
            lits = []
            for i, char in enumerate(cube):
                if char == '-': continue
                inp_name = inps[i]
                if inp_name not in blif_to_aig:
                    aig_id = len(aig_type)
                    aig_type.append(0)
                    aig_in1.append(0)
                    aig_in2.append(0)
                    aig_inv1.append(False)
                    aig_inv2.append(False)
                    blif_to_aig[inp_name] = (aig_id, False)

                if char == '1':
                    lits.append((blif_to_aig[inp_name][0], blif_to_aig[inp_name][1]))
                elif char == '0':
                    lits.append((blif_to_aig[inp_name][0], not blif_to_aig[inp_name][1]))

            cube_aigs.append(build_and_tree(lits))

        res_id, res_inv = build_or_tree(cube_aigs)

        if out_val == 0:
            res_inv = not res_inv

        blif_to_aig[name] = (res_id, res_inv)

    pi_names = set(inputs)
    po_aig_ids = []
    valid_outputs = []
    for po in outputs:
        if po in pi_names:
            continue
        if po not in blif_to_aig:
            po_id, po_inv = 0, False
        else:
            po_id, po_inv = blif_to_aig[po]

        new_id = len(aig_type)
        aig_type.append(2)
        aig_in1.append(po_id)
        aig_in2.append(0)
        aig_inv1.append(po_inv)
        aig_inv2.append(True)
        po_aig_ids.append(new_id)
        valid_outputs.append(po)

    aig_name = [None] * len(aig_type)
    for pi in inputs:
        if pi in blif_to_aig:
            aig_name[blif_to_aig[pi][0]] = pi

    for po, new_id in zip(valid_outputs, po_aig_ids):
        aig_name[new_id] = po

    # 4. Cut Enumeration
    K = 6
    N = len(aig_type)
    if N < 2000:
        max_cuts = 16
    elif N < 5000:
        max_cuts = 10
    elif N < 10000:
        max_cuts = 6
    elif N < 20000:
        max_cuts = 4
    else:
        max_cuts = 2

    cuts = [[] for _ in range(len(aig_type))]

    for i in range(len(aig_type)):
        if aig_type[i] == 0:
            cuts[i] = [(i,)]
        elif aig_type[i] == 1:
            cuts[i] = [()]
        else:
            in1 = aig_in1[i]
            in2 = aig_in2[i]

            res = {(i,)}

            cuts1 = cuts[in1]
            cuts2 = cuts[in2]

            for c1 in cuts1:
                s1 = set(c1)
                for c2 in cuts2:
                    u = s1.union(c2)
                    if len(u) <= K:
                        res.add(tuple(sorted(u)))

            sorted_cuts = sorted(list(res), key=len)
            filtered = []
            filtered_sets = []
            for c in sorted_cuts:
                c_set = set(c)
                is_dom = False
                for fc_set in filtered_sets:
                    if fc_set.issubset(c_set):
                        is_dom = True
                        break
                if not is_dom:
                    filtered.append(c)
                    filtered_sets.append(c_set)
                    if len(filtered) == max_cuts:
                        break
            cuts[i] = filtered

    # 5. Area Flow DP
    fanout_est = [0] * len(aig_type)
    for i in range(len(aig_type)):
        if aig_type[i] == 2:
            fanout_est[aig_in1[i]] += 1
            fanout_est[aig_in2[i]] += 1
    for po_id in po_aig_ids:
        fanout_est[po_id] += 1

    for i in range(len(fanout_est)):
        if fanout_est[i] == 0:
            fanout_est[i] = 1

    best_cut = [None] * len(aig_type)
    area_flow = [0.0] * len(aig_type)

    iterations = 3 if N < 10000 else (2 if N < 30000 else 1)
    for it in range(iterations):
        for i in range(len(aig_type)):
            if aig_type[i] == 0:
                best_cut[i] = (i,)
                area_flow[i] = 0.0
            elif aig_type[i] == 1:
                best_cut[i] = ()
                area_flow[i] = 0.0
            else:
                best_af = float('inf')
                best_c = None

                for cut in cuts[i]:
                    if len(cut) == 1 and cut[0] == i:
                        continue
                    af = 1.0
                    for inp in cut:
                        af += area_flow[inp] / fanout_est[inp]

                    if af < best_af - 1e-6 or (abs(af - best_af) <= 1e-6 and best_c is not None and len(cut) < len(best_c)):
                        best_af = af
                        best_c = cut

                if best_c is None:
                    fallback = set()
                    if aig_in1[i] != 0: fallback.add(aig_in1[i])
                    if aig_in2[i] != 0: fallback.add(aig_in2[i])
                    best_c = tuple(sorted(fallback))
                    best_af = 1.0
                    for inp in best_c:
                        best_af += area_flow[inp] / fanout_est[inp]

                best_cut[i] = best_c
                area_flow[i] = best_af

        if it < iterations - 1:
            mapped_fanout = [0] * len(aig_type)
            for po_id in po_aig_ids:
                mapped_fanout[po_id] += 1

            for i in reversed(range(len(aig_type))):
                if mapped_fanout[i] > 0 and aig_type[i] == 2:
                    for inp in best_cut[i]:
                        mapped_fanout[inp] += 1

            for i in range(len(aig_type)):
                new_fo = mapped_fanout[i]
                if new_fo == 0: new_fo = 1
                fanout_est[i] = 0.5 * fanout_est[i] + 0.5 * new_fo

    # 6. Generate Mapped Network
    required_luts = set()
    queue = list(po_aig_ids)
    visited_luts = set(po_aig_ids)

    idx = 0
    while idx < len(queue):
        curr = queue[idx]
        idx += 1

        if aig_type[curr] == 0:
            continue
        if aig_type[curr] == 1:
            required_luts.add(curr)
            continue

        required_luts.add(curr)

        for inp in best_cut[curr]:
            if inp not in visited_luts:
                visited_luts.add(inp)
                queue.append(inp)

    # 7. Compute Truth Tables and Write BLIF
    VAR_MASKS = [
        0xAAAAAAAAAAAAAAAA,
        0xCCCCCCCCCCCCCCCC,
        0xF0F0F0F0F0F0F0F0,
        0xFF00FF00FF00FF00,
        0xFFFF0000FFFF0000,
        0xFFFFFFFF00000000
    ]

    PRECOMPUTED_CUBES = {}
    for nv in range(1, 7):
        PRECOMPUTED_CUBES[nv] = []
        for i in range(1 << nv):
            cube = "".join("1" if (i & (1 << v)) else "0" for v in range(nv))
            PRECOMPUTED_CUBES[nv].append(cube)

    global_val = [0] * N
    global_visited = [0] * N
    visit_id = 0

    def compute_tt(node_id, cut_list):
        nonlocal visit_id
        visit_id += 1

        for i, c in enumerate(cut_list):
            global_val[c] = VAR_MASKS[i]
            global_visited[c] = visit_id

        cone = []
        stack = [node_id]
        while stack:
            n = stack[-1]
            if global_visited[n] == visit_id:
                stack.pop()
                continue

            pushed = False
            if aig_type[n] == 2:
                i1 = aig_in1[n]
                i2 = aig_in2[n]
                if global_visited[i1] != visit_id:
                    stack.append(i1)
                    pushed = True
                if global_visited[i2] != visit_id:
                    stack.append(i2)
                    pushed = True

            if pushed:
                continue

            global_visited[n] = visit_id
            cone.append(n)
            stack.pop()

        for n in cone:
            if aig_type[n] == 1:
                global_val[n] = 0
            elif aig_type[n] == 0:
                global_val[n] = 0
            elif aig_type[n] == 2:
                i1 = aig_in1[n]
                i2 = aig_in2[n]
                v1 = global_val[i1]
                if aig_inv1[n]: v1 = ~v1
                v2 = global_val[i2]
                if aig_inv2[n]: v2 = ~v2
                global_val[n] = v1 & v2

        return global_val[node_id] & 0xFFFFFFFFFFFFFFFF

    def generate_blif_cubes(tt, num_vars):
        if num_vars == 0:
            if tt & 1:
                return [], 1
            else:
                return [], 0

        num_bits = 1 << num_vars
        mask = (1 << num_bits) - 1
        tt = tt & mask

        if tt == mask:
            return ["-" * num_vars], 1
        if tt == 0:
            return [], 0

        on_set = []
        off_set = []

        cubes = PRECOMPUTED_CUBES[num_vars]
        for i in range(num_bits):
            if (tt & (1 << i)):
                on_set.append(cubes[i])
            else:
                off_set.append(cubes[i])

        if len(on_set) <= len(off_set):
            return on_set, 1
        else:
            return off_set, 0

    def get_name(id):
        if aig_name[id] is not None:
            return aig_name[id]
        return f"__my_lut_{id}"

    with open(solution_file, 'w') as f:
        f.write(f".model {model_name}\n")

        def write_list(prefix, lst):
            line = prefix
            for item in lst:
                if len(line) + len(item) + 1 > 72:
                    f.write(line + " \\\n")
                    line = " " + item
                else:
                    line += " " + item
            f.write(line + "\n")

        write_list(".inputs", inputs)
        write_list(".outputs", outputs)

        for lut in required_luts:
            cut = best_cut[lut]
            cut_list = list(cut)

            f.write(".names")
            for inp in cut_list:
                f.write(f" {get_name(inp)}")
            f.write(f" {get_name(lut)}\n")

            tt = compute_tt(lut, cut_list)
            cubes, out_val = generate_blif_cubes(tt, len(cut_list))

            if len(cut_list) == 0:
                if out_val == 1:
                    f.write("1\n")
            else:
                for cube in cubes:
                    f.write(f"{cube} {out_val}\n")

        f.write(".end\n")

