import json
import sys
from collections import defaultdict, deque

sys.setrecursionlimit(2000000)

def solve(input_file: str, solution_file: str):
    with open(input_file, 'r') as f:
        data = json.load(f)

    nodes = data['nodes']
    root_eclasses = set(data['root_eclasses'])

    # Build data structures
    eclass_to_nodes = defaultdict(list)
    node_children = {}
    node_cost = {}

    for node_id, node_data in nodes.items():
        eclass_id = node_data['eclass']
        eclass_to_nodes[eclass_id].append(node_id)
        node_cost[node_id] = node_data['cost']

        child_eclasses = []
        for child_ref in node_data['children']:
            if child_ref in nodes:
                child_eclasses.append(nodes[child_ref]['eclass'])
            else:
                child_eclasses.append(child_ref)
        node_children[node_id] = child_eclasses

    # Find reachable e-classes from roots
    reachable = set()
    queue = deque(root_eclasses)
    while queue:
        eclass = queue.popleft()
        if eclass in reachable or eclass not in eclass_to_nodes:
            continue
        reachable.add(eclass)
        for node_id in eclass_to_nodes[eclass]:
            for child_eclass in node_children[node_id]:
                if child_eclass not in reachable and child_eclass in eclass_to_nodes:
                    queue.append(child_eclass)

    # Compute best costs with iterative refinement
    eclass_cost = {ec: float('inf') for ec in reachable}

    # Initialize with leaf nodes
    for eclass in reachable:
        for node_id in eclass_to_nodes[eclass]:
            if not node_children[node_id] or all(c not in reachable for c in node_children[node_id]):
                cost = node_cost[node_id]
                for child in node_children[node_id]:
                    if child in reachable:
                        cost += eclass_cost.get(child, 0)
                if cost < eclass_cost[eclass]:
                    eclass_cost[eclass] = cost

