from collections import defaultdict

def solve(cap_file: str, net_file: str, solution_file: str):
    start_time = time.time()

    with open(cap_file, 'r') as f:
        lines = [l.strip() for l in f.readlines() if l.strip()]

    idx = 0
    nLayers, xSize, ySize = map(int, lines[idx].split())
    idx += 1

    costs = list(map(float, lines[idx].split()))
    UnitLengthWireCost, UnitViaCost = costs[0], costs[1]
    OFWeight = np.array(costs[2:2+nLayers])
    idx += 1

    h_lengths = list(map(int, lines[idx].split()))
    idx += 1
    v_lengths = list(map(int, lines[idx].split()))
    idx += 1

    layer_dirs = []
    cap_h = np.ones((nLayers, xSize, ySize)) * 10
    cap_v = np.ones((nLayers, xSize, ySize)) * 10

    for l in range(nLayers):
        parts = lines[idx].split()
        layer_dir = int(parts[1])
        layer_dirs.append(layer_dir)
        idx += 1

        for y in range(ySize):
            caps = list(map(float, lines[idx].split()))
            for x in range(xSize):
                if layer_dir == 0:
                    cap_h[l][x][y] = caps[x]
                else:
                    cap_v[l][x][y] = caps[x]
            idx += 1

    with open(net_file, 'r') as f:
        content = f.read()

    nets = []
    pattern = re.compile(r'(\S+)\s*\(\s*((?:\s*\[[^\]]*\]\s*)*)\s*\)', re.DOTALL)

    for match in pattern.finditer(content):
        net_name = match.group(1)
        pins_str = match.group(2)
        pins = []

        for pin_match in re.finditer(r'\[([^\]]*)\]', pins_str):
            aps = re.findall(r'\((\d+),\s*(\d+),\s*(\d+)\)', pin_match.group(1))
            access_points = [(int(z), int(x), int(y)) for z, x, y in aps]
            if access_points:
                pins.append(access_points)

        if pins:
            nets.append((net_name, pins))

    def get_route_layers():
        h_layers = [l for l in range(1, nLayers) if layer_dirs[l] == 0]
        v_layers = [l for l in range(1, nLayers) if layer_dirs[l] == 1]
        return h_layers, v_layers

    h_layers, v_layers = get_route_layers()
    default_h = h_layers[0] if h_layers else 2
    default_v = v_layers[0] if v_layers else 1

    def route_between_points(x1, y1, z1, x2, y2, z2):
        edges = []

        target_z = max(z1, z2, default_h)

        cz1, cz2 = z1, z2
        while cz1 < target_z:
            edges.append((x1, y1, cz1, x1, y1, cz1 + 1))
            cz1 += 1
        while cz2 < target_z:
            edges.append((x2, y2, cz2, x2, y2, cz2 + 1))
            cz2 += 1

        cx, cy = x1, y1

        if layer_dirs[target_z] == 0:
            if cx != x2:
                edges.append((min(cx, x2), cy, target_z, max(cx, x2), cy, target_z))
                cx = x2
            if cy != y2:
                via_z = target_z + 1 if target_z + 1 < nLayers else (target_z - 1 if target_z > 1 else target_z)
                if via_z >= 1 and via_z < nLayers and layer_dirs[via_z] == 1:
                    edges.append((cx, cy, target_z, cx, cy, via_z))
                    edges.append((cx, min(cy, y2), via_z, cx, max(cy, y2), via_z))
                    edges.append((cx, y2, via_z, cx, y2, target_z))
                elif v_layers:
                    via_z = v_layers[0]
                    for z in range(target_z, via_z):
                        edges.append((cx, cy, z, cx, cy, z + 1))
                    edges.append((cx, min(cy, y2), via_z, cx, max(cy, y2), via_z))
                    for z in range(via_z, target_z, -1):
                        edges.append((cx, y2, z, cx, y2, z - 1))
        else:
            if cy != y2:
                edges.append((cx, min(cy, y2), target_z, cx, max(cy, y2), target_z))
                cy = y2
            if cx != x2:
                via_z = target_z + 1 if target_z + 1 < nLayers else (target_z - 1 if target_z > 1 else target_z)
                if via_z >= 1 and via_z < nLayers and layer_dirs[via_z] == 0:
                    edges.append((cx, cy, target_z, cx, cy, via_z))
                    edges.append((min(cx, x2), cy, via_z, max(cx, x2), cy, via_z))
                    edges.append((x2, cy, via_z, x2, cy, target_z))
                elif h_layers:
                    via_z = h_layers[0]
                    for z in range(target_z, via_z):
                        edges.append((cx, cy, z, cx, cy, z + 1))
                    edges.append((min(cx, x2), cy, via_z, max(cx, x2), cy, via_z))
                    for z in range(via_z, target_z, -1):
                        edges.append((x2, cy, z, x2, cy, z - 1))

        return edges

    def route_net(pins_aps):
        if not pins_aps:
            return []

        pin_points = []
        for aps in pins_aps:
            best_ap = min(aps, key=lambda ap: (ap[0], ap[1], ap[2]))
            z, x, y = best_ap
            if z == 0:
                pin_points.append((x, y, 1))
            else:
                pin_points.append((x, y, z))

        if len(pin_points) == 1:
            z, x, y = pins_aps[0][0]
            if z == 0:
                return [(x, y, 0, x, y, 1)]
            return []

        all_edges = []
        connected = set()
        connected.add(pin_points[0])

        for i in range(1, len(pin_points)):
            x2, y2, z2 = pin_points[i]

            min_dist = float('inf')
            best_node = None
            for node in connected:
                x1, y1, z1 = node
                dist = abs(x1 - x2) + abs(y1 - y2) + abs(z1 - z2) * 2
                if dist < min_dist:
                    min_dist = dist
                    best_node = node

            if best_node:
                x1, y1, z1 = best_node
                edges = route_between_points(x1, y1, z1, x2, y2, z2)
                all_edges.extend(edges)

                for e in edges:
                    xl, yl, zl, xh, yh, zh = e
                    if xl == xh and yl == yh:
                        for z in range(zl, zh + 1):
                            connected.add((xl, yl, z))
                    elif yl == yh and zl == zh:
                        for x in range(xl, xh + 1):
                            connected.add((x, yl, zl))
                    elif xl == xh and zl == zh:
                        for y in range(yl, yh + 1):
                            connected.add((xl, y, zl))

        for aps in pins_aps:
            for z, x, y in aps:
                if z == 0:
                    all_edges.append((x, y, 0, x, y, 1))

        return all_edges

    net_paths = {}
    for net_name, pins in nets:
        edges = route_net(pins)
        net_paths[net_name] = edges

    with open(solution_file, 'w') as f:
        for net_name, pins in nets:
            f.write(f"{net_name}\n(\n")
            edges = net_paths.get(net_name, [])
            for xl, yl, zl, xh, yh, zh in edges:
                f.write(f"{xl} {yl} {zl} {xh} {yh} {zh}\n")
            f.write(")\n")

