def solve(input_file: str, solution_file: str):
    import json
    from collections import defaultdict, deque

    with open(input_file, 'r') as f:
        data = json.load(f)

    delays = data['delay']
    resources = data['resource']
    nodes = data['nodes']
    edges = data['edges']

    if not nodes:
        with open(solution_file, 'w') as f:
            pass
        return

    node_ids = [n[0] for n in nodes]
    node_types = {n[0]: n[1] for n in nodes}
    node_delays = {n[0]: delays[n[1]] for n in nodes}

    predecessors = defaultdict(list)
    successors = defaultdict(list)

    for src, tgt, _ in edges:
        predecessors[tgt].append(src)
        successors[src].append(tgt)

    # Compute ASAP times
    asap = {}
    in_degree = {n: len(predecessors[n]) for n in node_ids}
    queue = deque([n for n in node_ids if in_degree[n] == 0])

    while queue:
        node = queue.popleft()
        if predecessors[node]:
            asap[node] = max(asap[p] + node_delays[p] for p in predecessors[node])
        else:
            asap[node] = 0
        for succ in successors[node]:
            in_degree[succ] -= 1
            if in_degree[succ] == 0:
                queue.append(succ)

    # Compute critical path length
    critical_path = max((asap[n] + node_delays[n] for n in node_ids), default=0)

    # Compute ALAP times
    alap = {}
    out_degree = {n: len(successors[n]) for n in node_ids}
    queue = deque([n for n in node_ids if out_degree[n] == 0])

    while queue:
        node = queue.popleft()
        if successors[node]:
            alap[node] = min(alap[s] - node_delays[node] for s in successors[node])
        else:
            alap[node] = critical_path - node_delays[node]
        for pred in predecessors[node]:
            out_degree[pred] -= 1
            if out_degree[pred] == 0:
                queue.append(pred)

    # Compute critical path length to sink
    cp_to_sink = {}
    out_degree = {n: len(successors[n]) for n in node_ids}
    queue = deque([n for n in node_ids if out_degree[n] == 0])

    while queue:
        node = queue.popleft()
        if successors[node]:
            cp_to_sink[node] = node_delays[node] + max(cp_to_sink[s] for s in successors[node])
        else:
            cp_to_sink[node] = node_delays[node]
        for pred in predecessors[node]:
            out_degree[pred] -= 1
            if out_degree[pred] == 0:
                queue.append(pred)

    # Compute number of successors (transitive)
    num_successors = {}
    out_degree = {n: len(successors[n]) for n in node_ids}
    queue = deque([n for n in node_ids if out_degree[n] == 0])

    while queue:
        node = queue.popleft()
        num_successors[node] = len(successors[node])
        for s in successors[node]:
            num_successors[node] += num_successors.get(s, 0)
        for pred in predecessors[node]:
            out_degree[pred] -= 1
            if out_degree[pred] == 0:
                queue.append(pred)

    # Compute resource scarcity
    resource_scarcity = {rt: 1.0 / resources[rt] for rt in resources}

    # Compute nodes by resource type
    nodes_by_type = defaultdict(list)
    for n in node_ids:
        nodes_by_type[node_types[n]].append(n)

    # Define priority functions
    def priority_mobility(node):
        return (alap[node] - asap[node], alap[node])

    def priority_critical_path(node):
        return (-cp_to_sink[node], alap[node] - asap[node])

    def priority_alap(node):
        return (alap[node], -cp_to_sink[node])

    def priority_combined(node):
        mobility = alap[node] - asap[node]
        return (mobility, alap[node], -cp_to_sink[node], -num_successors.get(node, 0))

    def priority_resource(node):
        scarcity = resource_scarcity[node_types[node]]
        return (-scarcity, alap[node] - asap[node], alap[node])

    def priority_delay(node):
        delay = node_delays[node]
        return (-delay, alap[node] - asap[node], alap[node])

    def priority_weighted1(node):
        mobility = alap[node] - asap[node]
        cp = cp_to_sink[node]
        scarcity = resource_scarcity[node_types[node]]
        return (mobility - 0.3 * cp, alap[node])

    def priority_weighted2(node):
        mobility = alap[node] - asap[node]
        cp = cp_to_sink[node]
        delay = node_delays[node]
        return (mobility - 0.5 * cp - 0.2 * delay, alap[node])

    def priority_successors(node):
        return (-num_successors.get(node, 0), alap[node] - asap[node], alap[node])

    def priority_asap(node):
        return (asap[node], alap[node] - asap[node])

    priority_functions = [
        priority_mobility,
        priority_critical_path,
        priority_alap,
        priority_combined,
        priority_resource,
        priority_delay,
        priority_weighted1,
        priority_weighted2,
        priority_successors,
        priority_asap,
    ]

    def schedule_with_priority(priority_func):
        max_time = critical_path + max(node_delays.values()) * len(node_ids) + 1000
        resource_usage = {rt: [0] * (max_time + 1) for rt in resources}

        def find_earliest_feasible(node, es):
            rtype = node_types[node]
            delay = node_delays[node]
            ru = resource_usage[rtype]
            limit = resources[rtype]

            start_time = es
            while start_time + delay <= max_time:
                feasible = True
                for t in range(start_time, start_time + delay):
                    if ru[t] >= limit:
                        feasible = False
                        start_time = t + 1
                        break
                if feasible:
                    return start_time
            return start_time

        def add_resource_usage(node, start_time):
            rtype = node_types[node]
            delay = node_delays[node]
            ru = resource_usage[rtype]
            for t in range(start_time, start_time + delay):
                ru[t] += 1

        def remove_resource_usage(node, start_time):
            rtype = node_types[node]
            delay = node_delays[node]
            ru = resource_usage[rtype]
            for t in range(start_time, start_time + delay):
                ru[t] -= 1

        def earliest_start(node, schedule):
            if not predecessors[node]:
                return 0
            return max(schedule[p] + node_delays[p] for p in predecessors[node])

        schedule = {}
        unscheduled = set(node_ids)
        remaining_preds = {n: len(predecessors[n]) for n in node_ids}

        while unscheduled:
            ready = [n for n in unscheduled if remaining_preds[n] == 0]

            if not ready:
                break

            ready.sort(key=priority_func)

            for node in ready:
                es = earliest_start(node, schedule)
                start_time = find_earliest_feasible(node, es)

                schedule[node] = start_time
                add_resource_usage(node, start_time)
                unscheduled.remove(node)

                for succ in successors[node]:
                    remaining_preds[succ] -= 1

        # Post-processing: try to move operations earlier
        improved = True
        iterations = 0
        max_iterations = 10

        while improved and iterations < max_iterations:
            improved = False
            iterations += 1

            sorted_nodes = sorted(node_ids, key=lambda n: schedule[n], reverse=True)

            for node in sorted_nodes:
                current_start = schedule[node]
                es = earliest_start(node, schedule)

                new_start = find_earliest_feasible(node, es)
                if new_start < current_start:
                    remove_resource_usage(node, current_start)
                    add_resource_usage(node, new_start)
                    schedule[node] = new_start
                    improved = True

        return schedule

    # Try all priority functions and pick the best
    best_schedule = None
    best_cost = float('inf')

    for pf in priority_functions:
        schedule = schedule_with_priority(pf)
        cost = max(schedule[n] + node_delays[n] for n in node_ids)
        if cost < best_cost:
            best_cost = cost
            best_schedule = schedule

    # Try rescheduling with different node orders
    def reschedule_with_order(node_order):
        max_time = critical_path + max(node_delays.values()) * len(node_ids) + 1000
        resource_usage = {rt: [0] * (max_time + 1) for rt in resources}

        def find_earliest_feasible(node, es):
            rtype = node_types[node]
            delay = node_delays[node]
            ru = resource_usage[rtype]
            limit = resources[rtype]

            start_time = es
            while start_time + delay <= max_time:
                feasible = True
                for t in range(start_time, start_time + delay):
                    if ru[t] >= limit:
                        feasible = False
                        start_time = t + 1
                        break
                if feasible:
                    return start_time
            return start_time

        def add_resource_usage(node, start_time):
            rtype = node_types[node]
            delay = node_delays[node]
            ru = resource_usage[rtype]
            for t in range(start_time, start_time + delay):
                ru[t] += 1

        def earliest_start(node, schedule):
            if not predecessors[node]:
                return 0
            return max(schedule[p] + node_delays[p] for p in predecessors[node])

        schedule = {}
        remaining_preds = {n: len(predecessors[n]) for n in node_ids}

        for node in node_order:
            if remaining_preds[node] > 0:
                continue
            es = earliest_start(node, schedule)
            start_time = find_earliest_feasible(node, es)
            schedule[node] = start_time
            add_resource_usage(node, start_time)

            # Update remaining predecessors for successors
            for succ in successors[node]:
                remaining_preds[succ] -= 1

        # Schedule any remaining nodes
