from collections import defaultdict, deque

def solve(input_file: str, solution_file: str):
    individuals = []
    with open(input_file, 'r') as f:
        for line in f:
            parts = line.strip().split()
            if len(parts) < 7:
                continue
            individuals.append({
                'id': int(parts[1]),
                'father': int(parts[2]),
                'mother': int(parts[3]),
                'sex': int(parts[4]),
                'allele1': int(parts[5]),
                'allele2': int(parts[6])
            })

    m = len(individuals)
    if m == 0:
        with open(solution_file, 'w') as f:
            f.write('')
        return

    max_allele = max(max(ind['allele1'], ind['allele2']) for ind in individuals)
    n_alleles = max(1, max_allele)

    domain = [(a, b) for a in range(1, n_alleles + 1) for b in range(a, n_alleles + 1)]
    domain_size = len(domain)

    id_to_idx = {ind['id']: i for i, ind in enumerate(individuals)}

    parents = [None] * m
    children = defaultdict(list)

    for i, ind in enumerate(individuals):
        father_id, mother_id = ind['father'], ind['mother']
        if father_id > 0 and mother_id > 0 and father_id in id_to_idx and mother_id in id_to_idx:
            parents[i] = (id_to_idx[father_id], id_to_idx[mother_id])
            children[id_to_idx[father_id]].append(i)
            children[id_to_idx[mother_id]].append(i)

    unary_costs = np.zeros((m, domain_size), dtype=np.int8)
    for i, ind in enumerate(individuals):
        obs_a, obs_b = ind['allele1'], ind['allele2']
        for k, (a, b) in enumerate(domain):
            if obs_a == 0 and obs_b == 0:
                unary_costs[i, k] = 0
            elif obs_a == 0:
                unary_costs[i, k] = 0 if (a == obs_b or b == obs_b) else 1
            elif obs_b == 0:
                unary_costs[i, k] = 0 if (a == obs_a or b == obs_a) else 1
            else:
                unary_costs[i, k] = 0 if {obs_a, obs_b} == {a, b} else 1

    valid_child = np.zeros((domain_size, domain_size, domain_size), dtype=bool)
    for f in range(domain_size):
        for mo in range(domain_size):
            f_set, m_set = set(domain[f]), set(domain[mo])
            for c in range(domain_size):
                c_set = set(domain[c])
                if len(c_set) == 1:
                    a = list(c_set)[0]
                    if a in f_set and a in m_set:
                        valid_child[f, mo, c] = True
                else:
                    a, b = domain[c]
                    if (a in f_set and b in m_set) or (a in m_set and b in f_set):
                        valid_child[f, mo, c] = True

    in_degree = [0] * m
    for i in range(m):
        if parents[i] is not None:
            in_degree[i] = 2

    queue = deque([i for i in range(m) if in_degree[i] == 0])
    topo_order = []
    while queue:
        i = queue.popleft()
        topo_order.append(i)
        for c in children[i]:
            in_degree[c] -= 1
            if in_degree[c] == 0:
                queue.append(c)

    for i in range(m):
        if i not in topo_order:
            topo_order.append(i)

    domains = [set(range(domain_size)) for _ in range(m)]

    def propagate():
        queue = deque()
        for i in range(m):
            if parents[i] is not None:
                queue.append(i)

        while queue:
            i = queue.popleft()
            father, mother = parents[i]

            valid = set()
            for f in domains[father]:
                for mo in domains[mother]:
                    for g in domains[i]:
                        if valid_child[f, mo, g]:
                            valid.add(g)

            if valid != domains[i]:
                domains[i] = valid
                if not domains[i]:
                    return False
                for c in children[i]:
                    if parents[c] is not None:
                        queue.append(c)
                if parents[father] is not None:
                    queue.append(father)
                if parents[mother] is not None:
                    queue.append(mother)

        return True

    if not propagate():
        with open(solution_file, 'w') as f:
            f.write(' '.join(['0'] * m))
        return

    domains = [sorted(list(d), key=lambda g: unary_costs[i, g]) for i, d in enumerate(domains)]

    best_cost = [float('inf')]
    best_assignment = [None]
    min_unary = [unary_costs[i, domains[i][0]] if domains[i] else float('inf') for i in range(m)]

    def search(assignment, cost_so_far, idx):
        if best_cost[0] == 0:
            return
        if idx == m:
            if cost_so_far < best_cost[0]:
                best_cost[0] = cost_so_far
                best_assignment[0] = assignment[:]
            return

        i = topo_order[idx]

        lb = cost_so_far + sum(min_unary[topo_order[j]] for j in range(idx, m))
        if lb >= best_cost[0]:
            return

        valid = domains[i]
        if parents[i] is not None:
            father, mother = parents[i]
            f, mo = assignment[father], assignment[mother]
            if f is not None and mo is not None:
                valid = [g for g in valid if valid_child[f, mo, g]]

        for g in valid:
            assignment[i] = g
            new_cost = cost_so_far + unary_costs[i, g]
            if new_cost < best_cost[0]:
                search(assignment, new_cost, idx + 1)
            assignment[i] = None

    search([None] * m, 0, 0)

    if best_assignment[0] is None:
        assignment = [0] * m
        for i in topo_order:
            valid = list(range(domain_size))
            if parents[i] is not None:
                father, mother = parents[i]
                f, mo = assignment[father], assignment[mother]
                valid = [g for g in valid if valid_child[f, mo, g]]
            valid.sort(key=lambda g: unary_costs[i, g])
            assignment[i] = valid[0] if valid else 0

        cost = sum(unary_costs[i, assignment[i]] for i in range(m))
        improved = True
        while improved:
            improved = False
            for i in range(m):
                for g in range(domain_size):
                    if g != assignment[i]:
                        valid = True
                        if parents[i] is not None:
                            father, mother = parents[i]
                            f, mo = assignment[father], assignment[mother]
                            if not valid_child[f, mo, g]:
                                valid = False
                        if valid:
                            for c in children[i]:
                                if parents[c] is not None:
                                    father, mother = parents[c]
                                    other = mother if i == father else father
                                    gc = assignment[c]
                                    if not valid_child[g if i == father else assignment[other], 
                                                      assignment[other] if i == father else g, gc]:
                                        valid = False
                                        break

                        if valid:
                            new_cost = cost - unary_costs[i, assignment[i]] + unary_costs[i, g]
                            if new_cost < cost:
                                assignment[i] = g
                                cost = new_cost
                                improved = True
                                break
                if improved:
                    break

        best_assignment[0] = assignment

    result = [best_assignment[0][i] for i in range(m)]
    with open(solution_file, 'w') as f:
        f.write(' '.join(str(g) for g in result))

