def solve(input_file: str, solution_file: str):
    from dataclasses import dataclass
    from typing import Dict, List
    import os
    import time

    @dataclass
    class Node:
        index: int
        x: float
        y: float
        demand: float
        earliest_time: float
        latest_time: float
        service_time: float
        pickup_sibling: int
        delivery_sibling: int
        is_pickup: bool

    @dataclass
    class Instance:
        name: str
        type: str
        dimension: int
        vehicles: int
        capacity: float
        edge_weight_type: str
        nodes: Dict[int, Node]
        depot_node: List[int]

    def read_instance(file_path: str) -> Instance:
        with open(file_path, "r") as file:
            lines = file.readlines()

        name = ""
        type_ = ""
        dimension = 0
        vehicles = 0
        capacity = 0.0
        edge_weight_type = ""
        nodes = {}
        depot_node = []

        section = None
        for line in lines:
            line = line.strip()
            if line.startswith("NAME"):
                name = line.split(":")[1].strip()
            elif line.startswith("TYPE"):
                type_ = line.split(":")[1].strip()
            elif line.startswith("DIMENSION"):
                dimension = int(line.split(":")[1].strip())
            elif line.startswith("VEHICLES"):
                vehicles = int(line.split(":")[1].strip())
            elif line.startswith("CAPACITY"):
                capacity = float(line.split(":")[1].strip())
            elif line.startswith("EDGE_WEIGHT_TYPE"):
                edge_weight_type = line.split(":")[1].strip()
            elif line.startswith("NODE_COORD_SECTION"):
                section = "NODE_COORD_SECTION"
            elif line.startswith("PICKUP_AND_DELIVERY_SECTION"):
                section = "PICKUP_AND_DELIVERY_SECTION"
            elif line.startswith("DEPOT_SECTION"):
                section = "DEPOT_SECTION"
            elif line.startswith("EOF"):
                break
            elif section == "NODE_COORD_SECTION":
                parts = line.split()
                index = int(parts[0])
                x, y = float(parts[1]), float(parts[2])
                nodes[index] = Node(
                    index=index, x=x, y=y, demand=0.0, earliest_time=0.0,
                    latest_time=0.0, service_time=0.0, pickup_sibling=0,
                    delivery_sibling=0, is_pickup=False,
                )
            elif section == "PICKUP_AND_DELIVERY_SECTION":
                parts = line.split()
                index = int(parts[0])
                if index in nodes:
                    nodes[index].demand = float(parts[1])
                    nodes[index].earliest_time = float(parts[2])
                    nodes[index].latest_time = float(parts[3])
                    nodes[index].service_time = float(parts[4])
                    nodes[index].pickup_sibling = int(parts[5])
                    nodes[index].delivery_sibling = int(parts[6])
                    nodes[index].is_pickup = nodes[index].pickup_sibling == 0
            elif section == "DEPOT_SECTION":
                if line != "-1":
                    depot_node.append(int(line))

        return Instance(name=name, type=type_, dimension=dimension, vehicles=vehicles,
                       capacity=capacity, edge_weight_type=edge_weight_type,
                       nodes=nodes, depot_node=depot_node)

    def calculate_distance(x1: float, y1: float, x2: float, y2: float) -> float:
        return round(((x2 - x1) ** 2 + (y1 - y2) ** 2) ** 0.5, 0)

    base_name = os.path.splitext(os.path.basename(input_file))[0]
    instance = read_instance(input_file)

    start_time = time.time()
    depot = instance.depot_node[0]
    capacity = instance.capacity

    node_list = sorted(instance.nodes.keys())
    dist = {}
    for i in node_list:
        for j in node_list:
            dist[(i, j)] = calculate_distance(
                instance.nodes[i].x, instance.nodes[i].y,
                instance.nodes[j].x, instance.nodes[j].y
            )

    requests = []
    for idx, node in instance.nodes.items():
        if idx != depot and node.is_pickup:
            requests.append((idx, node.delivery_sibling))

    def route_distance(route):
        return sum(dist[(route[i], route[i+1])] for i in range(len(route)-1))

    def is_feasible(route):
        if len(route) <= 2:
            return True

        load = 0
        visited_pickups = set()
        for node in route[1:-1]:
            load += instance.nodes[node].demand
            if load > capacity + 0.001:
                return False
            if instance.nodes[node].is_pickup:
                visited_pickups.add(node)
            else:
                if instance.nodes[node].pickup_sibling not in visited_pickups:
                    return False

        t = 0
        for i in range(1, len(route)):
            t += dist[(route[i-1], route[i])]
            if i < len(route) - 1:
                node = instance.nodes[route[i]]
                if t > node.latest_time + 0.001:
                    return False
                t = max(t, node.earliest_time) + node.service_time

        return True

    def try_insert_pair(route, pickup, delivery):
        best_route, best_cost = None, float('inf')
        for i in range(1, len(route)):
            new_route = route[:i] + [pickup] + route[i:]
            for j in range(i + 1, len(new_route)):
                test = new_route[:j] + [delivery] + new_route[j:]
                if is_feasible(test):
                    c = route_distance(test)
                    if c < best_cost:
                        best_cost, best_route = c, test
        return best_route, best_cost if best_route else (None, float('inf'))

    def construct_solution():
        sorted_requests = sorted(requests, key=lambda r: instance.nodes[r[0]].earliest_time)

        routes = [[depot, depot] for _ in range(instance.vehicles)]

        for pickup, delivery in sorted_requests:
            best_route_idx = -1
            best_route = None
            best_cost = float('inf')

            for r, route in enumerate(routes):
                new_route, cost = try_insert_pair(route, pickup, delivery)
                if new_route:
                    inc = cost - route_distance(route)
                    if inc < best_cost:
                        best_cost = inc
                        best_route = new_route
                        best_route_idx = r

            if best_route_idx >= 0:
                routes[best_route_idx] = best_route
            else:
                for r, route in enumerate(routes):
                    if len(route) == 2:
                        test = [depot, pickup, delivery, depot]
                        if is_feasible(test):
                            routes[r] = test
                            break
                else:
                    routes.append([depot, pickup, delivery, depot])

        return [r for r in routes if len(r) > 2]

    def relocate(routes):
        improved = True
        while improved:
            improved = False
            for r1 in range(len(routes)):
                for r2 in range(len(routes)):
                    if r1 == r2:
                        continue
                    route1, route2 = routes[r1], routes[r2]
                    pairs = [(n, instance.nodes[n].delivery_sibling) for n in route1[1:-1]
                             if instance.nodes[n].is_pickup and instance.nodes[n].delivery_sibling in route1]
                    for p, d in pairs:
                        new_r2, c2 = try_insert_pair(route2, p, d)
                        if not new_r2:
                            continue
                        new_r1 = [depot] + [n for n in route1[1:-1] if n not in (p, d)] + [depot]
                        if len(new_r1) == 2:
                            new_r1 = [depot, depot]
                        if route_distance(new_r1) + c2 < route_distance(route1) + route_distance(route2) - 0.001:
                            routes[r1] = new_r1
                            routes[r2] = new_r2
                            improved = True
                            break
                    if improved:
                        break
                if improved:
                    break
        return [r for r in routes if len(r) > 2]

    def exchange(routes):
        improved = True
        while improved:
            improved = False
            for r1 in range(len(routes)):
                for r2 in range(r1 + 1, len(routes)):
                    route1, route2 = routes[r1], routes[r2]
                    pairs1 = [(n, instance.nodes[n].delivery_sibling) for n in route1[1:-1]
                              if instance.nodes[n].is_pickup and instance.nodes[n].delivery_sibling in route1]
                    pairs2 = [(n, instance.nodes[n].delivery_sibling) for n in route2[1:-1]
                              if instance.nodes[n].is_pickup and instance.nodes[n].delivery_sibling in route2]
                    for p1, d1 in pairs1:
                        for p2, d2 in pairs2:
                            t1 = [depot] + [n for n in route1[1:-1] if n not in (p1, d1)] + [depot]
                            t2 = [depot] + [n for n in route2[1:-1] if n not in (p2, d2)] + [depot]
                            if len(t1) == 2:
                                t1 = [depot, depot]
                            if len(t2) == 2:
                                t2 = [depot, depot]
                            n1, c1 = try_insert_pair(t1, p2, d2)
                            if not n1:
                                continue
                            n2, c2 = try_insert_pair(t2, p1, d1)
                            if not n2:
                                continue
                            if c1 + c2 < route_distance(route1) + route_distance(route2) - 0.001:
                                routes[r1] = n1
                                routes[r2] = n2
                                improved = True
                                break
                        if improved:
                            break
                    if improved:
                        break
                if improved:
                    break
        return routes

    def intra_opt(routes):
        improved = True
        while improved:
            improved = False
            for ri in range(len(routes)):
                route = routes[ri]
                if len(route) <= 4:
                    continue
                pairs = [(n, instance.nodes[n].delivery_sibling) for n in route[1:-1]
                         if instance.nodes[n].is_pickup and instance.nodes[n].delivery_sibling in route]
                for p, d in pairs:
                    temp = [depot] + [n for n in route[1:-1] if n not in (p, d)] + [depot]
                    if len(temp) == 2:
                        temp = [depot, depot]
                    for pi in range(1, len(temp)):
                        t = temp[:pi] + [p] + temp[pi:]
                        for pj in range(pi + 1, len(t) + 1):
                            final = t[:pj] + [d] + t[pj:]
                            if is_feasible(final) and route_distance(final) < route_distance(route) - 0.001:
                                routes[ri] = final
                                improved = True
                                break
                        if improved:
                            break
                    if improved:
                        break
                if improved:
                    break
        return routes

    def optimize(routes):
        routes = relocate(routes)
        routes = exchange(routes)
        routes = intra_opt(routes)
        return routes

    def total_dist(routes):
        return sum(route_distance(r) for r in routes)

    routes = construct_solution()

    for _ in range(10):
        if time.time() - start_time > 8:
            break
        old = total_dist(routes)
        routes = optimize(routes)
        if total_dist(routes) >= old - 0.001:
            break

    routes = [r for r in routes if len(r) > 2]

    with open(solution_file, 'w') as f:
        f.write(f"{instance.name}\n")
        for route in routes:
            f.write(" ".join(map(str, route)) + "\n")

