from collections import defaultdict, deque

def solve(input_file: str, solution_file: str):
    model_name, inputs, outputs, gates = parse_blif(input_file)

    inputs_set = set(inputs)
    outputs_set = set(outputs)

    preds = defaultdict(list)
    for out, (inps, tt) in gates.items():
        for inp in inps:
            preds[out].append(inp)

    order = topological_sort(gates, inputs_set)

    K = 6
    cuts = enumerate_cuts(order, preds, inputs_set, K)
    dp = dp_cover(order, cuts, inputs_set, K)
    lut_roots = find_lut_roots(dp, outputs_set, inputs_set)
    generate_blif(solution_file, model_name, inputs, outputs, gates, lut_roots, dp, inputs_set, preds, K)


def parse_blif(filename):
    with open(filename, 'r') as f:
        content = f.read()

    content = content.replace('\\\n', ' ')
    lines = content.split('\n')

    model_name = ''
    inputs = []
    outputs = []
    gates = {}

    i = 0
    while i < len(lines):
        line = lines[i].strip()

        if not line or line.startswith('#'):
            i += 1
            continue

        if line.startswith('.model'):
            parts = line.split()
            if len(parts) > 1:
                model_name = parts[1]
        elif line.startswith('.inputs'):
            parts = line.split()[1:]
            inputs.extend(parts)
        elif line.startswith('.outputs'):
            parts = line.split()[1:]
            outputs.extend(parts)
        elif line.startswith('.names'):
            parts = line.split()
            if len(parts) == 2:
                gate_output = parts[1]
                gate_inputs = []
            else:
                gate_inputs = parts[1:-1]
                gate_output = parts[-1]

            tt_rows = []
            i += 1
            while i < len(lines):
                row = lines[i].strip()
                if not row or row.startswith('#'):
                    i += 1
                    continue
                if row.startswith('.'):
                    break
                tt_rows.append(row)
                i += 1
            i -= 1

            gates[gate_output] = (gate_inputs, tt_rows)
        elif line.startswith('.end'):
            break

        i += 1

    return model_name, inputs, outputs, gates


def topological_sort(gates, inputs_set):
    succs = defaultdict(set)
    all_nodes = set(inputs_set)
    for out, (inps, tt) in gates.items():
        all_nodes.add(out)
        for inp in inps:
            succs[inp].add(out)

    in_degree = {node: 0 for node in all_nodes}
    for out, (inps, tt) in gates.items():
        in_degree[out] = len(inps)

    queue = deque([n for n in all_nodes if in_degree[n] == 0])
    order = []

    while queue:
        node = queue.popleft()
        order.append(node)

        for s in succs[node]:
            in_degree[s] -= 1
            if in_degree[s] == 0:
                queue.append(s)

    return order


def enumerate_cuts(order, preds, inputs_set, K, max_cuts=16):
    cuts = {}

    for v in order:
        if v in inputs_set:
            cuts[v] = [frozenset([v])]
        else:
            v_preds = preds.get(v, [])

            if not v_preds:
                cuts[v] = [frozenset()]
                continue

            v_cuts = {frozenset(v_preds)}

            for p in v_preds:
                if p not in inputs_set and p in cuts:
                    p_cuts = cuts[p]
                    new_cuts = set()
                    for c in v_cuts:
                        if p in c:
                            for c_p in p_cuts:
                                merged = (c - {p}) | c_p
                                new_cuts.add(merged)
                        else:
                            new_cuts.add(c)
                    v_cuts = new_cuts

                    if len(v_cuts) > max_cuts * 3:
                        v_cuts = set(prune_cuts(list(v_cuts), max_cuts))

            v_cuts = [c for c in v_cuts if len(c) <= K]

            if not v_cuts:
                v_cuts = [frozenset(list(v_preds)[:K])]

            cuts[v] = v_cuts

    return cuts


def prune_cuts(cuts, max_cuts):
    if len(cuts) <= max_cuts:
        return cuts

    cuts = sorted(cuts, key=lambda x: len(x))
    result = []
    for c in cuts:
        dominated = False
        for r in result:
            if r <= c:
                dominated = True
                break
        if not dominated:
            result.append(c)
            if len(result) >= max_cuts:
                break

    return result


def dp_cover(order, cuts, inputs_set, K):
    dp = {}

    for v in order:
        if v in inputs_set:
            dp[v] = (0, None)
        else:
            best_cost = float('inf')
            best_cut = None

            v_cuts = cuts.get(v, [])
            if not v_cuts:
                v_cuts = [frozenset()]

            for c in v_cuts:
                if len(c) > K:
                    continue

                cost = 1
                for u in c:
                    if u not in inputs_set:
                        if u in dp:
                            cost += dp[u][0]
                        else:
                            cost += 1

                if cost < best_cost:
                    best_cost = cost
                    best_cut = c

            dp[v] = (best_cost, best_cut)

    return dp


def find_lut_roots(dp, outputs, inputs_set):
    lut_roots = set()
    visited = set(inputs_set)

    to_process = list(outputs)

    while to_process:
        v = to_process.pop()
        if v in visited or v in inputs_set:
            continue

        lut_roots.add(v)
        visited.add(v)

        cut = dp.get(v, (0, None))[1]
        if cut:
            for u in cut:
                if u not in visited and u not in inputs_set:
                    to_process.append(u)

    return lut_roots


def get_cone_nodes(root, cut, preds, inputs_set):
    cut_set = set(cut)
    cone = set()

    queue = deque([root])
    visited = set()

    while queue:
        node = queue.popleft()
        if node in visited:
            continue
        visited.add(node)

        if node in cut_set or node in inputs_set:
            continue

        cone.add(node)

        for p in preds.get(node, []):
            if p not in visited:
                queue.append(p)

    return cone


def simulate_gate(inputs, tt_rows, values):
    if not inputs:
        if not tt_rows:
            return 0
        for row in tt_rows:
            if row.strip() == '1':
                return 1
        return 0

    input_values = [values.get(inp, 0) for inp in inputs]

    has_zero_row = False
    for row in tt_rows:
        parts = row.split()
        if len(parts) >= 2 and parts[-1] == '0':
            has_zero_row = True
            break

    for row in tt_rows:
        parts = row.split()
        if len(parts) < 2:
            continue

        pattern = parts[0]
        out_val = parts[-1]

        matches = True
        for i, ch in enumerate(pattern):
            if i < len(input_values):
                if ch == '0' and input_values[i] != 0:
                    matches = False
                    break
                elif ch == '1' and input_values[i] != 1:
                    matches = False
                    break

        if matches:
            return int(out_val)

    return 1 if has_zero_row else 0


def simulate_cone(root, cone, gates, cut_values, inputs_set, preds):
    cone_list = list(cone)
    cone_preds = {n: [p for p in preds.get(n, []) if p in cone] for n in cone}

    in_degree = {n: len(cone_preds[n]) for n in cone}
    queue = deque([n for n in cone if in_degree[n] == 0])
    cone_order = []

    while queue:
        node = queue.popleft()
        cone_order.append(node)
        for other in cone:
            if node in cone_preds.get(other, []):
                in_degree[other] -= 1
                if in_degree[other] == 0:
                    queue.append(other)

    values = dict(cut_values)

    for node in cone_order:
        if node in gates:
            gate_inputs, tt_rows = gates[node]
            values[node] = simulate_gate(gate_inputs, tt_rows, values)

    return values.get(root, 0)


def generate_lut_truth_table(root, cut, cone, gates, inputs_set, preds, K):
    cut_list = list(cut)
    k = len(cut_list)

    if k == 0:
        output = simulate_cone(root, cone, gates, {}, inputs_set, preds)
        return [], cut_list, output

    if k > K:
        cut_list = cut_list[:K]
        k = K

    outputs = []
    for i in range(2**k):
        cut_values = {cut_list[j]: (i >> j) & 1 for j in range(k)}
        output = simulate_cone(root, cone, gates, cut_values, inputs_set, preds)
        outputs.append(output)

    blif_rows = []
    for i, output in enumerate(outputs):
        if output == 1:
            pattern = ''.join(str((i >> j) & 1) for j in range(k))
            blif_rows.append(f"{pattern} 1")

    return blif_rows, cut_list, None


def generate_blif(filename, model_name, inputs, outputs, gates, lut_roots, dp, inputs_set, preds, K):
    sorted_roots = sorted(lut_roots, key=lambda x: str(x))

    with open(filename, 'w') as f:
        f.write(f".model {model_name}\n")
        f.write(".inputs " + " ".join(inputs) + "\n")
        f.write(".outputs " + " ".join(outputs) + "\n")

        for root in sorted_roots:
            cut = dp.get(root, (0, None))[1]
            if cut is None:
                continue

            if len(cut) > K:
                cut = frozenset(list(cut)[:K])

            cone = get_cone_nodes(root, cut, preds, inputs_set)
