def solve(input_file: str, solution_file: str):
    K = 6

    with open(input_file, "r") as f:
        raw = f.readlines()

    lines = []
    acc = ""
    for ln in raw:
        s = ln.split("#", 1)[0].rstrip("\n").rstrip()
        if not s:
            continue
        if s.endswith("\\"):
            acc += s[:-1].rstrip() + " "
        else:
            t = (acc + s).strip()
            acc = ""
            if t:
                lines.append(t)
    if acc.strip():
        lines.append(acc.strip())

    model = "top"
    inputs = []
    outputs = []
    nodes = []
    passthrough = []

    i = 0
    n = len(lines)
    while i < n:
        s = lines[i]
        if s.startswith(".model"):
            t = s.split()
            if len(t) > 1:
                model = t[1]
            i += 1
        elif s.startswith(".inputs"):
            inputs.extend(s.split()[1:])
            i += 1
        elif s.startswith(".outputs"):
            outputs.extend(s.split()[1:])
            i += 1
        elif s.startswith(".names"):
            t = s.split()
            if len(t) == 2:
                ins = []
                out = t[1]
            else:
                ins = t[1:-1]
                out = t[-1]
            i += 1
            rows = []
            while i < n and not lines[i].startswith("."):
                r = lines[i].strip()
                if r:
                    rows.append(r)
                i += 1
            nodes.append((ins, out, rows))
        elif s.startswith(".end"):
            i += 1
        else:
            passthrough.append(s)
            i += 1

    outputs_set = set(outputs)

    used = set(inputs) | set(outputs) | {model}
    for ins, out, _ in nodes:
        used.add(out)
        used.update(ins)

    temp_id = 0

    def new_temp():
        nonlocal temp_id
        while True:
            v = f"new_lut_{temp_id}"
            temp_id += 1
            if v not in used:
                used.add(v)
                return v

    blocks = []

    def emit(ins, out, rows):
        blocks.append((list(ins), out, list(rows)))
        return out

    alias = {x: x for x in inputs}

    def resolve(x):
        y = x
        trail = []
        while y in alias and alias[y] != y:
            trail.append(y)
            y = alias[y]
        for z in trail:
            alias[z] = y
        return y

    def norm_rows(rows):
        rr = []
        for r in rows:
            r = " ".join(r.split())
            if r:
                rr.append(r)
        rr.sort()
        out = []
        p = None
        for r in rr:
            if r != p:
                out.append(r)
                p = r
        return tuple(out)

    lut_cache = {}
    inv_cache = {}
    const0 = None
    const1 = None

    def get_const0():
        nonlocal const0
        if const0 is None:
            key = ((), ())
            got = lut_cache.get(key)
            if got is None:
                got = new_temp()
                emit([], got, [])
                lut_cache[key] = got
            const0 = got
        return const0

    def get_const1():
        nonlocal const1
        if const1 is None:
            key = ((), ("1",))
            got = lut_cache.get(key)
            if got is None:
                got = new_temp()
                emit([], got, ["1"])
                lut_cache[key] = got
            const1 = got
        return const1

    def emit_temp(ins, rows):
        key = (tuple(ins), norm_rows(rows))
        got = lut_cache.get(key)
        if got is not None:
            return got
        out = new_temp()
        emit(ins, out, key[1])
        lut_cache[key] = out
        return out

    def get_inv(x):
        x = resolve(x)
        y = inv_cache.get(x)
        if y is not None:
            return y
        y = emit_temp([x], ["0 1"])
        inv_cache[x] = y
        return y

    def connect(src, dst):
        src = resolve(src)
        if src == dst:
            alias[dst] = dst
            return dst
        emit([src], dst, ["1 1"])
        alias[dst] = dst
        return dst

    def parse_rows(rows):
        ones = []
        zeros = []
        for r in rows:
            t = r.split()
            if not t:
                continue
            if len(t) == 1:
                p, b = t[0], "1"
            else:
                p, b = t[0], t[1]
            if b == "0":
                zeros.append(p)
            else:
                ones.append(p)
        return ones, zeros

    def dedup_sorted(lst):
        if not lst:
            return ()
        s = sorted(set(lst))
        return tuple(s)

    def and_tree(nets):
        if not nets:
            return get_const1()
        cur = list(nets)
        while len(cur) > K:
            nxt = []
            j = 0
            while j < len(cur):
                ch = cur[j:j + K]
                j += K
                if len(ch) == 1:
                    nxt.append(ch[0])
                else:
                    nxt.append(emit_temp(ch, [("1" * len(ch)) + " 1"]))
            cur = nxt
        if len(cur) == 1:
            return cur[0]
        return emit_temp(cur, [("1" * len(cur)) + " 1"])

    def or_tree(nets):
        if not nets:
            return get_const0()
        cur = list(nets)
        while len(cur) > K:
            nxt = []
            j = 0
            while j < len(cur):
                ch = cur[j:j + K]
                j += K
                if len(ch) == 1:
                    nxt.append(ch[0])
                else:
                    nxt.append(emit_temp(ch, [("0" * len(ch)) + " 0"]))
            cur = nxt
        if len(cur) == 1:
            return cur[0]
        return emit_temp(cur, [("0" * len(cur)) + " 0"])

    def cube_net(ins, patt):
        lits = []
        for v, b in zip(ins, patt):
            if b == "0" or b == "1":
                lits.append((v, b))
        if not lits:
            return get_const1()
        if len(lits) <= K:
            vin = [v for v, _ in lits]
            bits = "".join(b for _, b in lits)
            return emit_temp(vin, [bits + " 1"])
        parts = []
        j = 0
        while j < len(lits):
            ch = lits[j:j + K]
            j += K
            vin = [v for v, _ in ch]
            bits = "".join(b for _, b in ch)
            parts.append(emit_temp(vin, [bits + " 1"]))
        return and_tree(parts)

    def trivial_map(ins, rows):
        nr = norm_rows(rows)
        if len(ins) == 0:
            if len(nr) == 0:
                return get_const0()
            if len(nr) == 1 and nr[0] == "1":
                return get_const1()
            return None
        if len(ins) == 1:
            a = ins[0]
            if len(nr) == 1:
                r = nr[0]
                if r == "1 1":
                    return a
                if r == "0 1":
                    return get_inv(a)
                if r == "1 0":
                    return get_inv(a)
                if r == "0 0":
                    return a
        return None

    for ins0, out, rows0 in nodes:
        ins = [resolve(x) for x in ins0]

        if len(ins) <= K:
            simp = trivial_map(ins, rows0)
            if simp is not None:
                alias[out] = resolve(simp)
                continue

            nr = norm_rows(rows0)
            key = (tuple(ins), nr)
            existing = lut_cache.get(key)

            if out in outputs_set:
                if existing is None:
                    emit(ins, out, nr)
                    lut_cache[key] = out
                    alias[out] = out
                else:
                    src = resolve(existing)
                    if src == out:
                        alias[out] = out
                    else:
                        if src == get_const0():
                            emit([], out, [])
                        elif src == get_const1():
                            emit([], out, ["1"])
                        else:
                            emit([src], out, ["1 1"])
                        alias[out] = out
            else:
                if existing is None:
                    emit(ins, out, nr)
                    lut_cache[key] = out
                    alias[out] = out
                else:
                    alias[out] = resolve(existing)
            continue

        if not rows0:
            alias[out] = get_const0()
            continue

        ones, zeros = parse_rows(rows0)
        if ones and not zeros:
            mode = 1
            cubes = dedup_sorted(ones)
        elif zeros and not ones:
            mode = 0
            cubes = dedup_sorted(zeros)
        elif ones and zeros:
            if len(ones) <= len(zeros):
                mode = 1
                cubes = dedup_sorted(ones)
            else:
                mode = 0
                cubes = dedup_sorted(zeros)
        else:
            alias[out] = get_const0()
            continue

        if cubes:
            dc = "-" * len(ins)
            if dc in cubes:
                fn = get_const1() if mode == 1 else get_const0()
                alias[out] = fn
                continue
        else:
            fn = get_const0() if mode == 1 else get_const1()
            alias[out] = fn
            continue

        terms = [cube_net(ins, c) for c in cubes]
        if mode == 1:
            fn = or_tree(terms)
        else:
            zf = or_tree(terms)
            fn = get_inv(zf)

        alias[out] = fn

    for po in outputs:
        src = resolve(po)
        if src == po:
            continue
        if src == get_const0():
            emit([], po, [])
            alias[po] = po
        elif src == get_const1():
            emit([], po, ["1"])
            alias[po] = po
        else:
            emit([src], po, ["1 1"])
            alias[po] = po

    with open(solution_file, "w") as f:
        f.write(f".model {model}\n")
        if inputs:
            f.write(".inputs " + " ".join(inputs) + "\n")
        else:
            f.write(".inputs\n")
        if outputs:
            f.write(".outputs " + " ".join(outputs) + "\n")
        else:
            f.write(".outputs\n")
        for p in passthrough:
            f.write(p + "\n")
        for ins, out, rows in blocks:
            if ins:
                f.write(".names " + " ".join(ins) + " " + out + "\n")
            else:
                f.write(".names " + out + "\n")
            for r in rows:
                f.write(r + "\n")
        f.write(".end\n")

