import json
import numpy as np
from collections import deque

def solve(input_file: str, solution_file: str):
    with open(input_file, 'r') as f:
        data = json.load(f)
    nodes = data['nodes']
    root_eclasses = data['root_eclasses']

    all_node_ids = list(nodes.keys())
    all_node_ids.sort()
    num_nodes = len(all_node_ids)
    node_idx = {nid: idx for idx, nid in enumerate(all_node_ids)}

    node_to_eclass = {nid: nodes[nid]['eclass'] for nid in all_node_ids}
    all_eclasses = list(set(node_to_eclass.values()))
    all_eclasses.sort()
    num_eclasses = len(all_eclasses)
    eclass_idx = {ecl: idx for idx, ecl in enumerate(all_eclasses)}

    eclass_to_nodes_list = [[] for _ in range(num_eclasses)]
    for i in range(num_nodes):
        nid = all_node_ids[i]
        ecl = node_to_eclass[nid]
        eidx = eclass_idx[ecl]
        eclass_to_nodes_list[eidx].append(i)

    node_cost_arr = np.array([nodes[all_node_ids[i]]['cost'] for i in range(num_nodes)], dtype=float)

    node_children_list = [[] for _ in range(num_nodes)]
    for i in range(num_nodes):
        nid = all_node_ids[i]
        ch_list = []
        for ch_nid in nodes[nid]['children']:
            ch_ecl = node_to_eclass[ch_nid]
            ch_list.append(eclass_idx[ch_ecl])
        node_children_list[i] = ch_list

    parent_eclasses_list = [set() for _ in range(num_eclasses)]
    for eidx in range(num_eclasses):
        for nidx in eclass_to_nodes_list[eidx]:
            seen = set()
            for ch_eidx in node_children_list[nidx]:
                if ch_eidx not in seen:
                    seen.add(ch_eidx)
                    parent_eclasses_list[ch_eidx].add(eidx)
    parent_eclasses_list = [list(s) for s in parent_eclasses_list]

    C_arr = np.full(num_eclasses, np.inf, dtype=float)

    queue = deque()
    in_queue = np.zeros(num_eclasses, dtype=bool)

    for eidx in range(num_eclasses):
        min_c = np.inf
        for nidx in eclass_to_nodes_list[eidx]:
            if not node_children_list[nidx]:
                min_c = min(min_c, node_cost_arr[nidx])
        if min_c < C_arr[eidx]:
            C_arr[eidx] = min_c
            queue.append(eidx)
            in_queue[eidx] = True

    while queue:
        eidx = queue.popleft()
        in_queue[eidx] = False
        for pidx in parent_eclasses_list[eidx]:
            new_c = np.inf
            for nidx in eclass_to_nodes_list[pidx]:
                child_cost = 0.0
                all_finite = True
                for ch_eidx in node_children_list[nidx]:
                    cc = C_arr[ch_eidx]
                    if np.isinf(cc):
                        all_finite = False
                        break
                    child_cost += cc
                if all_finite:
                    this_cost = node_cost_arr[nidx] + child_cost
                    new_c = min(new_c, this_cost)
            if new_c < C_arr[pidx]:
                C_arr[pidx] = new_c
                if not in_queue[pidx]:
                    queue.append(pidx)
                    in_queue[pidx] = True

    def get_chosen(eidx: int, visited: np.ndarray) -> int:
        min_cost = C_arr[eidx]
        if np.isinf(min_cost):
            return -1
        good_candidates = []
        bad_candidates = []
        for nidx in eclass_to_nodes_list[eidx]:
            child_cost = 0.0
            has_back = False
            for ch_eidx in node_children_list[nidx]:
                cc = C_arr[ch_eidx]
                child_cost += cc
                if visited[ch_eidx]:
                    has_back = True
            this_cost = node_cost_arr[nidx] + child_cost
            if np.isclose(this_cost, min_cost):
                if has_back:
                    bad_candidates.append(nidx)
                else:
                    good_candidates.append(nidx)
        candidates = good_candidates if good_candidates else bad_candidates
        if not candidates:
            return -1
        return min(candidates, key=lambda ni: all_node_ids[ni])

    selected_set = set()
    to_visit = deque()
    visited = np.zeros(num_eclasses, dtype=bool)
    root_idxs = [eclass_idx[r] for r in root_eclasses]
    for ridx in root_idxs:
        visited[ridx] = True
        to_visit.append(ridx)
    while to_visit:
        eidx = to_visit.popleft()
        nidx = get_chosen(eidx, visited)
        if nidx == -1:
            continue
        selected_set.add(nidx)
        for ch_eidx in node_children_list[nidx]:
            if not visited[ch_eidx]:
                visited[ch_eidx] = True
