import json
import heapq
import networkx as nx

def solve(input_file: str, solution_file: str):
    with open(input_file) as f:
        data = json.load(f)

    delay = data['delay']
    G_r = data['resource']
    nodes_list = data['nodes']
    edges = data['edges']

    G = nx.DiGraph()
    node_type = {}
    d = {}
    for nid, typ in nodes_list:
        G.add_node(nid)
        node_type[nid] = typ
        d[nid] = delay[typ]

    for src, tgt, _ in edges:
        G.add_edge(src, tgt)

    topo = list(nx.topological_sort(G))
    node_id = {n: i for i, n in enumerate(topo)}

    asap = {}
    for n in topo:
        asap[n] = max((asap[p] + d[p] for p in G.predecessors(n)), default=0)

    cp_max = max(asap[n] + d[n] for n in G)

    cp = {}
    rev_topo = list(reversed(topo))
    for n in rev_topo:
        cp[n] = d[n] + max((cp[s] for s in G.successors(n)), default=0)

    def attempt_schedule(M):
        if M is not None:
            alap = {}
            for n in rev_topo:
                succs = list(G.successors(n))
                if not succs:
                    alap[n] = M - d[n]
                else:
                    alap[n] = min(alap[s] - d[n] for s in succs)
            if any(alap[n] < asap[n] for n in G):
                return None

        remaining_preds = {n: G.in_degree(n) for n in G.nodes}
        ready_time = {n: 0 for n in G.nodes}
        unscheduled = set(G.nodes)
        scheduled = {}
        usage = {typ: [] for typ in G_r}
        ready_pq = []
        ready_set = set()

        def push_ready(n):
            if n not in ready_set:
                ready_set.add(n)
                if M is None:
                    pri = (999999999, -cp[n], node_id[n], n)
                else:
                    mob = alap[n] - asap[n]
                    pri = (mob, -cp[n], node_id[n], n)
                heapq.heappush(ready_pq, pri)

        for n in G.nodes:
            if remaining_preds[n] == 0:
                push_ready(n)

        while ready_pq:
            pri = heapq.heappop(ready_pq)
            n = pri[-1]
            ready_set.remove(n)
            if n not in unscheduled:
                continue
            t0 = max(ready_time[n], asap[n])
            r = node_type[n]
            dd = d[n]
            if M is None:
                t_max = 10**9
            else:
                t_max = alap[n]
            if t_max < t0:
                return None
            s = t0
            found = False
            while s <= t_max:
                max_c = s + dd - 1
                while len(usage[r]) <= max_c:
                    usage[r].append(0)
                can = True
                for c in range(s, s + dd):
                    if usage[r][c] >= G_r[r]:
                        can = False
                        s = c + 1
                        break
                if can:
                    found = True
                    break
            if not found:
                return None
            scheduled[n] = s
            unscheduled.remove(n)
            for c in range(s, s + dd):
                usage[r][c] += 1
            end = s + dd
            for succ in G.successors(n):
                ready_time[succ] = max(ready_time[succ], end)
                remaining_preds[succ] -= 1
                if remaining_preds[succ] == 0:
                    push_ready(succ)
        if unscheduled:
            return None
        return scheduled

    scheduled = attempt_schedule(None)
    current_M = max(scheduled[n] + d[n] for n in scheduled)
    low = cp_max
    high = current_M
    best_scheduled = scheduled
    while low <= high:
        mid = (low + high) // 2
        sched = attempt_schedule(mid)
        if sched is not None:
            best_scheduled = sched
            high = mid - 1
        else:
            low = mid + 1

    with open(solution_file, 'w') as f:
        for nid in sorted(best_scheduled):
            f.write(f"{nid}:{best_scheduled[nid]}\n")

