import numpy as np
from collections import defaultdict
from itertools import product

def solve(input_file: str, solution_file: str):
    lines = open(input_file).readlines()
    individuals = set()
    input_order = []
    father = {}
    mother = {}
    observed = {}
    alleles_set = set()
    for line in lines:
        parts = line.strip().split()
        if not parts:
            continue
        loc, ID, fID, mID, sx, al1, al2 = parts
        id = int(ID)
        f = int(fID)
        m = int(mID)
        a1i = int(al1)
        a2i = int(al2)
        individuals.add(id)
        input_order.append(id)
        father[id] = f
        mother[id] = m
        observed[id] = (a1i, a2i)
        if a1i > 0:
            alleles_set.add(a1i)
        if a2i > 0:
            alleles_set.add(a2i)
    if alleles_set:
        n = max(alleles_set)
    else:
        n = 1
    geno_list = [(a, b) for a in range(1, n + 1) for b in range(a, n + 1)]
    num_geno = len(geno_list)
    geno_to_idx = {g: i for i, g in enumerate(geno_list)}
    cost = {}
    for id in individuals:
        obs1, obs2 = observed[id]
        cost_arr = np.full(num_geno, 1.0)
        if obs1 == 0 and obs2 == 0:
            cost_arr[:] = 0.0
        elif obs1 > 0 and obs2 == 0:
            c = obs1
            for gi, (a, b) in enumerate(geno_list):
                if c == a or c == b:
                    cost_arr[gi] = 0.0
        elif obs2 > 0 and obs1 == 0:
            c = obs2
            for gi, (a, b) in enumerate(geno_list):
                if c == a or c == b:
                    cost_arr[gi] = 0.0
        else:
            c, d = min(obs1, obs2), max(obs1, obs2)
            if (c, d) in geno_to_idx:
                gi = geno_to_idx[(c, d)]
                cost_arr[gi] = 0.0
        cost[id] = cost_arr
    family_children = defaultdict(list)
    family_parents = {}
    for id in individuals:
        f = father.get(id, 0)
        m = mother.get(id, 0)
        ps = [p for p in (f, m) if p > 0 and p in individuals]
        if ps:
            key = tuple(sorted(ps))
            family_children[key].append(id)
            if key not in family_parents:
                family_parents[key] = list(sorted(ps))
    factors = []
    for id in individuals:
        factors.append({'vars': [id], 'table': cost[id].copy().astype(float)})
    parent_children = defaultdict(list)
    for id in individuals:
        f = father.get(id, 0)
        if f in individuals:
            parent_children[f].append(id)
        m = mother.get(id, 0)
        if m in individuals:
            parent_children[m].append(id)
    for p in parent_children:
        for c in parent_children[p]:
            table = np.full((num_geno, num_geno), 0.0)
            for gx in range(num_geno):
                set_p = set(geno_list[gx])
                for gy in range(num_geno):
                    set_c = set(geno_list[gy])
                    if set_p.isdisjoint(set_c):
                        table[gx, gy] = np.inf
            factors.append({'vars': sorted([p, c]), 'table': table})
    for key in family_parents:
        if len(family_parents[key]) == 2:
            j, k = family_parents[key]
            for i in family_children[key]:
                table = np.full((num_geno, num_geno, num_geno), 0.0)
                for gx in range(num_geno):
                    set_j = set(geno_list[gx])
                    for gy in range(num_geno):
                        set_k = set(geno_list[gy])
                        for gz in range(num_geno):
                            a, b = geno_list[gz]
                            if not ((a in set_j and b in set_k) or (a in set_k and b in set_j)):
                                table[gx, gy, gz] = np.inf
                factors.append({'vars': sorted([j, k, i]), 'table': table})
    graph = defaultdict(set)
    for f in factors:
        vs = f['vars']
        for ii in range(len(vs)):
            for jj in range(ii + 1, len(vs)):
                u = vs[ii]
                v = vs[jj]
                graph[u].add(v)
                graph[v].add(u)
    remaining = set(individuals)
    elim_order = []
    graph_copy = {u: set(graph[u]) for u in graph}
    while remaining:
        min_fill = np.inf
        best_u = None
        for u in remaining:
            neigh = [v for v in graph_copy[u] if v in remaining]
            num_neigh = len(neigh)
            if num_neigh < 2:
                fill = 0
            else:
                existing = 0
                for i in range(num_neigh):
                    for j in range(i + 1, num_neigh):
                        if neigh[j] in graph_copy[neigh[i]]:
                            existing += 1
                fill = num_neigh * (num_neigh - 1) // 2 - existing
            if fill < min_fill or (fill == min_fill and (best_u is None or u < best_u)):
                min_fill = fill
                best_u = u
        elim_order.append(best_u)
        neigh = [v for v in graph_copy[best_u] if v in remaining]
        for i in range(len(neigh)):
            for j in range(i + 1, len(neigh)):
                a = neigh[i]
                b = neigh[j]
                graph_copy[a].add(b)
                graph_copy[b].add(a)
        for v in neigh:
            graph_copy[v].remove(best_u)
        del graph_copy[best_u]
        remaining.remove(best_u)
    best_choice = {}
    current_factors = list(factors)
    for elim_var in elim_order:
        collected = [f for f in current_factors if elim_var in f['vars']]
        current_factors = [f for f in current_factors if elim_var not in f['vars']]
        sep_set = set()
        for f in collected:
            sep_set.update(f['vars'])
        sep_set.discard(elim_var)
        sep = sorted(sep_set)
        num_sep = len(sep)
        var_to_pos = {sep[i]: i for i in range(num_sep)}
        if num_sep > 0:
            shape = tuple(num_geno for _ in sep)
            new_table = np.full(shape, np.inf)
            best_xv_arr = np.full(shape, -1, dtype=int)
            for tuple_sep in product(range(num_geno), repeat=num_sep):
                costs = np.zeros(num_geno)
                for f in collected:
                    axis = f['vars'].index(elim_var)
                    fixed_indices = [tuple_sep[var_to_pos[vv]] for vv in f['vars'] if vv != elim_var]
                    sl = [slice(None)] * len(f['vars'])
                    fi_idx = 0
                    for j in range(len(f['vars'])):
                        if j != axis:
                            sl[j] = fixed_indices[fi_idx]
                            fi_idx += 1
                    val_arr = f['table'][tuple(sl)]
                    costs += val_arr
                finite = np.isfinite(costs)
                if np.any(finite):
                    idx = np.argmin(costs[finite])
                    min_total = costs[finite][idx]
                    best_xv = np.where(finite)[0][idx]
                    t_key = tuple(tuple_sep)
                    new_table[t_key] = min_total
                    best_xv_arr[t_key] = best_xv
            current_factors.append({'vars': sep, 'table': new_table})
            best_choice[elim_var] = {'sep': sep, 'table': best_xv_arr}
        else:
            costs = np.zeros(num_geno)
            for f in collected:
                axis = f['vars'].index(elim_var)
                fixed_indices = []
                sl = [slice(None)] * len(f['vars'])
                fi_idx = 0
                for j in range(len(f['vars'])):
                    if j != axis:
                        sl[j] = fixed_indices[fi_idx]
                        fi_idx += 1
                val_arr = f['table'][tuple(sl)]
                costs += val_arr
            finite = np.isfinite(costs)
            if np.any(finite):
                idx = np.argmin(costs[finite])
                min_total = costs[finite][idx]
                best_last_xv = np.where(finite)[0][idx]
                best_choice[elim_var] = {'sep': [], 'table': best_last_xv}
            else:
                with open(solution_file, 'w') as out:
                    out.write(' '.join(['0'] * len(input_order)) + '\n')
                return
    assign = {}
    for var in reversed(elim_order):
        bc = best_choice[var]
        sep = bc['sep']
        if sep:
            t_sep = tuple(assign[vv] for vv in sep)
            xv = bc['table'][t_sep]
        else:
            xv = bc['table']
        assign[var] = xv
    with open(solution_file, 'w') as out:
        out.write(' '.join(str(assign[id]) for id in input_order) + '\n')

