import networkx
from itertools import product

def solve(input_file: str, solution_file: str):
    with open(input_file, 'r') as f:
        lines = [line.strip() for line in f.readlines() if not line.strip().startswith('#') and line.strip()]

    i = 0
    model = None
    inputs = []
    outputs = []
    gates = {}
    while i < len(lines):
        line = lines[i]
        if line.startswith('.model'):
            model = line.split()[1]
            i += 1
            continue
        elif line.startswith('.inputs'):
            parts = line.split()[1:]
            i += 1
            while i < len(lines) and lines[i-1].endswith('\\'):
                line = lines[i].strip()
                parts.extend(line.split())
                i += 1
            inputs = parts
            continue
        elif line.startswith('.outputs'):
            parts = line.split()[1:]
            i += 1
            while i < len(lines) and lines[i-1].endswith('\\'):
                line = lines[i].strip()
                parts.extend(line.split())
                i += 1
            outputs = parts
            continue
        elif line.startswith('.names'):
            parts = line.split()[1:]
            fanins = parts[:-1]
            out = parts[-1]
            rows = []
            i += 1
            while i < len(lines) and not lines[i].startswith('.'):
                row = lines[i].strip()
                if row:
                    rows.append(row)
                i += 1
            gates[out] = (fanins, rows)
            continue
        elif line.startswith('.end'):
            break
        i += 1

    all_nodes = set(inputs) | set(gates.keys())
    G = networkx.DiGraph()
    for node in all_nodes:
        G.add_node(node)
    for out, (fanins, _) in gates.items():
        for fi in fanins:
            G.add_edge(fi, out)

    global_new_id = 0
    def new_name():
        nonlocal global_new_id
        global_new_id += 1
        return f'new_n{global_new_id}'

    to_decompose = [out for out, (fanins, rows) in gates.items() if len(fanins) > 6]
    for out in to_decompose:
        fanins, rows = gates[out]
        m = len(fanins)
        if len(rows) != 1:
            raise ValueError("Large gate not single row")
        row = rows[0]
        parts = row.split()
        if len(parts) not in (1, 2):
            raise ValueError("Invalid row for large gate")
        input_plane = parts[0]
        if len(input_plane) != m:
            raise ValueError("Input plane length mismatch")
        out_bit = parts[1] if len(parts) == 2 else None
        is_and = all(c == '1' for c in input_plane) and (out_bit is None or out_bit == '1')
        is_nand = all(c == '1' for c in input_plane) and out_bit == '0'
        is_or = all(c == '0' for c in input_plane) and out_bit == '0'
        if not (is_and or is_nand or is_or):
            raise ValueError("Large gate not AND, NAND or OR")
        for fi in fanins:
            if G.has_edge(fi, out):
                G.remove_edge(fi, out)
        signals = list(fanins)
        previous = None
        while signals:
            if previous is None:
                num_take = min(6, len(signals))
            else:
                num_take = min(5, len(signals))
            group = signals[:num_take]
            signals = signals[num_take:]
            inputs_ = group if previous is None else [previous] + group
            if not signals:
                new_out = out
            else:
                new_out = new_name()
            if is_and or is_or:
                new_rows = ['0' * len(inputs_) + ' 0'] if is_or else ['1' * len(inputs_) + ' 1']
            else:  # is_nand
                new_rows = ['1' * len(inputs_) + ' 0']
            gates[new_out] = (inputs_, new_rows)
            for inp in inputs_:
                G.add_edge(inp, new_out)
            G.add_node(new_out)
            previous = new_out

    tt = {}
    for out, (fanins, rows) in gates.items():
        m = len(fanins)
        if m == 0:
            if rows and rows[0] == '1':
                truth = 1
            else:
                truth = 0
        else:
            has_zero = any(len(row.split()) == 2 and row.split()[-1] == '0' for row in rows)
            if has_zero:
                truth = (1 << (1 << m)) - 1
                polarity = 0
            else:
                truth = 0
                polarity = 1
            for row in rows:
                parts = row.split()
                if len(parts) not in (1, 2):
                    raise ValueError("Invalid row")
                input_plane = parts[0]
                if len(input_plane) != m:
                    raise ValueError("Input plane length mismatch")
                cube = list(input_plane)
                if len(parts) == 1:
                    row_polarity = 1
                else:
                    row_polarity = int(parts[1])
                dc_pos = [j for j, lit in enumerate(cube) if lit == '-']
                num_dc = len(dc_pos)
                for k in range(1 << num_dc):
                    minterm = 0
                    for j in range(m):
                        lit = cube[j]
                        if lit == '-':
                            bit = (k >> dc_pos.index(j)) & 1
                            minterm |= bit << j
                        elif lit == '1':
                            minterm |= 1 << j
                    if polarity == 1:
                        truth |= (1 << minterm) if row_polarity == 1 else 0
                    else:
                        truth &= ~(1 << minterm) if row_polarity == 0 else ~0
        tt[out] = (fanins, truth, m)

    topo = list(networkx.topological_sort(G))
    pis = [n for n in G if G.in_degree(n) == 0]
    cuts = {}
    for v in topo:
        if G.in_degree(v) == 0:
            cuts[v] = []
            continue
        fanins = list(G.predecessors(v))
        fanin_choices = []
        for u in fanins:
            choices = [{u}] + cuts[u]
            fanin_choices.append(choices)
        v_cuts = set()
        for combo in product(*fanin_choices):
            cut_set = set()
            for s in combo:
                cut_set.update(s)
            if len(cut_set) <= 6:
                v_cuts.add(frozenset(cut_set))
        cuts[v] = [set(fs) for fs in v_cuts]

    fanout = dict(G.out_degree())
    af = {}
    best_cut = {}
    for v in topo:
        if G.in_degree(v) == 0:
            af[v] = 0.0
            continue
        min_af = float('inf')
        best_c = None
        for C in cuts[v]:
            current = sum(af.get(u, 0.0) for u in C)
            if current < min_af:
                min_af = current
                best_c = C
        af[v] = (min_af + 1) / max(1, fanout.get(v, 0))
        best_cut[v] = best_c

    lut_roots = set()
    def map_node(r):
        if r in pis or r in lut_roots:
            return
        C = best_cut[r]
        for u in C:
            map_node(u)
        lut_roots.add(r)

    for po in outputs:
        if po in pis:
            continue
        map_node(po)

    with open(solution_file, 'w') as f:
        f.write(f'.model {model}\n')
        f.write('.inputs ' + ' '.join(inputs) + '\n')
        f.write('.outputs ' + ' '.join(outputs) + '\n')
        for root in sorted(lut_roots):
            C = best_cut[root]
            input_list = sorted(C)
            p = len(input_list)
            cut_index = {node: idx for idx, node in enumerate(input_list)}
            cone = set()
            visited = set()
            to_visit = [root]
            while to_visit:
                curr = to_visit.pop()
                if curr in visited:
                    continue
                visited.add(curr)
                if curr in C:
                    continue
                cone.add(curr)
                for pred in G.predecessors(curr):
                    to_visit.append(pred)
            cone_topo = [n for n in topo if n in cone]
            truth = 0
            for mask in range(1 << p):
                values = {}
                for i, u in enumerate(input_list):
                    values[u] = (mask >> i) & 1
                for n in cone_topo:
                    fanins_n, _ = gates[n]
                    _, truth_n, _ = tt[n]
                    input_bits = 0
                    for j, fi in enumerate(fanins_n):
                        input_bits |= values[fi] << j
                    values[n] = (truth_n >> input_bits) & 1
