            num_zeros = (1 << p) - num_ones
            if p == 0:
                if truth == 1:
                    f.write(f'.names {root}\n1\n')
                else:
                    f.write(f'.names {root}\n')
                continue
            if num_zeros < num_ones:
                polarity = 0
                target = 0
            else:
                polarity = 1
                target = 1
            f.write('.names ' + ' '.join(input_list) + ' ' + root + '\n')
            for mask in range(1 << p):
                out_bit = (truth >> mask) & 1
                if out_bit == target:
                    input_str = ''.join('1' if (mask >> j) & 1 else '0' for j in range(p))
                    if polarity == 1:
                        f.write(input_str + '\n')
                    else:
                        f.write(input_str + ' 0\n')
        f.write('.end\n')

