def solve(input_file: str, solution_file: str):
    import json
    from collections import defaultdict, deque

    with open(input_file, 'r') as f:
        data = json.load(f)

    nodes_data = data['nodes']
    root_eclasses = data['root_eclasses']

    node_cost = {}
    node_eclass = {}
    node_children = {}

    for nid, info in nodes_data.items():
        node_cost[nid] = info['cost']
        node_eclass[nid] = info['eclass']
        node_children[nid] = info['children']

    eclass_nodes = defaultdict(list)
    for nid, ec in node_eclass.items():
        eclass_nodes[ec].append(nid)

    all_eclasses = list(eclass_nodes.keys())
    n_eclasses = len(all_eclasses)
    eclass_to_idx = {ec: i for i, ec in enumerate(all_eclasses)}

    node_child_ecs = {}
    for nid, ch in node_children.items():
        node_child_ecs[nid] = [eclass_to_idx[node_eclass[c]] for c in ch]

    # Build e-class dependency graph
    ec_graph = [set() for _ in range(n_eclasses)]
    for nid, ec in node_eclass.items():
        u = eclass_to_idx[ec]
        for v in node_child_ecs[nid]:
            ec_graph[u].add(v)

    # Check if DAG using Kahn's algorithm
    in_deg = [0] * n_eclasses
    for u in range(n_eclasses):
        for v in ec_graph[u]:
            in_deg[v] += 1

    q = deque([i for i in range(n_eclasses) if in_deg[i] == 0])
    topo = []
    temp_in_deg = in_deg[:]
    while q:
        u = q.popleft()
        topo.append(u)
        for v in ec_graph[u]:
            temp_in_deg[v] -= 1
            if temp_in_deg[v] == 0:
                q.append(v)

    is_dag = len(topo) == n_eclasses

    INF = 1e100

    if is_dag:
        # DP on DAG in reverse topological order
        dp = [INF] * n_eclasses
        choice = [None] * n_eclasses

        for u in reversed(topo):
            best_cost = INF
            best_node = None
            ec_name = all_eclasses[u]
            for nid in eclass_nodes[ec_name]:
                c = node_cost[nid]
                for v in node_child_ecs[nid]:
                    c += dp[v]
                if c < best_cost:
                    best_cost = c
                    best_node = nid
            dp[u] = best_cost
            choice[u] = best_node

        # Extract solution
        selected = []
        done = [False] * n_eclasses

        def extract_dag(u):
            if done[u]:
                return
            nid = choice[u]
            selected.append(nid)
            done[u] = True
            for v in node_child_ecs[nid]:
                if not done[v]:
                    extract_dag(v)

        for root_str in root_eclasses:
            ri = eclass_to_idx[root_str]
            extract_dag(ri)
    else:
        # Iterative DP for cyclic graphs
        dp = [INF] * n_eclasses
        for i, ec in enumerate(all_eclasses):
            min_c = INF
            for nid in eclass_nodes[ec]:
                if node_cost[nid] < min_c:
                    min_c = node_cost[nid]
            dp[i] = min_c

        for _ in range(100):
            changed = False
            for i, ec in enumerate(all_eclasses):
                for nid in eclass_nodes[ec]:
                    c = node_cost[nid]
                    for ce in node_child_ecs[nid]:
                        c += dp[ce]
                    if c < dp[i] - 1e-9:
                        dp[i] = c
                        changed = True
            if not changed:
                break

        # Sort nodes by cost for each e-class
        ec_sorted = []
        for i, ec in enumerate(all_eclasses):
            arr = []
            for nid in eclass_nodes[ec]:
                c = node_cost[nid]
                for ce in node_child_ecs[nid]:
                    c += dp[ce]
                arr.append((c, nid))
            arr.sort()
            ec_sorted.append([n for _, n in arr])

        selected = []
        done = [False] * n_eclasses

        # Iterative extraction with explicit stack
        for root_str in root_eclasses:
            ri = eclass_to_idx[root_str]
            if done[ri]:
                continue

            # Try each node in this e-class
            for start_nid in ec_sorted[ri]:
                stack = [(ri, start_nid, 0)]  # (ec_idx, node_id, state) state: 0=enter, 1=exit
                in_stack = [False] * n_eclasses
                temp_selected = []
                valid = True

                while stack and valid:
                    ec_idx, nid, state = stack.pop()

                    if state == 1:
                        in_stack[ec_idx] = False
                        continue

                    if done[ec_idx]:
                        continue

                    if in_stack[ec_idx]:
                        valid = False
                        break

                    in_stack[ec_idx] = True
                    temp_selected.append((ec_idx, nid))
                    stack.append((ec_idx, nid, 1))

                    # Check children
                    for ce in node_child_ecs[nid]:
                        if in_stack[ce]:
                            valid = False
                            break
                        if not done[ce]:
                            # Try to pick a node for this child
                            found = False
                            for cnid in ec_sorted[ce]:
                                stack.append((ce, cnid, 0))
                                found = True
                                break
                            if not found:
                                valid = False
                                break

                    if not valid:
                        break

                if valid:
                    for ec_idx, nid in temp_selected:
                        if not done[ec_idx]:
                            done[ec_idx] = True
                            selected.append(nid)
                    break

    with open(solution_file, 'w') as f:
        json.dump(selected, f)

