import json
import time
import random
import heapq

def solve(input_file: str, solution_file: str):
    start_time = time.time()
    time_limit = 9.5

    with open(input_file, 'r') as f:
        data = json.load(f)

    problem = data['problem']
    usage_limit = problem['usage_limit']

    nodes_data = problem['nodes']
    edges_data = problem['edges']

    n = len(nodes_data['intervals'])

    intervals = [(nodes_data['intervals'][i][0], nodes_data['intervals'][i][1]) for i in range(n)]
    node_costs = nodes_data['costs']
    node_usages = nodes_data['usages']
    num_strats = [len(c) for c in node_costs]

    edge_nodes = edges_data['nodes']
    edge_costs = edges_data['costs']

    edge_dict = {}
    for idx, (i, j) in enumerate(edge_nodes):
        costs = edge_costs[idx]
        key = (i, j)
        if key in edge_dict:
            old = edge_dict[key]
            for k in range(len(old)):
                old[k] += costs[k]
        else:
            edge_dict[key] = costs[:]

    adj = [[] for _ in range(n)]
    node_degree = [0] * n
    for (i, j), costs in edge_dict.items():
        l_j = num_strats[j]
        adj[i].append((j, costs, l_j, True))
        adj[j].append((i, costs, l_j, False))
        node_degree[i] += 1
        node_degree[j] += 1

    time_points = set()
    for l, r in intervals:
        if l < r:
            time_points.add(l)
            time_points.add(r)

    skip_memory = len(time_points) == 0
    time_to_idx = {}

    if not skip_memory:
        sorted_times = sorted(time_points)
        time_to_idx = {t: i for i, t in enumerate(sorted_times)}
        m = len(sorted_times)
        seg_size = 1
        while seg_size < m:
            seg_size <<= 1
        seg_tree = [0] * (2 * seg_size)
        seg_lazy = [0] * (2 * seg_size)

        def seg_apply(idx, val):
            seg_tree[idx] += val
            seg_lazy[idx] += val

        def seg_push(idx):
            if seg_lazy[idx] and idx < seg_size:
                v = seg_lazy[idx]
                seg_apply(idx<<1, v)
                seg_apply(idx<<1|1, v)
                seg_lazy[idx] = 0

        def seg_add_range(l, r, val, idx=1, nl=0, nr=None):
            if nr is None:
                nr = seg_size
            if r <= nl or nr <= l:
                return
            if l <= nl and nr <= r:
                seg_apply(idx, val)
                return
            seg_push(idx)
            mid = (nl + nr) >> 1
            seg_add_range(l, r, val, idx<<1, nl, mid)
            seg_add_range(l, r, val, idx<<1|1, mid, nr)
            left = seg_tree[idx<<1]
            right = seg_tree[idx<<1|1]
            seg_tree[idx] = left if left >= right else right

        def seg_query():
            return seg_tree[1]

        def seg_reset():
            for i in range(2 * seg_size):
                seg_tree[i] = 0
                seg_lazy[i] = 0
    else:
        def seg_add_range(l, r, val, idx=1, nl=0, nr=None):
            pass
        def seg_query():
            return 0
        def seg_reset():
            pass

    sol = [0] * n

    def build_from_solution():
        seg_reset()
        for i in range(n):
            l, r = intervals[i]
            if l < r and not skip_memory:
                li = time_to_idx[l]
                ri = time_to_idx[r]
                seg_add_range(li, ri, node_usages[i][sol[i]])

    def compute_cost():
        cost = 0
        for i in range(n):
            cost += node_costs[i][sol[i]]
        for (i, j), costs in edge_dict.items():
            idx = sol[i] * num_strats[j] + sol[j]
            cost += costs[idx]
        return cost

    def check_and_apply_memory(i, old_s, new_s, apply=False):
        if skip_memory:
            return True
        old_u = node_usages[i][old_s]
        new_u = node_usages[i][new_s]
        if old_u == new_u:
            return True
        l, r = intervals[i]
        if l >= r:
            return True
        li = time_to_idx[l]
        ri = time_to_idx[r]
        diff = new_u - old_u
        if apply:
            seg_add_range(li, ri, diff)
            return True
        else:
            seg_add_range(li, ri, diff)
            feasible = seg_query() <= usage_limit
            seg_add_range(li, ri, -diff)
            return feasible

    def greedy_init():
        order = sorted(range(n), key=lambda x: -node_degree[x])
        assigned = [False] * n

        for i in order:
            best_s = 0
            best_cost = float('inf')

            for s in range(num_strats[i]):
                node_c = node_costs[i][s]
                edge_c = 0
                for (j, costs, l_j, is_pred) in adj[i]:
                    if assigned[j]:
                        if is_pred:
                            idx = s * l_j + sol[j]
                        else:
                            idx = sol[j] * l_j + s
                        edge_c += costs[idx]

                if node_c + edge_c < best_cost:
                    if check_and_apply_memory(i, sol[i], s, apply=False):
                        best_cost = node_c + edge_c
                        best_s = s

            sol[i] = best_s
            assigned[i] = True
            check_and_apply_memory(i, 0, best_s, apply=True)

    def min_usage_init():
        for i in range(n):
            min_u = min(node_usages[i])
            for s in range(num_strats[i]):
                if node_usages[i][s] == min_u:
                    sol[i] = s
                    break
        build_from_solution()

    def min_cost_init():
        for i in range(n):
            min_c = min(node_costs[i])
            for s in range(num_strats[i]):
                if node_costs[i][s] == min_c:
                    sol[i] = s
                    break
        build_from_solution()

    def local_search_best_improvement(max_iters):
        improved = True
        it = 0
        while improved and it < max_iters:
            improved = False
            it += 1
            if time.time() - start_time > time_limit:
                break

            nodes_order = list(range(n))
            random.shuffle(nodes_order)

            for i in nodes_order:
                if num_strats[i] <= 1:
                    continue

                cur_s = sol[i]
                cur_cost = node_costs[i][cur_s]

                for (j, costs, l_j, is_pred) in adj[i]:
                    if is_pred:
                        cur_cost += costs[cur_s * l_j + sol[j]]
                    else:
                        cur_cost += costs[sol[j] * l_j + cur_s]

                best_delta = 0
                best_s = cur_s

                for s in range(num_strats[i]):
                    if s == cur_s:
                        continue

                    new_cost = node_costs[i][s]
                    for (j, costs, l_j, is_pred) in adj[i]:
                        if is_pred:
                            new_cost += costs[s * l_j + sol[j]]
                        else:
                            new_cost += costs[sol[j] * l_j + s]

                    delta = new_cost - cur_cost

                    if delta < best_delta:
                        if check_and_apply_memory(i, cur_s, s, apply=False):
                            best_delta = delta
                            best_s = s

                if best_s != cur_s:
                    check_and_apply_memory(i, cur_s, best_s, apply=True)
                    sol[i] = best_s
                    improved = True

    def local_search_first_improvement(max_iters):
        for it in range(max_iters):
            if time.time() - start_time > time_limit:
                break

            nodes_order = list(range(n))
            random.shuffle(nodes_order)

            for i in nodes_order:
                if num_strats[i] <= 1:
                    continue

                cur_s = sol[i]

                for s in range(num_strats[i]):
                    if s == cur_s:
                        continue

                    delta = node_costs[i][s] - node_costs[i][cur_s]

                    for (j, costs, l_j, is_pred) in adj[i]:
                        if is_pred:
                            old_idx = cur_s * l_j + sol[j]
                            new_idx = s * l_j + sol[j]
                        else:
                            old_idx = sol[j] * l_j + cur_s
                            new_idx = sol[j] * l_j + s
                        delta += costs[new_idx] - costs[old_idx]

                    if delta < 0:
                        if check_and_apply_memory(i, cur_s, s, apply=False):
                            check_and_apply_memory(i, cur_s, s, apply=True)
                            sol[i] = s
                            break

    best_sol = [0] * n
    best_cost = float('inf')

    inits = [min_usage_init, min_cost_init]
    if n < 2000:
        inits.append(greedy_init)

    for init_func in inits:
        if time.time() - start_time > time_limit * 0.8:
            break

        init_func()
        current_cost = compute_cost()

        if current_cost < best_cost:
            best_cost = current_cost
            best_sol = sol[:]

        if n < 1000:
            local_search_best_improvement(50)
        else:
            local_search_first_improvement(10000)

        current_cost = compute_cost()
        if current_cost < best_cost:
            best_cost = current_cost
            best_sol = sol[:]

    if best_cost == float('inf'):
        min_usage_init()
        best_sol = sol[:]

    with open(solution_file, 'w') as f:
        f.write('[' + ','.join(map(str, best_sol)) + ']')

