def solve(input_file: str, solution_file: str):
    import json
    from collections import defaultdict, deque

    with open(input_file, 'r') as f:
        data = json.load(f)

    delays = data['delay']
    res_caps = data['resource']
    nodes_data = data['nodes']
    edges_data = data['edges']

    node_delay = {}
    node_type = {}
    nodes = []

    for nid, rtype in nodes_data:
        nodes.append(nid)
        node_delay[nid] = delays[rtype]
        node_type[nid] = rtype

    n = len(nodes)

    # Build adjacency lists
    preds = defaultdict(list)
    succs = defaultdict(list)

    for src, dst, _ in edges_data:
        preds[dst].append(src)
        succs[src].append(dst)

    # Compute ASAP using topological sort
    remaining_in_degree = defaultdict(int)
    for v in nodes:
        remaining_in_degree[v] = len(preds[v])

    topo_order = []
    queue = deque([v for v in nodes if remaining_in_degree[v] == 0])

    while queue:
        v = queue.popleft()
        topo_order.append(v)
        for s in succs[v]:
            remaining_in_degree[s] -= 1
            if remaining_in_degree[s] == 0:
                queue.append(s)

    # Compute ASAP
    asap = {}
    for v in topo_order:
        if not preds[v]:
            asap[v] = 0
        else:
            asap[v] = max(asap[p] + node_delay[p] for p in preds[v])

    # Compute ALAP (with large upper bound)
    ub_init = max(asap[v] + node_delay[v] for v in nodes) * 2 + 10
    alap = {}
    for v in reversed(topo_order):
        if not succs[v]:
            alap[v] = ub_init - node_delay[v]
        else:
            alap[v] = min(alap[s] for s in succs[v]) - node_delay[v]

    def list_schedule(priority_key):
        usage = {}
        start = {}
        scheduled = set()

        def is_ready(v):
            return all(p in scheduled for p in preds[v])

        def find_earliest(v):
            rtype = node_type[v]
            delay = node_delay[v]
            cap = res_caps[rtype]
            t = 0
            for p in preds[v]:
                t = max(t, start[p] + node_delay[p])
            while True:
                valid = True
                for dt in range(delay):
                    if usage.get((t + dt, rtype), 0) >= cap:
                        valid = False
                        break
                if valid:
                    return t
                t += 1

        remaining = set(nodes)

        while remaining:
            ready_nodes = [v for v in remaining if is_ready(v)]
            if not ready_nodes:
                break

            ready_nodes.sort(key=priority_key)
            v = ready_nodes[0]

            t = find_earliest(v)
            start[v] = t
            rtype = node_type[v]
            for dt in range(node_delay[v]):
                usage[(t + dt, rtype)] = usage.get((t + dt, rtype), 0) + 1

            scheduled.add(v)
            remaining.remove(v)

        return start

    # Try multiple priority schemes and pick the best
    best_sched = None
    best_cost = float('inf')

    schemes = [
        lambda v: (alap[v], asap[v]),  # Most urgent first
        lambda v: (alap[v] - asap[v], asap[v]),  # Smallest mobility
        lambda v: (-asap[v], alap[v]),  # Critical path first
        lambda v: (alap[v], -node_delay[v]),  # ALAP then longest op
    ]

    for scheme in schemes:
        sched = list_schedule(scheme)
        cost = max(sched[v] + node_delay[v] for v in nodes)
        if cost < best_cost:
            best_cost = cost
            best_sched = sched

    # For small graphs, try iterative refinement
    if n <= 50:
        # Try to improve using binary search on latency limit
        cp_lb = max(asap[v] + node_delay[v] for v in nodes)

        def try_limit(L):
            # Recompute ALAP with tighter limit
            new_alap = {}
            for v in reversed(topo_order):
                if not succs[v]:
                    new_alap[v] = L - node_delay[v]
                else:
                    new_alap[v] = min(new_alap[s] for s in succs[v]) - node_delay[v]
                if new_alap[v] < asap[v]:
                    return None

            # Schedule with this ALAP
            sched = list_schedule(lambda v: (new_alap[v], asap[v]))
            cost = max(sched[v] + node_delay[v] for v in nodes)
            return sched if cost <= L else None

        lo, hi = cp_lb, best_cost
        while lo < hi:
            mid = (lo + hi) // 2
            sched = try_limit(mid)
            if sched is not None:
                best_sched = sched
                best_cost = mid
                hi = mid
            else:
                lo = mid + 1

    # Write output
    with open(solution_file, 'w') as f:
        for v in sorted(best_sched.keys()):
            f.write(f"{v}:{best_sched[v]}\n")

