import numpy as np
from collections import defaultdict

def solve(input_file: str, solution_file: str):
    # Parse input
    with open(input_file, 'r') as f:
        lines = [line.strip() for line in f if line.strip()]

    records = []
    all_ids = set()
    max_allele = 0
    for line in lines:
        parts = line.split()
        if len(parts) != 7:
            continue
        locus, id_s, fid_s, mid_s, sex, a1_s, a2_s = parts
        id_val = int(id_s)
        fid_val = int(fid_s)
        mid_val = int(mid_s)
        a1 = int(a1_s)
        a2 = int(a2_s)
        records.append((id_val, fid_val, mid_val, a1, a2))
        all_ids.add(id_val)
        max_allele = max(max_allele, a1, a2)

    # Map IDs to 0..m-1
    ids = sorted(all_ids)
    id_map = {v: i for i, v in enumerate(ids)}
    m = len(ids)

    # Setup pedigree
    father = [-1] * m
    mother = [-1] * m
    obs_a1 = [0] * m
    obs_a2 = [0] * m

    for id_val, fid, mid, a1, a2 in records:
        i = id_map[id_val]
        if fid != 0:
            father[i] = id_map[fid]
        if mid != 0:
            mother[i] = id_map[mid]
        obs_a1[i] = a1
        obs_a2[i] = a2

    n_alleles = max_allele
    # Generate all genotypes (a,b) with 1 <= a <= b <= n_alleles
    genotypes = [(a, b) for a in range(1, n_alleles + 1) for b in range(a, n_alleles + 1)]
    gt_to_idx = {g: i for i, g in enumerate(genotypes)}
    N = len(genotypes)

    # Compute unary costs
    unary_costs = []
    for i in range(m):
        a1, a2 = obs_a1[i], obs_a2[i]
        costs = np.zeros(N, dtype=np.int32)
        for gi, (a, b) in enumerate(genotypes):
            if a1 == 0 and a2 == 0:
                costs[gi] = 0
            elif a1 == 0 or a2 == 0:
                c = a1 if a1 != 0 else a2
                costs[gi] = 0 if (a == c or b == c) else 1
            else:
                obs_set = frozenset([a1, a2])
                gt_set = frozenset([a, b])
                costs[gi] = 0 if obs_set == gt_set else 1
        unary_costs.append(costs)

    # Determine which method to use
    num_with_parents = sum(1 for i in range(m) if father[i] != -1 and mother[i] != -1)

    if m <= 25 and num_with_parents <= 15:
        assignment = exact_elimination(m, N, genotypes, gt_to_idx, unary_costs, father, mother)
    else:
        # Use faster local search for larger problems
        assignment = fast_local_search(m, N, genotypes, gt_to_idx, unary_costs, father, mother, 
                                       time_limit=9.0)

    # Write output
    result = [str(assignment[i]) for i in range(m)]
    with open(solution_file, 'w') as f:
        f.write(' '.join(result))


def exact_elimination(m, N, genotypes, gt_to_idx, unary_costs, father, mother):
    """Exact variable elimination for small pedigrees"""

    factors = []

    # Unary factors
    for i in range(m):
        factor_dict = {(gi,): int(unary_costs[i][gi]) for gi in range(N)}
        factors.append(([i], factor_dict))

    # Ternary factors
    for i in range(m):
        if father[i] != -1 and mother[i] != -1:
            j = father[i]
            k = mother[i]
            factor_dict = {}
            for gj, (aj1, aj2) in enumerate(genotypes):
                alleles_j = [aj1, aj2]
                for gk, (ak1, ak2) in enumerate(genotypes):
                    alleles_k = [ak1, ak2]
                    seen = set()
                    for allele_j in alleles_j:
                        for allele_k in alleles_k:
                            if allele_j <= allele_k:
                                child_gt = (allele_j, allele_k)
                            else:
                                child_gt = (allele_k, allele_j)
                            if child_gt not in seen:
                                seen.add(child_gt)
                                gi = gt_to_idx[child_gt]
                                factor_dict[(gj, gk, gi)] = 0
            factors.append(([j, k, i], factor_dict))

    # Build moral graph
    adj = [set() for _ in range(m)]
    for vars_list, _ in factors:
        for i in range(len(vars_list)):
            for j in range(i + 1, len(vars_list)):
                adj[vars_list[i]].add(vars_list[j])
                adj[vars_list[j]].add(vars_list[i])

    # Min-degree ordering
    order = []
    degree = [len(adj[i]) for i in range(m)]
    remaining = set(range(m))

    while remaining:
        min_node = min(remaining, key=lambda x: degree[x])
        order.append(min_node)
        remaining.remove(min_node)

        neighbors = [n for n in adj[min_node] if n in remaining]
        for i in range(len(neighbors)):
            for j in range(i + 1, len(neighbors)):
                if neighbors[j] not in adj[neighbors[i]]:
                    adj[neighbors[i]].add(neighbors[j])
                    adj[neighbors[j]].add(neighbors[i])
                    degree[neighbors[i]] += 1
                    degree[neighbors[j]] += 1

        for n in neighbors:
            if min_node in adj[n]:
                adj[n].remove(min_node)
                degree[n] -= 1

    # Variable Elimination
    backtrack_info = {}

    for var in order:
        relevant_factors = []
        remaining_factors = []
        for vars_list, factor_dict in factors:
            if var in vars_list:
                relevant_factors.append((vars_list, factor_dict))
            else:
                remaining_factors.append((vars_list, factor_dict))

        if not relevant_factors:
            factors = remaining_factors
            continue

        # Join factors
        current_vars, current_dict = relevant_factors[0]

        for vars_list, factor_dict in relevant_factors[1:]:
            new_vars = []
            var_pos_curr = {}
            var_pos_new = {}
            var_pos_res = {}

            for idx, v in enumerate(current_vars):
                var_pos_curr[v] = idx
                if v not in var_pos_res:
                    var_pos_res[v] = len(new_vars)
                    new_vars.append(v)

            for idx, v in enumerate(vars_list):
                var_pos_new[v] = idx
                if v not in var_pos_res:
                    var_pos_res[v] = len(new_vars)
                    new_vars.append(v)

            new_dict = {}
            for assign_curr, cost_curr in current_dict.items():
                for assign_new, cost_new in factor_dict.items():
                    consistent = True
                    shared_vars = set(current_vars) & set(vars_list)
                    for sv in shared_vars:
                        if assign_curr[var_pos_curr[sv]] != assign_new[var_pos_new[sv]]:
                            consistent = False
                            break

                    if consistent:
                        combined = [0] * len(new_vars)
                        for v in current_vars:
                            combined[var_pos_res[v]] = assign_curr[var_pos_curr[v]]
                        for v in vars_list:
                            combined[var_pos_res[v]] = assign_new[var_pos_new[v]]

                        combined_tuple = tuple(combined)
                        total_cost = cost_curr + cost_new

                        if combined_tuple not in new_dict or total_cost < new_dict[combined_tuple]:
                            new_dict[combined_tuple] = total_cost

            current_vars = new_vars
            current_dict = new_dict

        # Marginalize
        var_pos = current_vars.index(var)
        other_vars = [v for v in current_vars if v != var]

        if not other_vars:
            min_cost = min(current_dict.values())
            for assign, cost in current_dict.items():
                if cost == min_cost:
                    backtrack_info[var] = (None, assign[0])
                    break
            factors = remaining_factors
        else:
            min_dict = {}
            argmin_dict = {}

            for assign, cost in current_dict.items():
                other_assign = tuple(assign[i] for i in range(len(current_vars)) if i != var_pos)
                if other_assign not in min_dict or cost < min_dict[other_assign]:
                    min_dict[other_assign] = cost
                    argmin_dict[other_assign] = assign[var_pos]

            backtrack_info[var] = (other_vars, argmin_dict)
            factors = remaining_factors + [(other_vars, min_dict)]

    # Backtrack
    assignment = {}
    for var in reversed(order):
        other_vars, argmin_info = backtrack_info[var]
        if other_vars is None:
            assignment[var] = argmin_info
        else:
            key = tuple(assignment[v] for v in other_vars)
            assignment[var] = argmin_info.get(key, 0)

    return assignment


def fast_local_search(m, N, genotypes, gt_to_idx, unary_costs, father, mother, time_limit=9.0):
    """Fast local search with incremental evaluation"""
    import time
    start_time = time.time()

    # Build children lists
    children = [[] for _ in range(m)]
    for i in range(m):
        if father[i] != -1:
            children[father[i]].append(i)
        if mother[i] != -1:
            children[mother[i]].append(i)

    # Precompute valid children for all parent pairs
    valid_children_cache = {}
    for i in range(N):
        for j in range(N):
            a1, a2 = genotypes[i]
            b1, b2 = genotypes[j]
            valid = set()
            for allele_a in [a1, a2]:
                for allele_b in [b1, b2]:
                    if allele_a <= allele_b:
                        child_gt = (allele_a, allele_b)
                    else:
                        child_gt = (allele_b, allele_a)
                    valid.add(gt_to_idx[child_gt])
            valid_children_cache[(i, j)] = valid

    # Initialize
    assignment = np.array([int(np.argmin(unary_costs[i])) for i in range(m)], dtype=np.int32)

    # Compute initial costs incrementally
    unary_cost = sum(unary_costs[i][assignment[i]] for i in range(m))
    violation_cost = 0

    # Track which children violate constraints
    violations = set()
    for i in range(m):
        if father[i] != -1 and mother[i] != -1:
            if assignment[i] not in valid_children_cache[(assignment[father[i]], assignment[mother[i]])]:
                violations.add(i)
                violation_cost += 1000

    current_cost = unary_cost + violation_cost

    best_assignment = assignment.copy()
    best_cost = current_cost

    # Tabu search parameters
    tabu = {}
    tabu_tenure = 10
    iteration = 0

    while time.time() - start_time < time_limit:
        if best_cost == 0:
            break

        # Find best move
        best_move = None
        best_move_cost = current_cost + 1

        # Sample variables to try
        vars_to_try = np.random.choice(m, min(m, 30), replace=False)

        for i in vars_to_try:
            current_gt = assignment[i]

            # Compute delta for changing i's genotype
            for new_gt in range(N):
                if new_gt == current_gt:
                    continue

                if (i, new_gt) in tabu and tabu[(i, new_gt)] > iteration:
                    continue

                # Compute cost change
                delta = int(unary_costs[i][new_gt]) - int(unary_costs[i][current_gt])

                # Check violations for i if i has parents
                if father[i] != -1 and mother[i] != -1:
                    was_violation = i in violations
                    is_violation = new_gt not in valid_children_cache[(assignment[father[i]], assignment[mother[i]])]

                    if was_violation and not is_violation:
                        delta -= 1000
                    elif not was_violation and is_violation:
                        delta += 1000

                # Check violations for children of i
                for child in children[i]:
                    if father[child] == -1 or mother[child] == -1:
                        continue

                    other_parent = mother[child] if father[child] == i else father[child]

                    was_violation = child in violations
                    is_violation = assignment[child] not in valid_children_cache[(new_gt, assignment[other_parent])]

                    if was_violation and not is_violation:
                        delta -= 1000
                    elif not was_violation and is_violation:
                        delta += 1000

                new_cost = current_cost + delta

                if new_cost < best_move_cost:
                    best_move_cost = new_cost
                    best_move = (i, new_gt, delta)

                    if new_cost < best_cost:
                        break

            if best_move and best_move_cost < best_cost:
                break

        if best_move:
            i, new_gt, delta = best_move
            old_gt = assignment[i]

            # Update violations before changing assignment
            # Update for i itself
            if father[i] != -1 and mother[i] != -1:
                if i in violations:
                    violations.remove(i)
                if new_gt not in valid_children_cache[(assignment[father[i]], assignment[mother[i]])]:
                    violations.add(i)

            # Update for children of i
            for child in children[i]:
                if father[child] == -1 or mother[child] == -1:
                    continue

                other_parent = mother[child] if father[child] == i else father[child]

                if child in violations:
                    violations.remove(child)
                if assignment[child] not in valid_children_cache[(new_gt, assignment[other_parent])]:
                    violations.add(child)

            # Apply move
            assignment[i] = new_gt
            current_cost += delta

            # Add to tabu
            tabu[(i, old_gt)] = iteration + tabu_tenure

            # Clean old tabu
            to_remove = [k for k, v in list(tabu.items()) if v <= iteration]
            for k in to_remove:
                del tabu[k]

            if current_cost < best_cost:
                best_cost = current_cost
                best_assignment = assignment.copy()
        else:
            # Random restart
            assignment = best_assignment.copy()
            violations = set()
            for i in range(m):
                if father[i] != -1 and mother[i] != -1:
                    if assignment[i] not in valid_children_cache[(assignment[father[i]], assignment[mother[i]])]:
                        violations.add(i)

            # Random perturbation
            for idx in np.random.choice(m, min(m // 5 + 1, 10), replace=False):
                assignment[idx] = np.random.randint(N)

            # Recompute violations
            violations = set()
            unary_cost = 0
            for i in range(m):
                unary_cost += int(unary_costs[i][assignment[i]])
                if father[i] != -1 and mother[i] != -1:
                    if assignment[i] not in valid_children_cache[(assignment[father[i]], assignment[mother[i]])]:
                        violations.add(i)

            current_cost = unary_cost + len(violations) * 1000

        iteration += 1

        # Periodically clean tabu to save memory
        if iteration % 1000 == 0:
            to_remove = [k for k, v in list(tabu.items()) if v <= iteration]
            for k in to_remove:
                del tabu[k]

    return {i: int(best_assignment[i]) for i in range(m)}

