def solve(input_file: str, solution_file: str):
    from dataclasses import dataclass
    from typing import Dict, List
    import os
    import random
    import time

    @dataclass
    class Node:
        index: int
        x: float
        y: float
        demand: float
        earliest_time: float
        latest_time: float
        service_time: float
        pickup_sibling: int
        delivery_sibling: int
        is_pickup: bool

    @dataclass
    class Instance:
        name: str
        type: str
        dimension: int
        vehicles: int
        capacity: float
        edge_weight_type: str
        nodes: Dict[int, Node]
        depot_node: List[int]

    def read_instance(file_path: str) -> Instance:
        with open(file_path, "r") as file:
            lines = file.readlines()

        name = ""
        type_ = ""
        dimension = 0
        vehicles = 0
        capacity = 0.0
        edge_weight_type = ""
        nodes = {}
        depot_node = []

        section = None
        for line in lines:
            line = line.strip()
            if line.startswith("NAME"):
                name = line.split(":")[1].strip()
            elif line.startswith("TYPE"):
                type_ = line.split(":")[1].strip()
            elif line.startswith("DIMENSION"):
                dimension = int(line.split(":")[1].strip())
            elif line.startswith("VEHICLES"):
                vehicles = int(line.split(":")[1].strip())
            elif line.startswith("CAPACITY"):
                capacity = float(line.split(":")[1].strip())
            elif line.startswith("EDGE_WEIGHT_TYPE"):
                edge_weight_type = line.split(":")[1].strip()
            elif line.startswith("NODE_COORD_SECTION"):
                section = "NODE_COORD_SECTION"
            elif line.startswith("PICKUP_AND_DELIVERY_SECTION"):
                section = "PICKUP_AND_DELIVERY_SECTION"
            elif line.startswith("DEPOT_SECTION"):
                section = "DEPOT_SECTION"
            elif line.startswith("EOF"):
                break
            elif section == "NODE_COORD_SECTION":
                parts = line.split()
                index = int(parts[0])
                x, y = float(parts[1]), float(parts[2])
                nodes[index] = Node(
                    index=index,
                    x=x,
                    y=y,
                    demand=0.0,
                    earliest_time=0.0,
                    latest_time=0.0,
                    service_time=0.0,
                    pickup_sibling=0,
                    delivery_sibling=0,
                    is_pickup=False,
                )
            elif section == "PICKUP_AND_DELIVERY_SECTION":
                parts = line.split()
                index = int(parts[0])
                if index in nodes:
                    nodes[index].demand = float(parts[1])
                    nodes[index].earliest_time = float(parts[2])
                    nodes[index].latest_time = float(parts[3])
                    nodes[index].service_time = float(parts[4])
                    nodes[index].pickup_sibling = int(parts[5])
                    nodes[index].delivery_sibling = int(parts[6])
                    nodes[index].is_pickup = nodes[index].pickup_sibling == 0
            elif section == "DEPOT_SECTION":
                if line != "-1":
                    depot_node.append(int(line))

        return Instance(
            name=name,
            type=type_,
            dimension=dimension,
            vehicles=vehicles,
            capacity=capacity,
            edge_weight_type=edge_weight_type,
            nodes=nodes,
            depot_node=depot_node,
        )

    def calculate_distance(x1: float, y1: float, x2: float, y2: float) -> float:
        return round(((x2 - x1) ** 2 + (y1 - y2) ** 2) ** 0.5, 0)

    base_name = os.path.splitext(os.path.basename(input_file))[0]
    instance = read_instance(input_file)

    start_time = time.time()
    time_limit = 8.0

    depot_id = instance.depot_node[0]
    n = instance.dimension
    capacity = instance.capacity

    dist = [[0.0] * (n + 1) for _ in range(n + 1)]
    for i in range(1, n + 1):
        for j in range(i + 1, n + 1):
            d = calculate_distance(instance.nodes[i].x, instance.nodes[i].y, 
                                 instance.nodes[j].x, instance.nodes[j].y)
            dist[i][j] = d
            dist[j][i] = d

    pairs = {}
    pickups = []
    for idx, node in instance.nodes.items():
        if idx == depot_id:
            continue
        if node.is_pickup:
            pairs[idx] = node.delivery_sibling
            pickups.append(idx)

    def check_route_feasible(route):
        if len(route) <= 2:
            return True

        time = 0.0
        load = 0.0

        for i in range(len(route) - 1):
            curr = route[i]
            next_node = route[i + 1]
            node = instance.nodes[curr]

            if i > 0:
                time = max(time, node.earliest_time)
                if time > node.latest_time:
                    return False
                time += node.service_time

            load += node.demand
            if load > capacity:
                return False

            time += dist[curr][next_node]

        if time > instance.nodes[route[-1]].latest_time:
            return False

        return True

    def get_route_distance(route):
        total = 0.0
        for i in range(len(route) - 1):
            total += dist[route[i]][route[i+1]]
        return total

    def try_insert_pair(route, pickup, delivery):
        best_route = None
        best_cost = float('inf')
        n_route = len(route)

        if n_route == 2:
            new_route = [route[0], pickup, delivery, route[1]]
            if check_route_feasible(new_route):
                cost = get_route_distance(new_route)
                return new_route, cost
            return None, float('inf')

        for i in range(1, n_route):
            for j in range(i, n_route):
                new_route = route[:i] + [pickup] + route[i:j] + [delivery] + route[j:]
                if check_route_feasible(new_route):
                    cost = get_route_distance(new_route)
                    if cost < best_cost:
                        best_cost = cost
                        best_route = new_route

        return best_route, best_cost

    def build_solution(seed=None):
        if seed is not None:
            random.seed(seed)

        routes = []
        unassigned = set(pickups)

        order = list(unassigned)
        random.shuffle(order)

        for pickup in order:
            if pickup not in unassigned:
                continue
            delivery = pairs[pickup]

            best_cost = float('inf')
            best_route_idx = -1
            best_new_route = None

            for idx, route in enumerate(routes):
                new_route, cost = try_insert_pair(route, pickup, delivery)
                if new_route is not None and cost < best_cost:
                    best_cost = cost
                    best_route_idx = idx
                    best_new_route = new_route

            if len(routes) < instance.vehicles:
                new_route = [depot_id, depot_id]
                result, cost = try_insert_pair(new_route, pickup, delivery)
                if result is not None:
                    if cost < best_cost * 1.1 or best_new_route is None:
                        routes.append(result)
                        unassigned.remove(pickup)
                        continue

            if best_new_route is not None:
                routes[best_route_idx] = best_new_route
                unassigned.remove(pickup)

        return routes, unassigned

    def simple_two_opt(route):
        if len(route) <= 4:
            return route

        improved = True
        iteration = 0
        max_iter = 5

        while improved and iteration < max_iter:
            improved = False
            iteration += 1
            best_dist = get_route_distance(route)

            for i in range(1, len(route) - 2):
                for j in range(i + 1, len(route) - 1):
                    segment = route[i:j+1]
                    valid = True
                    for p in segment:
                        if p in pairs and pairs[p] in segment:
                            valid = False
                            break

                    if not valid:
                        continue

                    new_route = route[:i] + route[i:j+1][::-1] + route[j+1:]
                    if check_route_feasible(new_route):
                        new_dist = get_route_distance(new_route)
                        if new_dist < best_dist - 0.5:
                            route = new_route
                            best_dist = new_dist
                            improved = True
                            break
                if improved:
                    break

        return route

    best_routes = []
    best_cost = float('inf')

    for iteration in range(50):
        if time.time() - start_time > time_limit:
            break

        routes, unassigned = build_solution(iteration)

        if unassigned:
            continue

        for i in range(len(routes)):
            routes[i] = simple_two_opt(routes[i])

        total_cost = sum(get_route_distance(r) for r in routes)

        if total_cost < best_cost:
            best_cost = total_cost
            best_routes = [r[:] for r in routes]

    if not best_routes:
        routes, unassigned = build_solution(42)
        if not unassigned:
            best_routes = routes

    if not best_routes:
        best_routes = [[depot_id, depot_id]]

    final_routes = []
    for route in best_routes:
        if len(route) > 2:
            if route[0] != depot_id:
                route.insert(0, depot_id)
            if route[-1] != depot_id:
                route.append(depot_id)
            final_routes.append(route)

    if not final_routes:
        final_routes = [[depot_id, depot_id]]

    with open(solution_file, 'w') as f:
        f.write(f"{instance.name}\n")
        for route in final_routes:
            f.write(" ".join(map(str, route)) + "\n")

