def solve(cap_file: str, net_file: str, solution_file: str):
    import re
    from collections import defaultdict

    # ==================== PARSE CAP FILE ====================
    with open(cap_file, 'r') as f:
        lines = f.readlines()

    it = iter(lines)

    nLayers, xSize, ySize = map(int, next(it).split())

    line2 = next(it).split()
    UnitLengthWireCost = float(line2[0])
    UnitViaCost = float(line2[1])
    OFWeight = [float(x) for x in line2[2:]]

    HorizontalGCellEdgeLengths = list(map(int, next(it).split()))
    VerticalGCellEdgeLengths = list(map(int, next(it).split()))

    layer_directions = []
    layer_capacities = []

    for layer_idx in range(nLayers):
        header = next(it).split()
        layer_direction = int(header[1])
        layer_directions.append(layer_direction)

        capacity_grid = []
        for _ in range(ySize):
            row = list(map(float, next(it).split()))
            capacity_grid.append(row)
        layer_capacities.append(capacity_grid)

    # ==================== PARSE NET FILE ====================
    with open(net_file, 'r') as f:
        content = f.read()

    nets = []
    lines = content.split('\n')

    i = 0
    while i < len(lines):
        line = lines[i].strip()
        if line and not line.startswith('(') and not line.startswith('[') and line != ')':
            net_name = line
            i += 1
            if i < len(lines) and lines[i].strip() == '(':
                i += 1
                pin_lines = []
                depth = 1
                while i < len(lines) and depth > 0:
                    l = lines[i].strip()
                    if l == ')':
                        depth -= 1
                        if depth == 0:
                            break
                    if l:
                        pin_lines.append(l)
                    if '(' in l:
                        depth += 1
                    i += 1
                nets.append((net_name, pin_lines))
        i += 1

    parsed_nets = []
    for net_name, pin_lines in nets:
        pins = []
        for pin_line in pin_lines:
            pin_line = pin_line.strip()
            if pin_line.startswith('[') and pin_line.endswith(']'):
                pin_line = pin_line[1:-1]

            access_points = []
            tuples = re.findall(r'\(([^)]+)\)', pin_line)
            for t in tuples:
                parts = t.split(',')
                if len(parts) == 3:
                    layer = int(parts[0].strip())
                    x = int(parts[1].strip())
                    y = int(parts[2].strip())
                    access_points.append((layer, x, y))

            if access_points:
                pins.append(access_points)
        parsed_nets.append((net_name, pins))

    # ==================== ROUTING FUNCTIONS ====================

    def find_l_shaped_path(x1, y1, z1, x2, y2, z2):
        """Find L-shaped path on a specific layer"""
        if z1 == 0:
            return None

        direction = layer_directions[z1]

        path = []
        cx, cy = x1, y1

        if direction == 0:  # Horizontal layer: go horizontal first
            while cx != x2:
                path.append((cx, cy, z1))
                cx += 1 if x2 > cx else -1
            path.append((cx, cy, z1))
            while cy != y2:
                path.append((cx, cy, z1))
                cy += 1 if y2 > cy else -1
            path.append((cx, cy, z1))
        else:  # Vertical layer: go vertical first
            while cy != y2:
                path.append((cx, cy, z1))
                cy += 1 if y2 > cy else -1
            path.append((cx, cy, z1))
            while cx != x2:
                path.append((cx, cy, z1))
                cx += 1 if x2 > cx else -1
            path.append((cx, cy, z1))

        return path

    def connect_points(p1, p2):
        """Connect two access points"""
        z1, x1, y1 = p1
        z2, x2, y2 = p2

        if z1 == z2:
            if z1 == 0:
                path = [(x1, y1, z1)]
                for z in range(z1, 1):
                    path.append((x1, y1, z+1))
                l_path = find_l_shaped_path(x1, y1, 1, x2, y2, 1)
                if l_path:
                    path.extend(l_path[1:])
                return path
            else:
                return find_l_shaped_path(x1, y1, z1, x2, y2, z2)

        # Different layers
        best_path = None
        best_len = float('inf')

        # Try direct via connection if adjacent
        if abs(z1 - z2) == 1:
            path = []
            if z1 < z2:
                for z in range(z1, z2):
                    path.append((x1, y1, z))
                    path.append((x1, y1, z+1))
            else:
                for z in range(z2, z1):
                    path.append((x1, y1, z))
                    path.append((x1, y1, z+1))
            if z2 != 0:
                l_path = find_l_shaped_path(x1, y1, z2, x2, y2, z2)
                if l_path:
                    path.extend(l_path[1:])
            if path:
                best_path = path
                best_len = len(path)

        # Try going through each valid intermediate layer
        for mid_z in range(1, nLayers):
            if mid_z == z1 or mid_z == z2:
                continue

            path = []

            if z1 < mid_z:
                for z in range(z1, mid_z):
                    path.append((x1, y1, z))
                    path.append((x1, y1, z+1))
            elif z1 > mid_z:
                for z in range(mid_z, z1):
                    path.append((x1, y1, z))
                    path.append((x1, y1, z+1))

            l_path = find_l_shaped_path(x1, y1, mid_z, x2, y2, mid_z)
            if l_path is None:
                continue
            path.extend(l_path)

            if z2 < mid_z:
                for z in range(z2, mid_z):
                    path.append((x2, y2, z))
                    path.append((x2, y2, z+1))
            elif z2 > mid_z:
                for z in range(mid_z, z2):
                    path.append((x2, y2, z))
                    path.append((x2, y2, z+1))

            if len(path) < best_len:
                best_path = path
                best_len = len(path)

        return best_path

    def path_to_segments(path):
        """Convert a path of nodes to segments - EXPLICIT format"""
        if not path or len(path) < 2:
            return []

        segments = []
        for i in range(len(path) - 1):
            x1, y1, z1 = path[i]
            x2, y2, z2 = path[i+1]

            # Skip degenerate segments
            if x1 == x2 and y1 == y2 and z1 == z2:
                continue

            if z1 != z2:
                # Via segment: same x,y, different z
                # z_l < z_h
                z_low = min(z1, z2)
                z_high = max(z1, z2)
                segments.append((x1, y1, z_low, x1, y1, z_high))
            elif x1 != x2:
                # Horizontal segment: same y,z, different x
                # x_l < x_h
                x_low = min(x1, x2)
                x_high = max(x1, x2)
                segments.append((x_low, y1, z1, x_high, y1, z1))
            elif y1 != y2:
                # Vertical segment: same x,z, different y
                # y_l < y_h
                y_low = min(y1, y2)
                y_high = max(y1, y2)
                segments.append((x1, y_low, z1, x1, y_high, z1))

        return segments

    def route_net(pins):
        """Route a net with multiple pins"""
        if not pins or len(pins) == 0:
            return []

        if len(pins) == 1:
            return []

        all_aps = []
        for pin_access in pins:
            for ap in pin_access:
                all_aps.append(ap)

        if not all_aps:
            return []

        connected = {all_aps[0]}
        remaining = all_aps[1:]

        all_segments = []

        while remaining:
            best_path = None
            best_rem = None
            best_len = float('inf')

            for conn_ap in connected:
                for rem_ap in remaining:
                    path = connect_points(conn_ap, rem_ap)
                    if path and len(path) < best_len:
                        best_len = len(path)
                        best_path = path
                        best_rem = rem_ap

            if best_path is None:
                path = connect_points(all_aps[0], remaining[0])
                if path:
                    best_path = path
                    best_rem = remaining[0]
                else:
                    remaining = remaining[1:]
                    continue

            segs = path_to_segments(best_path)
            all_segments.extend(segs)
            connected.add(best_rem)
            remaining.remove(best_rem)

        return all_segments

    # ==================== ROUTE ALL NETS ====================

    net_routes = {}
    for net_name, pins in parsed_nets:
        segments = route_net(pins)
        net_routes[net_name] = segments

    # ==================== WRITE OUTPUT ====================

    with open(solution_file, 'w') as f:
        for net_name, segments in net_routes.items():
            f.write(net_name + '\n')
            f.write('(\n')
            for seg in segments:
                x1, y1, z1, x2, y2, z2 = seg
                # Validate before writing
                if z1 == z2:
                    if y1 == y2:
                        # Horizontal
                        if x1 >= x2:
                            continue  # Skip invalid
                    elif x1 == x2:
                        # Vertical
                        if y1 >= y2:
                            continue  # Skip invalid
                elif x1 == x2 and y1 == y2:
                    # Via
                    if z1 >= z2:
                        continue
                f.write(f'{x1} {y1} {z1} {x2} {y2} {z2}\n')
            f.write(')\n')

    return 0

