import json
import random
from collections import defaultdict

def solve(input_file: str, solution_file: str):
    with open(input_file, 'r') as f:
        data = json.load(f)

    problem = data['problem']
    usage_limit = problem['usage_limit']

    node_intervals = problem['nodes']['intervals']
    node_costs = problem['nodes']['costs']
    node_usages = problem['nodes']['usages']

    n_nodes = len(node_intervals)
    n_strategies = [len(node_costs[i]) for i in range(n_nodes)]

    edge_nodes = problem['edges']['nodes']
    edge_costs = problem['edges']['costs']

    edge_cost_map = defaultdict(list)
    for i, (u, v) in enumerate(edge_nodes):
        edge_cost_map[(min(u, v), max(u, v))].append((i, edge_costs[i]))

    all_times = set()
    for interval in node_intervals:
        all_times.add(interval[0])
        all_times.add(interval[1])
    all_times = sorted(all_times)

    time_to_nodes = defaultdict(set)
    for t in all_times:
        for i, (lo, hi) in enumerate(node_intervals):
            if lo <= t < hi:
                time_to_nodes[t].add(i)

    def compute_total_cost(assignment):
        total = 0
        for i, s in enumerate(assignment):
            total += node_costs[i][s]
        for (u, v), edges_info in edge_cost_map.items():
            su, sv = assignment[u], assignment[v]
            l_v = n_strategies[v]
            for edge_idx, cost_matrix in edges_info:
                total += cost_matrix[su * l_v + sv]
        return total

    def check_feasibility(assignment):
        for t in all_times:
            total_usage = 0
            for i in time_to_nodes[t]:
                total_usage += node_usages[i][assignment[i]]
            if total_usage > usage_limit:
                return False
        return True

    def greedy_initial_solution():
        node_order = list(range(n_nodes))
        random.shuffle(node_order)
        node_order.sort(key=lambda i: (node_intervals[i][1] - node_intervals[i][0], n_strategies[i]), reverse=True)

        assignment = [0] * n_nodes

        for i in node_order:
            best_strategy = 0
            best_cost = float('inf')

            for s in range(n_strategies[i]):
                assignment[i] = s
                if check_feasibility(assignment):
                    cost = node_costs[i][s]
                    if cost < best_cost:
                        best_cost = cost
                        best_strategy = s

            assignment[i] = best_strategy

        return assignment

    def try_improve(assignment, max_iterations=5000):
        current_cost = compute_total_cost(assignment)
        improved = True
        iterations = 0

        while improved and iterations < max_iterations:
            improved = False
            iterations += 1

            nodes_to_try = list(range(n_nodes))
            random.shuffle(nodes_to_try)

            for i in nodes_to_try:
                current_strategy = assignment[i]
                current_node_cost = node_costs[i][current_strategy]

                for s in range(n_strategies[i]):
                    if s == current_strategy:
                        continue

                    if node_costs[i][s] >= current_node_cost:
                        if random.random() > 0.1:
                            continue

                    old_strategy = assignment[i]
                    assignment[i] = s

                    if check_feasibility(assignment):
                        new_cost = compute_total_cost(assignment)
                        if new_cost < current_cost:
                            current_cost = new_cost
                            improved = True
                            break
                    else:
                        assignment[i] = old_strategy

        return assignment, current_cost

    best_assignment = None
    best_cost = float('inf')

    n_restarts = min(20, max(5, n_nodes // 100))

    for restart in range(n_restarts):
        assignment = greedy_initial_solution()

        if not check_feasibility(assignment):
            continue

        assignment, cost = try_improve(assignment)

        if cost < best_cost:
            best_cost = cost
            best_assignment = assignment.copy()

    if best_assignment is None:
        assignment = [0] * n_nodes
        for i in range(n_nodes):
            min_cost_idx = min(range(n_strategies[i]), key=lambda s: node_costs[i][s])
            assignment[i] = min_cost_idx

        for i in range(n_nodes):
            for s in range(n_strategies[i]):
                assignment[i] = s
                if not check_feasibility(assignment):
                    assignment[i] = 0
                    break

        best_assignment = assignment

    with open(solution_file, 'w') as f:
        f.write('[' + ', '.join(str(s) for s in best_assignment) + ']')

