import json
import heapq
from collections import defaultdict

def solve(input_file: str, solution_file: str):
    with open(input_file, 'r') as f:
        data = json.load(f)

    delay = data['delay']
    resource = data['resource']
    nodes = data['nodes']
    edges = data['edges']

    node_to_res = {}
    node_to_idx = {}
    for i, (node_id, res_type) in enumerate(nodes):
        node_to_idx[node_id] = i
        node_to_res[node_id] = res_type

    successors = defaultdict(list)
    predecessors = defaultdict(list)

    for src, tgt, _ in edges:
        successors[src].append(tgt)
        predecessors[tgt].append(src)

    node_delay = {node_id: delay[res_type] for node_id, res_type in zip([n[0] for n in nodes], [n[1] for n in nodes])}

    est = {}
    def compute_est(node):
        if node in est:
            return est[node]
        if not predecessors[node]:
            est[node] = 0
        else:
            est[node] = max(compute_est(pred) + node_delay[pred] for pred in predecessors[node])
        return est[node]

    for node in node_to_idx:
        compute_est(node)

    lct = {}
    def compute_lct(node):
        if node in lct:
            return lct[node]
        if not successors[node]:
            lct[node] = node_delay[node]
        else:
            lct[node] = node_delay[node] + max(compute_lct(succ) for succ in successors[node])
        return lct[node]

    for node in node_to_idx:
        compute_lct(node)

    resource_free = {res: [] for res in resource}
    for res in resource:
        for i in range(resource[res]):
            heapq.heappush(resource_free[res], (0, i))

    schedule = {}
    scheduled = set()

    ready = []
    for node in node_to_idx:
        if not predecessors[node]:
            heapq.heappush(ready, (-lct[node], node))

    while ready:
        _, node = heapq.heappop(ready)

        if node in scheduled:
            continue

        if not all(pred in schedule for pred in predecessors[node]):
            heapq.heappush(ready, (-lct[node], node))
            continue

        res_type = node_to_res[node]
        d = node_delay[node]

        t = est[node]
        for pred in predecessors[node]:
            t = max(t, schedule[pred] + node_delay[pred])

        while True:
            available_units = []
            while resource_free[res_type] and resource_free[res_type][0][0] <= t:
                free_time, unit_id = heapq.heappop(resource_free[res_type])
                available_units.append(unit_id)

            if available_units:
                unit_id = available_units[0]
                heapq.heappush(resource_free[res_type], (t + d, unit_id))
                for uid in available_units[1:]:
                    heapq.heappush(resource_free[res_type], (t, uid))
                break
            else:
                t = resource_free[res_type][0][0]

        schedule[node] = t
        scheduled.add(node)

        for succ in successors[node]:
            if all(pred in schedule for pred in predecessors[succ]):
                heapq.heappush(ready, (-lct[succ], succ))

    with open(solution_file, 'w') as f:
        for node in sorted(schedule.keys()):
            f.write(f"{node}:{schedule[node]}\n")

