def solve(input_file: str, solution_file: str):

    from dataclasses import dataclass
    from typing import Dict, List
    import os

    @dataclass
    class Node:
        index: int
        x: float
        y: float
        demand: float
        earliest_time: float
        latest_time: float
        service_time: float
        pickup_sibling: int
        delivery_sibling: int
        is_pickup: bool


    @dataclass
    class Instance:
        name: str
        type: str
        dimension: int
        vehicles: int
        capacity: float
        edge_weight_type: str
        nodes: Dict[int, Node]
        depot_node: List[int]


    def read_instance(file_path: str) -> Instance:
        with open(file_path, "r") as file:
            lines = file.readlines()

        name = ""
        type_ = ""
        dimension = 0
        vehicles = 0
        capacity = 0.0
        edge_weight_type = ""
        nodes = {}
        depot_node = []

        section = None
        for line in lines:
            line = line.strip()
            if line.startswith("NAME"):
                name = line.split(":")[1].strip()
            elif line.startswith("TYPE"):
                type_ = line.split(":")[1].strip()
            elif line.startswith("DIMENSION"):
                dimension = int(line.split(":")[1].strip())
            elif line.startswith("VEHICLES"):
                vehicles = int(line.split(":")[1].strip())
            elif line.startswith("CAPACITY"):
                capacity = float(line.split(":")[1].strip())
            elif line.startswith("EDGE_WEIGHT_TYPE"):
                edge_weight_type = line.split(":")[1].strip()
            elif line.startswith("NODE_COORD_SECTION"):
                section = "NODE_COORD_SECTION"
            elif line.startswith("PICKUP_AND_DELIVERY_SECTION"):
                section = "PICKUP_AND_DELIVERY_SECTION"
            elif line.startswith("DEPOT_SECTION"):
                section = "DEPOT_SECTION"
            elif line.startswith("EOF"):
                break
            elif section == "NODE_COORD_SECTION":
                parts = line.split()
                index = int(parts[0])
                x, y = float(parts[1]), float(parts[2])
                nodes[index] = Node(
                    index=index,
                    x=x,
                    y=y,
                    demand=0.0,
                    earliest_time=0.0,
                    latest_time=0.0,
                    service_time=0.0,
                    pickup_sibling=0,
                    delivery_sibling=0,
                    is_pickup=False,
                )
            elif section == "PICKUP_AND_DELIVERY_SECTION":
                parts = line.split()
                index = int(parts[0])
                if index in nodes:
                    nodes[index].demand = float(parts[1])
                    nodes[index].earliest_time = float(parts[2])
                    nodes[index].latest_time = float(parts[3])
                    nodes[index].service_time = float(parts[4])
                    nodes[index].pickup_sibling = int(parts[5])
                    nodes[index].delivery_sibling = int(parts[6])
                    nodes[index].is_pickup = (
                        nodes[index].pickup_sibling == 0
                    )
            elif section == "DEPOT_SECTION":
                if line != "-1":
                    depot_node.append(int(line))

        return Instance(
            name=name,
            type=type_,
            dimension=dimension,
            vehicles=vehicles,
            capacity=capacity,
            edge_weight_type=edge_weight_type,
            nodes=nodes,
            depot_node=depot_node,
        )


    def calculate_distance(x1: float, y1: float, x2: float, y2: float) -> float:
        return round(((x2 - x1) ** 2 + (y1 - y2) ** 2) ** 0.5, 0)


    base_name = os.path.splitext(os.path.basename(input_file))[0]

    instance = read_instance(input_file)

    n_nodes = len(instance.nodes)
    node_indices = sorted(instance.nodes.keys())
    idx_to_node = {i: node_indices[i] for i in range(n_nodes)}
    node_to_idx = {node_indices[i]: i for i in range(n_nodes)}

    dist_matrix = [[0.0] * n_nodes for _ in range(n_nodes)]
    for i in range(n_nodes):
        for j in range(n_nodes):
            if i != j:
                ni = instance.nodes[idx_to_node[i]]
                nj = instance.nodes[idx_to_node[j]]
                dist_matrix[i][j] = calculate_distance(ni.x, ni.y, nj.x, nj.y)

    depot_original = instance.depot_node[0]
    depot_idx = node_to_idx[depot_original]
    capacity = instance.capacity
    max_vehicles = instance.vehicles

    pd_pairs = []
    for idx in node_indices:
        node = instance.nodes[idx]
        if node.is_pickup:
            delivery_idx = node.delivery_sibling
            if delivery_idx > 0:
                pd_pairs.append((node_to_idx[idx], node_to_idx[delivery_idx]))

    def pair_distance(pickup_idx, delivery_idx):
        pickup_node = instance.nodes[idx_to_node[pickup_idx]]
        delivery_node = instance.nodes[idx_to_node[delivery_idx]]
        depot_node = instance.nodes[depot_original]
        d1 = calculate_distance(depot_node.x, depot_node.y, pickup_node.x, pickup_node.y)
        d2 = calculate_distance(pickup_node.x, pickup_node.y, delivery_node.x, delivery_node.y)
        return d1 + d2

    pd_pairs.sort(key=lambda x: pair_distance(x[0], x[1]))

    def calculate_route_cost(route):
        if len(route) < 2:
            return 0
        total = 0
        for i in range(len(route) - 1):
            total += dist_matrix[route[i]][route[i+1]]
        return total

    def calculate_load_on_route(route):
        load = 0
        for idx in route:
            node = instance.nodes[idx_to_node[idx]]
            load += node.demand
        return load

    def check_time_windows(route):
        if len(route) <= 1:
            return True
        current_time = 0
        for i in range(len(route) - 1):
            from_idx = route[i]
            to_idx = route[i+1]
            current_time += dist_matrix[from_idx][to_idx]
            node = instance.nodes[idx_to_node[to_idx]]
            if current_time < node.earliest_time:
                current_time = node.earliest_time
            if current_time > node.latest_time:
                return False
            current_time += node.service_time
        return True

    def find_best_insertion(route, pickup_idx, delivery_idx):
        if len(route) == 1:
            return None, float('inf')

        best_cost = float('inf')
        best_route = None

        for pos_pickup in range(1, len(route)):
            for pos_delivery in range(pos_pickup + 1, len(route) + 1):
                new_route = route[:pos_pickup] + [pickup_idx] + route[pos_pickup:pos_delivery-1] + [delivery_idx] + route[pos_delivery-1:]

                if calculate_load_on_route(new_route) > capacity:
                    continue

                if not check_time_windows(new_route):
                    continue

                cost = calculate_route_cost(new_route)
                if cost < best_cost:
                    best_cost = cost
                    best_route = new_route

        return best_route, best_cost

    def try_insert_into_route(route, pickup_idx, delivery_idx):
        new_route, cost = find_best_insertion(route, pickup_idx, delivery_idx)
        if new_route is not None:
            return new_route, cost
        return None, float('inf')

    total_demand = sum(instance.nodes[idx].demand for idx in node_indices if instance.nodes[idx].demand > 0)
    min_routes_needed = max(1, int(total_demand / capacity) + 1)
    initial_routes = min(max_vehicles, min_routes_needed)

    routes = []
    for _ in range(initial_routes):
        routes.append([depot_idx, depot_idx])

    for pickup_idx, delivery_idx in pd_pairs:
        best_found = False
        best_route_idx = -1
        best_new_route = None
        best_cost = float('inf')

        for r_idx in range(len(routes)):
            new_route, cost = try_insert_into_route(routes[r_idx], pickup_idx, delivery_idx)
            if new_route is not None and cost < best_cost:
                best_cost = cost
                best_route_idx = r_idx
                best_new_route = new_route
                best_found = True

        if best_found:
            routes[best_route_idx] = best_new_route
        elif len(routes) < max_vehicles:
            new_route = [depot_idx, depot_idx]
            new_route, cost = try_insert_into_route(new_route, pickup_idx, delivery_idx)
            if new_route is not None:
                routes.append(new_route)
            else:
                for r_idx in range(len(routes)):
                    new_route, cost = find_best_insertion(routes[r_idx], pickup_idx, delivery_idx)
                    if new_route is not None:
                        routes[r_idx] = new_route
                        best_found = True
                        break

    final_routes = []
    for route in routes:
        if len(route) > 2:
            final_routes.append(route)

    def two_opt(route):
        if len(route) <= 3:
            return route

        improved = True
        best_route = route[:]
        best_cost = calculate_route_cost(best_route)

        while improved:
            improved = False
            for i in range(1, len(best_route) - 2):
                for j in range(i + 1, len(best_route) - 1):
                    new_route = best_route[:i] + best_route[i:j+1][::-1] + best_route[j+1:]
                    if calculate_load_on_route(new_route) <= capacity and check_time_windows(new_route):
                        new_cost = calculate_route_cost(new_route)
                        if new_cost < best_cost:
                            best_route = new_route
                            best_cost = new_cost
                            improved = True
                            break
                if improved:
                    break
        return best_route

    for i in range(len(final_routes)):
        final_routes[i] = two_opt(final_routes[i])

    def or_opt(route):
        if len(route) <= 3:
            return route

        best_route = route[:]
        best_cost = calculate_route_cost(best_route)

        for seg_len in [1, 2, 3]:
            for i in range(1, len(best_route) - seg_len):
                segment = best_route[i:i+seg_len]
                remaining = best_route[:i] + best_route[i+seg_len:]

                for j in range(1, len(remaining)):
                    new_route = remaining[:j] + segment + remaining[j:]
                    if calculate_load_on_route(new_route) <= capacity and check_time_windows(new_route):
                        new_cost = calculate_route_cost(new_route)
                        if new_cost < best_cost:
                            best_route = new_route
                            best_cost = new_cost
                            break
                if best_route != route:
                    break
        return best_route

    for i in range(len(final_routes)):
        final_routes[i] = or_opt(final_routes[i])

    output_routes = []
    for route in final_routes:
        output_route = [idx_to_node[idx] for idx in route]
        output_routes.append(output_route)

    routes = output_routes

    with open(solution_file, 'w') as f:
        f.write(f"{instance.name}\n")
        for route in routes:
            f.write(" ".join(map(str, route)) + "\n")

