def get_genotype_map(n_alleles):
    """Generates mapping between genotype index and (allele1, allele2)."""
    if n_alleles == 0:
        return [(0, 0)]
    pairs = []
    for a in range(1, n_alleles + 1):
        for b in range(a, n_alleles + 1):
            pairs.append((a, b))
    return pairs

def get_unary_cost_and_valid(observed, n_alleles):
    """Computes unary cost and valid genotypes for an individual."""
    if n_alleles == 0:
        return np.array([0], dtype=np.int32), np.array([True], dtype=bool)

    d = n_alleles * (n_alleles + 1) // 2
    costs = np.zeros(d, dtype=np.int32)
    valid = np.ones(d, dtype=bool)

    o1, o2 = observed
    observed_alleles = [x for x in [o1, o2] if x != 0]

    if len(observed_alleles) == 0:
        return costs, valid

    idx = 0
    for a in range(1, n_alleles + 1):
        for b in range(a, n_alleles + 1):
            if len(observed_alleles) == 1:
                val = observed_alleles[0]
                if a != val and b != val:
                    costs[idx] = 1
                    valid[idx] = False
            else:
                if not ((a == observed_alleles[0] and b == observed_alleles[1]) or
                        (a == observed_alleles[1] and b == observed_alleles[0])):
                    costs[idx] = 1
                    valid[idx] = False
            idx += 1

    return costs, valid

def build_valid_tables_optimized(n_alleles):
