def solve_component(component_data):
    """Solves a single connected component with optimizations."""
    individuals, families, n_alleles, orig_indices = component_data

    m = len(individuals)
    if m == 0:
        return {idx: 0 for idx in orig_indices.values()}

    valid_children_list, valid_single_list, d, genotype_pairs = build_valid_tables_optimized(n_alleles)
    INF = 10**9

    # Initialize Unary Costs and valid domains
    unary_costs = np.zeros((m, d), dtype=np.int32)
    unary_valid = np.ones((m, d), dtype=bool)
    for i, ind in enumerate(individuals):
        costs, valid = get_unary_cost_and_valid((ind['a1'], ind['a2']), n_alleles)
        unary_costs[i] = costs
        unary_valid[i] = valid

    # Prune domains using arc consistency
    domains = prune_domains(m, families, n_alleles, unary_valid)

    # Build adjacency for VE
    adj = [set() for _ in range(m)]
    child_count = np.zeros(m, dtype=int)
    for fam in families:
        p1, p2, c = fam['p1'], fam['p2'], fam['c']
        if c != -1:
            child_count[c] += 1
            if p1 != -1:
                adj[c].add(p1)
                adj[p1].add(c)
            if p2 != -1:
                adj[c].add(p2)
                adj[p2].add(c)

    # Factors with domain pruning
    factors = {}
    for i in range(m):
        # Apply domain pruning to unary costs
        costs = unary_costs[i].copy()
        costs[~domains[i]] = INF
        factors[(i,)] = costs

    elimination_order = []
    backpointers = {}
    remaining = set(range(m))
    current_adj = [set(neighbors) for neighbors in adj]

    while remaining:
        # Min-fill heuristic with child priority
        best_var = -1
        best_fill = float('inf')
        best_degree = float('inf')

        for i in remaining:
            neighbors = list(current_adj[i] & remaining)
            fill_in = 0
            for j_idx, j in enumerate(neighbors):
                for k in neighbors[j_idx+1:]:
                    if k not in current_adj[j]:
                        fill_in += 1

            degree = len(neighbors)
            if (child_count[i], fill_in, degree) < (child_count[best_var] if best_var != -1 else float('inf'), 
                                                     best_fill, best_degree):
                best_var = i
                best_fill = fill_in
                best_degree = degree

        if best_var == -1:
            break

        X = best_var
        remaining.remove(X)
        elimination_order.append(X)
        neighbors = list(current_adj[X] & remaining)

        involved_scopes = [s for s in list(factors.keys()) if X in s]

        if not involved_scopes:
            ft = factors.get((X,), np.full(d, INF, dtype=np.int32))
            valid_mask = domains[X] if X < len(domains) else np.ones(d, dtype=bool)
            ft_copy = ft.copy()
            ft_copy[~valid_mask] = INF
            best_g = int(np.argmin(ft_copy))
            backpointers[X] = ((), best_g)
            if (X,) in factors:
                del factors[(X,)]
            continue

        all_vars = set()
        for s in involved_scopes:
            all_vars.update(s)
        all_vars.discard(X)
        new_scope_vars = sorted(list(all_vars))
        new_scope = tuple(new_scope_vars)

        fac_data = []
        for s in involved_scopes:
            fac_data.append((factors[s], s))
            del factors[s]

        if new_scope:
            new_shape = [d] * len(new_scope_vars)
            best_table = np.full(new_shape, INF, dtype=np.int32)
            best_arg = np.full(new_shape, -1, dtype=np.int16)

            for x_val in range(d):
                if X < len(domains) and not domains[X][x_val]:
                    continue

                current_sum = np.zeros(new_shape, dtype=np.int32)

                for ft, fs in fac_data:
                    if X in fs:
                        x_dim = fs.index(X)
                        fs_no_x = tuple(v for v in fs if v != X)

                        if len(fs) == 1:
                            current_sum += int(ft[x_val])
                        else:
                            slices = [slice(None)] * len(fs)
                            slices[x_dim] = x_val
                            ft_slice = ft[tuple(slices)]

                            if len(fs_no_x) > 0:
                                b_shape = [1] * len(new_scope_vars)
                                perm = []
                                for v_idx, v in enumerate(new_scope_vars):
                                    if v in fs_no_x:
                                        b_shape[v_idx] = d
                                        perm.append(fs_no_x.index(v))

                                if perm:
                                    ft_trans = np.transpose(ft_slice, perm)
                                else:
                                    ft_trans = ft_slice

                                current_sum += ft_trans.reshape(b_shape)
                    else:
                        current_sum += ft

                mask = current_sum < best_table
                if np.any(mask):
                    best_table[mask] = current_sum[mask]
                    best_arg[mask] = x_val

            factors[new_scope] = best_table
            backpointers[X] = (new_scope, best_arg)
        else:
            best_val = INF
            best_idx = 0
            for x_val in range(d):
                if X < len(domains) and not domains[X][x_val]:
                    continue
                current_sum = 0
                for ft, fs in fac_data:
                    if X in fs:
                        x_dim = fs.index(X)
                        slices = [slice(None)] * len(fs)
                        slices[x_dim] = x_val
                        ft_slice = ft[tuple(slices)]
                        current_sum += int(np.min(ft_slice)) if ft_slice.size > 0 else int(ft_slice)
                    else:
                        current_sum += int(np.min(ft)) if ft.size > 0 else int(ft)

                if current_sum < best_val:
                    best_val = current_sum
                    best_idx = x_val

            factors[()] = best_val
            backpointers[X] = ((), best_idx)

        for i, nb1 in enumerate(neighbors):
            for nb2 in neighbors[i+1:]:
                current_adj[nb1].add(nb2)
                current_adj[nb2].add(nb1)

    assignment = {}
    for X in reversed(elimination_order):
        scope, bp_table = backpointers[X]
        if not scope:
            assignment[X] = int(bp_table)
        else:
            key = tuple(assignment[v] for v in scope)
            assignment[X] = int(bp_table[key])

    result_dict = {}
    for local_idx, global_idx in orig_indices.items():
        result_dict[global_idx] = assignment.get(local_idx, 0)

    return result_dict

def solve(input_file: str, solution_file: str):
    lines = []
    with open(input_file, 'r') as f:
        for line in f:
            line = line.strip()
            if line:
                lines.append(line.split())

    if not lines:
        with open(solution_file, 'w') as f:
            f.write("")
        return

    id_to_data = {}
    all_alleles = set()
    input_order_ids = []

    for parts in lines:
        iid = parts[1]
        fid = parts[2]
        mid = parts[3]
        a1 = int(parts[5])
        a2 = int(parts[6])

        input_order_ids.append(iid)
        id_to_data[iid] = {
            'id': iid,
            'father': fid,
            'mother': mid,
            'a1': a1,
            'a2': a2
        }
        if a1 > 0:
            all_alleles.add(a1)
        if a2 > 0:
            all_alleles.add(a2)

    n_alleles = max(all_alleles) if all_alleles else 0

    G = nx.Graph()
    for iid in id_to_data:
        G.add_node(iid)
        data = id_to_data[iid]
        if data['father'] != '0' and data['father'] in id_to_data:
            G.add_edge(iid, data['father'])
        if data['mother'] != '0' and data['mother'] in id_to_data:
            G.add_edge(iid, data['mother'])

    components = list(nx.connected_components(G))

    tasks = []
    for comp in components:
        comp_ids = list(comp)
        local_map = {iid: i for i, iid in enumerate(comp_ids)}

        individuals = []
        families = []

        for iid in comp_ids:
            data = id_to_data[iid]
            individuals.append({
                'id': iid,
                'a1': data['a1'],
                'a2': data['a2']
            })
            f_id = data['father']
            m_id = data['mother']

            p1 = local_map.get(f_id, -1) if f_id != '0' else -1
            p2 = local_map.get(m_id, -1) if m_id != '0' else -1
            c = local_map[iid]

            if f_id != '0' or m_id != '0':
                families.append({'p1': p1, 'p2': p2, 'c': c})

        orig_indices = {}
        for i, iid in enumerate(comp_ids):
            idx = input_order_ids.index(iid)
            orig_indices[i] = idx

        tasks.append((individuals, families, n_alleles, orig_indices))

    final_assignments = {}

    if len(tasks) > 1:
        with mp.Pool(processes=min(8, len(tasks))) as pool:
            for res_dict in pool.imap(solve_component, tasks):
                final_assignments.update(res_dict)
    else:
        final_assignments = solve_component(tasks[0])

    output_indices = []
    for iid in input_order_ids:
        output_indices.append(str(final_assignments.get(iid, 0)))

    with open(solution_file, 'w') as f:
        f.write(" ".join(output_indices))

if __name__ == '__main__':
