import re
from collections import defaultdict, deque
from typing import Dict, Set, List, Tuple, Optional

K = 6

def parse_blif(filename: str):
    """Parse BLIF file and return circuit information."""
    with open(filename, 'r') as f:
        content = f.read()

    lines = []
    for line in content.split('\n'):
        if '#' in line:
            line = line[:line.index('#')]
        lines.append(line.rstrip())

    joined = []
    current = ""
    for line in lines:
        if line.endswith('\\'):
            current += line[:-1] + " "
        else:
            current += line
            if current.strip():
                joined.append(current.strip())
            current = ""

    pis = set()
    pos = set()
    gates = {}

    i = 0
    while i < len(joined):
        parts = joined[i].split()
        if not parts:
            i += 1
            continue

        cmd = parts[0]
        if cmd == '.inputs':
            pis.update(parts[1:])
        elif cmd == '.outputs':
            pos.update(parts[1:])
        elif cmd == '.names':
            gate_parts = parts[1:]
            output = gate_parts[-1]
            inputs = tuple(gate_parts[:-1])

            tt = []
            i += 1
            while i < len(joined):
                if joined[i].startswith('.'):
                    break
                tt_line = joined[i].split()
                if tt_line:
                    tt.append(tt_line)
                i += 1
            gates[output] = (inputs, tt)
            continue

        i += 1

    return pis, pos, gates

def build_graph(gates: Dict):
    """Build dependency graph from gates."""
    gate_inputs = {}
    for gate_name, (inputs, tt) in gates.items():
        gate_inputs[gate_name] = list(inputs)

    fanin = defaultdict(set)
    fanout = defaultdict(set)

    for gate_name, inputs in gate_inputs.items():
        for inp in inputs:
            if inp in gates:
                fanin[gate_name].add(inp)
                fanout[inp].add(gate_name)

    return gate_inputs, fanin, fanout

def topological_sort(gates: Dict, gate_inputs: Dict, fanout: Dict):
    """Perform topological sort on the gate graph."""
    in_degree = {g: 0 for g in gates}
    for gate_name, inputs in gate_inputs.items():
        for inp in inputs:
            if inp in gates:
                in_degree[gate_name] += 1

    topo_order = []
    queue = deque([g for g in gates if in_degree[g] == 0])

    while queue:
        node = queue.popleft()
        topo_order.append(node)
        for fan in fanout[node]:
            if fan in in_degree:
                in_degree[fan] -= 1
                if in_degree[fan] == 0:
                    queue.append(fan)

    return topo_order

def get_cone_inputs(cone: Set, gate_inputs: Dict, all_gates: Set, pis: Set) -> Set:
    """Get the input signals to a cone (external inputs)."""
    inputs = set()
    for n in cone:
        for inp in gate_inputs.get(n, []):
            if inp not in cone:
                inputs.add(inp)
    return inputs

def extract_maximal_k_cone(root: str, gate_inputs: Dict, all_gates: Set, 
                           pis: Set, K: int, covered: Set, topo_order: List) -> Set:
    """Extract a maximal K-feasible cone rooted at root using greedy approach."""
    cone = {root}

    while True:
        best_add = None

        for node in list(all_gates - cone - covered):
            if node in gate_inputs:
                node_fanin = set(gate_inputs[node])
                if node_fanin <= cone:
                    test_cone = cone | {node}
                    test_inputs = get_cone_inputs(test_cone, gate_inputs, all_gates, pis)
                    if len(test_inputs) <= K:
                        if best_add is None:
                            best_add = node

        if best_add is None:
            break
        cone.add(best_add)

    return cone

def evaluate_gate(node_inputs: List, node_tt: List, signal_values: Dict) -> int:
    """Evaluate a gate given input signal values."""
    for row in node_tt:
        if len(row) >= 2:
            input_pattern = row[0]
            out_val = row[1]
        else:
            input_pattern = row[0]
            out_val = '1'

        match = True
        for j, ch in enumerate(input_pattern):
            if ch == '-':
                continue
            if j < len(node_inputs):
                inp_name = node_inputs[j]
                if inp_name in signal_values:
                    expected = int(ch)
                    if signal_values[inp_name] != expected:
                        match = False
                        break
                else:
                    match = False
                    break

        if match:
            return 1 if out_val == '1' else 0

    return 0

def compute_lut_truth_table(cone: Set, root: str, gate_inputs: Dict, gates: Dict, 
                            input_list: List, topo_order: List) -> List:
    """Compute the truth table for a LUT implementing a cone."""
    num_inputs = len(input_list)

    if num_inputs == 0:
        signal_values = {}
        for node in cone:
            node_inputs_list = gate_inputs.get(node, [])
            node_tt = gates[node][1]
            signal_values[node] = evaluate_gate(node_inputs_list, node_tt, signal_values)
        val = signal_values.get(root, 0)
        return [['', '1']] if val == 1 else [['', '0']]

    on_set = set()

    for pattern in range(1 << num_inputs):
        signal_values = {}
        for i, inp in enumerate(input_list):
            signal_values[inp] = (pattern >> i) & 1

        nodes_in_order = sorted(cone, key=lambda x: topo_order.index(x) if x in topo_order else len(topo_order))

        for node in nodes_in_order:
            node_inputs_list = gate_inputs.get(node, [])
            node_tt = gates[node][1]
            signal_values[node] = evaluate_gate(node_inputs_list, node_tt, signal_values)

        if signal_values.get(root, 0) == 1:
            on_set.add(pattern)

    tt = []
    for pattern in sorted(on_set):
        row = ''
        for i in range(num_inputs):
            row += '1' if (pattern >> i) & 1 else '0'
        tt.append([row, '1'])

    if not tt:
        tt = [['0' * num_inputs, '0']]

    return tt

def solve(input_file: str, solution_file: str):
    """Solve the technology mapping optimization problem."""
    pis, pos, gates = parse_blif(input_file)

    if not gates:
        with open(solution_file, 'w') as f:
            f.write(".model mapped\n")
            f.write(".inputs " + " ".join(sorted(pis)) + "\n")
            f.write(".outputs " + " ".join(sorted(pos)) + "\n")
            f.write(".end\n")
        return

    gate_inputs, fanin, fanout = build_graph(gates)
    topo_order = topological_sort(gates, gate_inputs, fanout)
    all_gates = set(gates.keys())

    covered = set()
    lut_list = []

    processing_order = list(reversed(topo_order))

    for gate_name in processing_order:
        if gate_name in covered or gate_name not in gates:
            continue

        cone = extract_maximal_k_cone(
            gate_name, gate_inputs, all_gates, pis, K, covered, topo_order
        )

        cone_inputs = get_cone_inputs(cone, gate_inputs, all_gates, pis)
        input_list = sorted(cone_inputs)

        # Ensure we don't exceed K inputs
        if len(input_list) > K:
            cone = {gate_name}
            cone_inputs = get_cone_inputs(cone, gate_inputs, all_gates, pis)
            input_list = sorted(cone_inputs)

        # Still might have > K inputs if gate has many direct PI inputs
        if len(input_list) > K:
            input_list = input_list[:K]

        num_inputs = len(input_list)

        if len(cone) == 1:
            orig_inputs, orig_tt = gates[gate_name]
            # Filter truth table rows to match actual input count
            tt = []
            for row in orig_tt:
                if len(row) >= 2:
                    pattern, val = row[0], row[1]
                else:
                    pattern, val = row[0], '1'
                # Only include rows that match the input count
                if len(pattern) == len(orig_inputs):
                    tt.append([pattern, val])
            lut_list.append((input_list, gate_name, tt))
        else:
            tt = compute_lut_truth_table(cone, gate_name, gate_inputs, gates, input_list, topo_order)
            lut_list.append((input_list, gate_name, tt))

        for g in cone:
            covered.add(g)

    for gate_name in gates:
        if gate_name not in covered:
            inputs = gate_inputs.get(gate_name, [])
            tt = gates[gate_name][1]
            if len(inputs) > K:
                inputs = inputs[:K]
            lut_list.append((inputs, gate_name, tt))
            covered.add(gate_name)

    with open(solution_file, 'w') as f:
        f.write(".model mapped\n")
        f.write(".inputs " + " ".join(sorted(pis)) + "\n")
        f.write(".outputs " + " ".join(sorted(pos)) + "\n")

        for inputs, output, tt in lut_list:
            if inputs:
                f.write(".names " + " ".join(inputs) + " " + output + "\n")
            else:
                f.write(".names " + output + "\n")
            for row in tt:
                if len(row) >= 2:
                    f.write(row[0] + " " + row[1] + "\n")
                else:
                    f.write(row[0] + "\n")

        f.write(".end\n")

if __name__ == "__main__":
    import sys
    if len(sys.argv) >= 3:
        solve(sys.argv[1], sys.argv[2])

