    output_blif = generate_output_blif(mapping, circuit)

    # Write output
    with open(solution_file, 'w') as f:
        f.write(output_blif)

def parse_blif(content):
    """Parse BLIF content into a circuit structure."""
    lines = content.split('\n')
    circuit = {
        'name': None,
        'inputs': [],
        'outputs': [],
        'names': []
    }

    i = 0
    while i < len(lines):
        line = lines[i].strip()

        # Skip empty lines and comments
        if not line or line.startswith('#'):
            i += 1
            continue

        # Handle line continuation
        while line.endswith('\\'):
            i += 1
            line = line[:-1] + lines[i].strip()

        if line.startswith('.model'):
            parts = line.split()
            circuit['name'] = parts[1]

        elif line.startswith('.inputs'):
            parts = line.split()
            circuit['inputs'].extend(parts[1:])

        elif line.startswith('.outputs'):
            parts = line.split()
            circuit['outputs'].extend(parts[1:])

        elif line.startswith('.names'):
            # Parse .names block
            name_parts = line.split()
            inputs = name_parts[1:-1]
            output = name_parts[-1]

            # Read truth table rows
            i += 1
            truth_table = []
            while i < len(lines):
                row_line = lines[i].strip()
                if not row_line or row_line.startswith('#'):
                    i += 1
                    continue
                if row_line.startswith('.') or row_line.startswith('.names'):
                    i -= 1
                    break
                # Handle continuation in truth table
                while row_line.endswith('\\'):
                    i += 1
                    row_line = row_line[:-1] + lines[i].strip()
                truth_table.append(row_line)
                i += 1

            circuit['names'].append({
                'inputs': inputs,
                'output': output,
                'truth_table': truth_table
            })
            continue

        elif line.startswith('.end'):
            break

        i += 1

    return circuit

def build_graph(circuit):
    """Build a directed graph from the circuit."""
    graph = {
        'nodes': set(),
        'edges': [],
        'pi': set(circuit['inputs']),
        'po': set(circuit['outputs']),
        'functions': {},  # node -> (inputs, truth_table)
        'fanout': defaultdict(list),  # node -> list of successors
        'fanin': defaultdict(list),   # node -> list of predecessors
    }

    # Add all nodes
    graph['nodes'].update(circuit['inputs'])
    graph['nodes'].update(circuit['outputs'])

    # Process .names blocks
    for block in circuit['names']:
        output = block['output']
        inputs = block['inputs']
        truth_table = block['truth_table']

        graph['nodes'].add(output)
        graph['functions'][output] = (inputs, truth_table)

        # Add edges from inputs to output
        for inp in inputs:
            if inp not in circuit['inputs']:  # Not a PI
                graph['nodes'].add(inp)
            graph['edges'].append((inp, output))
            graph['fanout'][inp].append(output)
            graph['fanin'][output].append(inp)

    # Remove PI from fanin
    for pi in circuit['inputs']:
        if pi in graph['fanin']:
            del graph['fanin'][pi]

    return graph

def topological_sort(graph):
    """Topological sort of the graph."""
    indegree = defaultdict(int)
    for node in graph['nodes']:
        indegree[node] = 0

    for u, v in graph['edges']:
        indegree[v] += 1

    queue = deque()
    for node in graph['nodes']:
        if indegree[node] == 0:
            queue.append(node)

    topo_order = []
    while queue:
        u = queue.popleft()
        topo_order.append(u)
        for v in graph['fanout'][u]:
            indegree[v] -= 1
            if indegree[v] == 0:
                queue.append(v)

    return topo_order

def compute_cone(graph, root, max_inputs=6):
    """Compute all K-feasible cones for a given root."""
    # Get all predecessors in topological order
    topo = topological_sort(graph)
    node_index = {node: i for i, node in enumerate(topo)}

    # Get all ancestors of root
    ancestors = set()
    queue = deque([root])
    while queue:
        node = queue.popleft()
        for pred in graph['fanin'][node]:
            if pred not in ancestors and pred not in graph['pi']:
                ancestors.add(pred)
                queue.append(pred)

    # Sort ancestors by topological order (reverse)
    sorted_ancestors = sorted(ancestors, key=lambda x: node_index[x], reverse=True)

    # Try to find all K-feasible cones
    cones = []

    # Use a recursive approach to find cones
    def find_cones(current_nodes, remaining_ancestors, current_inputs):
        if len(current_inputs) > max_inputs:
            return

        # Check if current cone is valid
        if len(current_nodes) > 0:
            # Count inputs
            if len(current_inputs) <= max_inputs:
                cones.append((frozenset(current_nodes), frozenset(current_inputs)))

        # Try adding more nodes
        for i, node in enumerate(remaining_ancestors):
            # Check if node can be added
            # Node's fanin must be subset of current_nodes + PIs
            node_fanin = set(graph['fanin'].get(node, []))
            if not node_fanin.issubset(current_nodes | graph['pi']):
