    import json
    from collections import deque, defaultdict
    import heapq

    with open(input_file, "r") as f:
        data = json.load(f)

    delay_by_type = data["delay"]
    capacity_by_type = data["resource"]
    nodes_in = data["nodes"]
    edges_in = data["edges"]

    n = len(nodes_in)
    id_to_idx = {}
    idx_to_id = [None] * n
    rtype = [None] * n
    dur = [0] * n

    for i, (nid, rt) in enumerate(nodes_in):
        id_to_idx[nid] = i
        idx_to_id[i] = nid
        rtype[i] = rt
        dur[i] = int(delay_by_type[rt])

    succ = [[] for _ in range(n)]
    pred = [[] for _ in range(n)]
    indeg = [0] * n
    outdeg = [0] * n

    for e in edges_in:
        u = id_to_idx[e[0]]
        v = id_to_idx[e[1]]
        succ[u].append(v)
        pred[v].append(u)
        indeg[v] += 1
        outdeg[u] += 1

    q = deque([i for i in range(n) if indeg[i] == 0])
    topo = []
    indeg_tmp = indeg[:]
    while q:
        u = q.popleft()
        topo.append(u)
        for v in succ[u]:
            indeg_tmp[v] -= 1
            if indeg_tmp[v] == 0:
                q.append(v)

    if len(topo) != n:
        with open(solution_file, "w") as f:
            for nid in idx_to_id:
                f.write(f"{nid}:0\n")
        return

    est = [0] * n
    for u in topo:
        tu = est[u] + dur[u]
        for v in succ[u]:
            if tu > est[v]:
                est[v] = tu

    rev_topo = topo[::-1]
    cp_len = [0] * n
    for u in rev_topo:
        best = 0
        for v in succ[u]:
            if cp_len[v] > best:
                best = cp_len[v]
        cp_len[u] = dur[u] + best

    priority = [0] * n
    for i in range(n):
        priority[i] = cp_len[i]

    ready_count = [len(pred[i]) for i in range(n)]
    pred_finish_heap = [[] for _ in range(n)]
    unscheduled = set(range(n))
    start = [-1] * n

    usage = {rt: [] for rt in capacity_by_type}
    active_by_type = {rt: [] for rt in capacity_by_type}

    future_events = []
    for i in range(n):
        if ready_count[i] == 0:
            heapq.heappush(future_events, (0, i))

    ready_by_type = {rt: [] for rt in capacity_by_type}

    scheduled_cnt = 0
    current_time = 0

    while scheduled_cnt < n:
        while future_events and future_events[0][0] <= current_time:
            t, u = heapq.heappop(future_events)
            if start[u] != -1:
                continue
            rt = rtype[u]
            heapq.heappush(ready_by_type[rt], (-priority[u], est[u], u))

        progress = True
        while progress:
            progress = False
            for rt, cap in capacity_by_type.items():
                if cap <= 0:
                    continue
                if rt not in active_by_type:
                    active_by_type[rt] = []
                active = active_by_type[rt]
                while active and active[0] <= current_time:
                    heapq.heappop(active)
                avail = cap - len(active)
                if avail <= 0:
                    continue

                rb = ready_by_type[rt]
                while avail > 0 and rb:
                    _, _, u = heapq.heappop(rb)
                    if start[u] != -1:
                        continue
                    if est[u] > current_time:
                        heapq.heappush(future_events, (est[u], u))
                        continue

                    start[u] = current_time
                    scheduled_cnt += 1
                    finish = current_time + dur[u]
                    heapq.heappush(active, finish)

                    for v in succ[u]:
                        ready_count[v] -= 1
                        if finish > est[v]:
                            est[v] = finish
                        if ready_count[v] == 0:
                            heapq.heappush(future_events, (est[v], v))

                    avail -= 1
                    progress = True

        if scheduled_cnt >= n:
            break

        next_time = None
        for rt in capacity_by_type:
            active = active_by_type[rt]
            if active:
                t = active[0]
                if t > current_time and (next_time is None or t < next_time):
                    next_time = t
        if future_events:
            t = future_events[0][0]
            if t > current_time and (next_time is None or t < next_time):
                next_time = t

        if next_time is None:
            next_time = current_time + 1
        current_time = next_time

    with open(solution_file, "w") as f:
        out = [f"{idx_to_id[i]}:{start[i] if start[i] >= 0 else 0}\n" for i in range(n)]
        f.writelines(out)

