    with open(cap_file, "r") as f:
        a = f.readline().split()
        nLayers = int(a[0])
        xSize = int(a[1])
        ySize = int(a[2])

        second = f.readline().split()
        unit_wire = float(second[0])
        unit_via = float(second[1])

        hlen = list(map(int, f.readline().split())) if xSize > 1 else []
        vlen = list(map(int, f.readline().split())) if ySize > 1 else []

        layer_dir = [0] * nLayers
        for z in range(nLayers):
            p = f.readline().split()
            layer_dir[z] = int(p[1])
            for _ in range(ySize):
                f.readline()

    hps = [0] * xSize
    for i in range(xSize - 1):
        hps[i + 1] = hps[i] + hlen[i]
    vps = [0] * ySize
    for i in range(ySize - 1):
        vps[i + 1] = vps[i] + vlen[i]

    hz_layers = [z for z in range(1, nLayers) if layer_dir[z] == 0]
    vt_layers = [z for z in range(1, nLayers) if layer_dir[z] == 1]
    if not hz_layers:
        hz_layers = [1 if nLayers > 1 else 0]
    if not vt_layers:
        vt_layers = [1 if nLayers > 1 else 0]

    def wlx(x1, x2):
        if x1 > x2:
            x1, x2 = x2, x1
        return hps[x2] - hps[x1]

    def wly(y1, y2):
        if y1 > y2:
            y1, y2 = y2, y1
        return vps[y2] - vps[y1]

    def normz(z):
        return 1 if z == 0 and nLayers > 1 else z

    def add_seg(out, x1, y1, z1, x2, y2, z2):
        if x1 == x2 and y1 == y2 and z1 == z2:
            return
        if x1 > x2:
            x1, x2 = x2, x1
        if y1 > y2:
            y1, y2 = y2, y1
        if z1 > z2:
            z1, z2 = z2, z1
        out.append((x1, y1, z1, x2, y2, z2))

    def path_cost(root, ap, hz, vt):
        rz, rx, ry = root
        pz, px, py = ap
        rz1 = normz(rz)
        pz1 = normz(pz)
        return unit_wire * (wlx(rx, px) + wly(ry, py)) + unit_via * (
            abs(rz1 - hz) + abs(hz - vt) + abs(vt - pz1) + (1 if rz == 0 and nLayers > 1 else 0) + (1 if pz == 0 and nLayers > 1 else 0)
        )

    def choose_root(pin):
        best = None
        bestk = None
        for ap in pin:
            z, x, y = ap
            if 0 <= z < nLayers and 0 <= x < xSize and 0 <= y < ySize:
                nz = normz(z)
                for hz in hz_layers:
                    for vt in vt_layers:
                        k = (abs(nz - hz) + abs(hz - vt), nz, x, y, z)
                        if best is None or k < bestk:
                            best = ap
                            bestk = k
        if best is None:
            return (0, 0, 0)
        return best

    def choose_attach(root, pin):
        best = None
        bestc = None
        bestpair = None
        for ap in pin:
            z, x, y = ap
            if not (0 <= z < nLayers and 0 <= x < xSize and 0 <= y < ySize):
                continue
            for hz in hz_layers:
                for vt in vt_layers:
                    c = path_cost(root, ap, hz, vt)
                    if bestc is None or c < bestc:
                        bestc = c
                        best = ap
                        bestpair = (hz, vt)
        if best is None:
            return (0, 0, 0), (hz_layers[0], vt_layers[0])
        return best, bestpair

    def emit_path(root, ap, hv, out):
        hz, vt = hv
        rz, rx, ry = root
        pz, px, py = ap

        curz = rz
        if curz == 0 and nLayers > 1:
            add_seg(out, rx, ry, 0, rx, ry, 1)
            curz = 1

        if curz != hz:
            add_seg(out, rx, ry, curz, rx, ry, hz)
            curz = hz

        if rx != px:
            add_seg(out, rx, ry, curz, px, ry, curz)

        cx = px
        cy = ry
        if curz != vt:
            add_seg(out, cx, cy, curz, cx, cy, vt)
            curz = vt

        if cy != py:
            add_seg(out, cx, cy, curz, cx, py, curz)
            cy = py

        target_norm = normz(pz)
        if curz != target_norm:
            add_seg(out, cx, cy, curz, cx, cy, target_norm)
            curz = target_norm

        if pz == 0 and nLayers > 1:
            add_seg(out, px, py, 0, px, py, 1)

    with open(net_file, "r") as f:
        lines = [line.strip() for line in f]

    with open(solution_file, "w") as f:
        i = 0
        n = len(lines)
        while i < n:
            if not lines[i]:
                i += 1
                continue
            name = lines[i]
            i += 1
            while i < n and not lines[i]:
                i += 1
            if i >= n or lines[i] != "(":
                break
            i += 1
            pins = []
            while i < n:
                s = lines[i]
                i += 1
                if not s:
                    continue
                if s == ")":
                    break
                pins.append(ast.literal_eval(s))

            f.write(name + "\n")
            f.write("(\n")
            if pins:
                root = choose_root(pins[0])
                for pin in pins[1:]:
                    ap, hv = choose_attach(root, pin)
                    segs = []
                    emit_path(root, ap, hv, segs)
                    for seg in segs:
                        f.write(f"{seg[0]} {seg[1]} {seg[2]} {seg[3]} {seg[4]} {seg[5]}\n")
            f.write(")\n")

