import json
import heapq
from collections import defaultdict
import networkx as nx

def solve(input_file: str, solution_file: str):
    with open(input_file, 'r') as f:
        data = json.load(f)

    delay_map = data['delay']
    resource_map = data['resource']
    nodes_data = data['nodes']
    edges_data = data['edges']

    G = nx.DiGraph()
    node_to_resource = {}
    for node_id, res_type in nodes_data:
        G.add_node(node_id)
        node_to_resource[node_id] = res_type

    for source, target, _ in edges_data:
        G.add_edge(source, target)

    topo_order = list(nx.topological_sort(G))

    # Compute ASAP times
    asap = {}
    for node in topo_order:
        preds = list(G.predecessors(node))
        if not preds:
            asap[node] = 0
        else:
            max_pred = 0
            for pred in preds:
                finish = asap[pred] + delay_map[node_to_resource[pred]]
                if finish > max_pred:
                    max_pred = finish
            asap[node] = max_pred

    # Compute critical path length
    critical_length = 0
    for node in G.nodes():
        finish = asap[node] + delay_map[node_to_resource[node]]
        if finish > critical_length:
            critical_length = finish

    # Compute ALAP times
    alap = {}
    for node in reversed(topo_order):
        succs = list(G.successors(node))
        if not succs:
            alap[node] = critical_length - delay_map[node_to_resource[node]]
        else:
            min_succ = float('inf')
            for succ in succs:
                start = alap[succ] - delay_map[node_to_resource[node]]
                if start < min_succ:
                    min_succ = start
            alap[node] = min_succ

    # Compute mobility
    mobility = {}
    for node in G.nodes():
        mobility[node] = alap[node] - asap[node]

    # Compute longest path to sink
    dist_to_sink = {}
    for node in reversed(topo_order):
        succs = list(G.successors(node))
        if not succs:
            dist_to_sink[node] = delay_map[node_to_resource[node]]
        else:
            max_succ = 0
            for succ in succs:
                if dist_to_sink[succ] > max_succ:
                    max_succ = dist_to_sink[succ]
            dist_to_sink[node] = delay_map[node_to_resource[node]] + max_succ

    # Compute number of successors
    num_successors = {}
    for node in reversed(topo_order):
        succs = list(G.successors(node))
        num_successors[node] = len(succs)
        for succ in succs:
            num_successors[node] += num_successors[succ]

    def schedule_with_priority(priority_func):
        in_degree = {node: G.in_degree(node) for node in G.nodes()}
        ready_set = [node for node in G.nodes() if in_degree[node] == 0]
        event_heap = []
        resource_usage = defaultdict(lambda: defaultdict(int))
        node_start = {}
        current_time = 0
        scheduled_count = 0
        n = len(nodes_data)

        while scheduled_count < n:
            ready_set.sort(key=priority_func)
            scheduled_any = False

            for node in ready_set[:]:
                r = node_to_resource[node]
                d = delay_map[r]
                # Check resource availability
                can_schedule = True
                for t in range(current_time, current_time + d):
                    if resource_usage[r][t] >= resource_map[r]:
                        can_schedule = False
                        break

                if can_schedule:
                    node_start[node] = current_time
                    finish_time = current_time + d
                    heapq.heappush(event_heap, (finish_time, node))
                    for t in range(current_time, finish_time):
                        resource_usage[r][t] += 1
                    ready_set.remove(node)
                    scheduled_count += 1
                    scheduled_any = True

            if not scheduled_any and ready_set:
                if event_heap:
                    next_time, _ = event_heap[0]
                    current_time = next_time
                else:
                    break

            while event_heap and event_heap[0][0] == current_time:
                finish_time, node = heapq.heappop(event_heap)
                r = node_to_resource[node]
                start = node_start[node]
                for t in range(start, finish_time):
                    resource_usage[r][t] -= 1
                for succ in G.successors(node):
                    in_degree[succ] -= 1
                    if in_degree[succ] == 0:
                        ready_set.append(succ)

            if not scheduled_any and not ready_set and event_heap:
                next_time, _ = event_heap[0]
                current_time = next_time

        return node_start

    def compact_schedule(node_start):
        max_passes = 30
        for _ in range(max_passes):
            changed = False
            nodes_by_start = sorted(G.nodes(), key=lambda node: node_start[node], reverse=True)
            for node in nodes_by_start:
                r = node_to_resource[node]
                d = delay_map[r]
                current_start = node_start[node]
                earliest = 0
                for pred in G.predecessors(node):
                    finish_pred = node_start[pred] + delay_map[node_to_resource[pred]]
                    if finish_pred > earliest:
                        earliest = finish_pred
                if current_start > earliest:
                    other_usage = defaultdict(int)
                    for other_node in G.nodes():
                        if other_node != node:
                            other_r = node_to_resource[other_node]
                            other_start = node_start[other_node]
                            other_d = delay_map[other_r]
                            for t in range(other_start, other_start + other_d):
                                other_usage[(other_r, t)] += 1
                    for t in range(earliest, current_start):
                        can_move = True
                        for offset in range(d):
                            if other_usage[(r, t + offset)] >= resource_map[r]:
                                can_move = False
                                break
                        if can_move:
                            node_start[node] = t
                            changed = True
                            break
            if not changed:
                break
        return node_start

    def compute_cost(node_start):
        max_finish = 0
        for node in G.nodes():
            finish = node_start[node] + delay_map[node_to_resource[node]]
            if finish > max_finish:
                max_finish = finish
        return max_finish

    # Try different priority functions
    best_cost = float('inf')
    best_schedule = None

    priority_funcs = [
        lambda node: (mobility[node], -dist_to_sink[node]),
        lambda node: (mobility[node], -num_successors[node]),
        lambda node: (asap[node], -dist_to_sink[node]),
        lambda node: (alap[node], -dist_to_sink[node]),
        lambda node: (-dist_to_sink[node], mobility[node]),
        lambda node: (mobility[node], asap[node]),
    ]

    for priority_func in priority_funcs:
        node_start = schedule_with_priority(priority_func)
        node_start = compact_schedule(node_start)
        cost = compute_cost(node_start)
        if cost < best_cost:
            best_cost = cost
            best_schedule = node_start.copy()

    with open(solution_file, 'w') as f:
        for node_id, _ in nodes_data:
            f.write(f"{node_id}:{best_schedule[node_id]}\n")

