            topo_order.append(name)

    K = 6
    INF = 10**9

    # DP structures
    cost = {name: 0 if nodes[name].is_pi else INF for name in nodes}
    best_cut = {name: None for name in nodes}  # (leaves_set, cost)
    cuts = {name: [] for name in nodes}  # list of (leaves_set, cost)

    # Process in topological order
    for name in topo_order:
        node = nodes[name]
        if node.is_pi:
            continue

        candidate_cuts = []

        # Direct cut: if number of direct predecessors <= K
        if len(node.predecessors) <= K:
            leaves = frozenset(node.predecessors)
            cut_cost = 1 + sum(cost[p] for p in leaves)
            candidate_cuts.append((leaves, cut_cost))

        # Combine cuts from predecessors
        if node.predecessors:
            # Initialize with empty leaves set
            current_leaves_list = [frozenset()]
            for pred in node.predecessors:
                new_leaves_list = []
                for leaves_set in current_leaves_list:
                    for pred_leaves, _ in cuts[pred]:
                        new_leaves = leaves_set | pred_leaves
                        if len(new_leaves) <= K:
                            new_leaves_list.append(new_leaves)
                # Prune: keep top 10 by cost
                if new_leaves_list:
                    # Compute cost for each candidate
                    scored = []
                    for leaves_set in new_leaves_list:
                        cut_cost = 1 + sum(cost[leaf] for leaf in leaves_set)
                        scored.append((cut_cost, leaves_set))
                    scored.sort()
                    # Keep unique leaves sets with smallest cost
                    seen = set()
                    unique_scored = []
                    for cut_cost, leaves_set in scored:
                        if leaves_set not in seen:
                            seen.add(leaves_set)
                            unique_scored.append((leaves_set, cut_cost))
                    current_leaves_list = [ls for ls, _ in unique_scored[:10]]
                else:
                    current_leaves_list = []
            for leaves_set in current_leaves_list:
                cut_cost = 1 + sum(cost[leaf] for leaf in leaves_set)
                candidate_cuts.append((leaves_set, cut_cost))

        # If no candidate cuts (should not happen for non-PI), create a trivial cut with direct predecessors
        if not candidate_cuts:
            leaves = frozenset(node.predecessors)
            cut_cost = 1 + sum(cost[p] for p in leaves)
            candidate_cuts.append((leaves, cut_cost))

        # Keep top 10 cuts by cost
        candidate_cuts.sort(key=lambda x: x[1])
        unique_cuts = []
        seen_leaves = set()
        for leaves_set, cut_cost in candidate_cuts:
            if leaves_set not in seen_leaves:
                seen_leaves.add(leaves_set)
                unique_cuts.append((leaves_set, cut_cost))
        cuts[name] = unique_cuts[:10]

        # Update best cut and cost
        if cuts[name]:
            best_leaves, best_cost = min(cuts[name], key=lambda x: x[1])
            cost[name] = best_cost
            best_cut[name] = (best_leaves, best_cost)

    # Backtrack to select cones
    selected_cones = set()
    def backtrack(v):
        if v in selected_cones or nodes[v].is_pi:
            return
        selected_cones.add(v)
        if best_cut[v] is None:
            return
        leaves_set, _ = best_cut[v]
        for leaf in leaves_set:
            backtrack(leaf)

    for po in po_names:
        backtrack(po)

    # Generate truth tables for each selected cone
    def compute_truth_table(v, leaves_set):
        # Get all nodes in cone (v and internal nodes)
        cone_nodes = set()
        stack = [v]
        while stack:
            u = stack.pop()
            if u in cone_nodes:
                continue
            cone_nodes.add(u)
            for pred in nodes[u].predecessors:
                if pred not in leaves_set:
                    stack.append(pred)
        # Topological order of cone nodes
        indegree_cone = {u: 0 for u in cone_nodes}
        for u in cone_nodes:
            for pred in nodes[u].predecessors:
                if pred in cone_nodes:
                    indegree_cone[u] += 1
        queue = collections.deque([u for u in cone_nodes if indegree_cone[u] == 0])
        topo_cone = []
        while queue:
            u = queue.popleft()
            topo_cone.append(u)
            for succ in nodes[u].successors:
                if succ in cone_nodes:
                    indegree_cone[succ] -= 1
                    if indegree_cone[succ] == 0:
                        queue.append(succ)
        # Evaluate for all input combinations
        leaves_list = sorted(leaves_set)
        n = len(leaves_list)
        truth = []
        for bits in range(1 << n):
            values = {}
            for i, leaf in enumerate(leaves_list):
                values[leaf] = (bits >> (n - 1 - i)) & 1
            # Evaluate cone nodes in topological order
            for u in topo_cone:
                if u in values:
                    continue
                node_u = nodes[u]
                if not node_u.inputs:
                    # Constant node? Should not happen in cone
                    values[u] = 0
                    continue
                # Get input values
                input_vals = []
                for inp in node_u.inputs:
                    if inp in values:
                        input_vals.append(values[inp])
                    else:
                        # Should not happen
                        input_vals.append(0)
                # Evaluate truth table
                out_val = 0
                for pattern, out in node_u.truth_table:
                    match = True
                    for i, ch in enumerate(pattern):
                        if ch == '0' and input_vals[i] != 0:
                            match = False
                            break
                        elif ch == '1' and input_vals[i] != 1:
                            match = False
                            break
                    if match:
                        out_val = int(out)
                        break
                values[u] = out_val
            truth.append(values[v])
        # Convert to BLIF format
        rows = []
        for bits in range(1 << n):
            if truth[bits] == 1:
                pattern = ''.join(str((bits >> (n - 1 - i)) & 1) for i in range(n))
                rows.append(pattern + ' 1')
        return leaves_list, rows

    # Write output BLIF
    with open(solution_file, 'w') as f:
        f.write('.model mapped\n')
        # Write inputs
        f.write('.inputs')
        for pi in sorted(pi_names):
            f.write(' ' + pi)
        f.write('\n')
        # Write outputs
        f.write('.outputs')
        for po in sorted(po_names):
            f.write(' ' + po)
        f.write('\n')
        # Write LUTs
        for v in sorted(selected_cones):
            leaves_set, _ = best_cut[v]
            leaves_list, rows = compute_truth_table(v, leaves_set)
            f.write('.names')
            for leaf in leaves_list:
                f.write(' ' + leaf)
            f.write(' ' + v + '\n')
            for row in rows:
                f.write(row + '\n')
        f.write('.end\n')

