import json
import heapq
from collections import defaultdict, deque

def solve(input_file: str, solution_file: str):
    with open(input_file, 'r') as f:
        data = json.load(f)

    nodes_data = data['nodes']
    root_eclasses = data['root_eclasses']

    # Build data structures
    node_to_eclass = {}
    eclass_to_nodes = defaultdict(list)
    node_children = {}
    node_cost = {}

    for node_id, node_info in nodes_data.items():
        eclass = node_info['eclass']
        cost = node_info['cost']
        children = node_info['children']

        node_to_eclass[node_id] = eclass
        eclass_to_nodes[eclass].append(node_id)
        node_children[node_id] = children
        node_cost[node_id] = cost

    # Build parent relationships
    eclass_parents = defaultdict(set)
    for node_id, children in node_children.items():
        for child_eclass in children:
            eclass_parents[child_eclass].add(node_id)

    # Topological sort using Kahn's algorithm
    in_degree = defaultdict(int)
    for eclass in eclass_to_nodes:
        in_degree[eclass] = 0

    for node_id, children in node_children.items():
        for child_eclass in children:
            in_degree[child_eclass] += 1

    queue = deque()
    for eclass in eclass_to_nodes:
        if in_degree[eclass] == 0:
            queue.append(eclass)

    topo_order = []
    while queue:
        eclass = queue.popleft()
        topo_order.append(eclass)
        for node_id in eclass_to_nodes[eclass]:
            for child_eclass in node_children[node_id]:
                in_degree[child_eclass] -= 1
                if in_degree[child_eclass] == 0:
                    queue.append(child_eclass)

    # Dynamic programming with cycle detection
    dp = {}
    parent_choice = {}

    for eclass in reversed(topo_order):
        best_cost = float('inf')
        best_node = None

        for node_id in eclass_to_nodes[eclass]:
            cost = node_cost[node_id]
            valid = True

            for child_eclass in node_children[node_id]:
                if child_eclass not in dp:
                    valid = False
                    break
                cost += dp[child_eclass]

            if valid and cost < best_cost:
                best_cost = cost
                best_node = node_id

        if best_node is not None:
            dp[eclass] = best_cost
            parent_choice[eclass] = best_node

    # Extract solution
    selected_nodes = set()

    def extract_solution(eclass):
        if eclass not in parent_choice:
            return

        node_id = parent_choice[eclass]
        selected_nodes.add(node_id)

        for child_eclass in node_children[node_id]:
            extract_solution(child_eclass)

    for root_eclass in root_eclasses:
        extract_solution(root_eclass)

    # Write output
    with open(solution_file, 'w') as f:
        json.dump(list(selected_nodes), f)

mimo-v2-pro.pedigree:
import numpy as np
from collections import defaultdict, deque
from dataclasses import dataclass
from typing import List, Tuple, Dict, Any

@dataclass
class Factor:
    variables: List[int]
    table: np.ndarray

class EliminationRecord:
    def __init__(self, i: int, other_vars: List[int], backpointer: np.ndarray):
        self.i = i
        self.other_vars = other_vars
        self.backpointer = backpointer

def solve(input_file: str, solution_file: str):
    # Read input
    individuals = []
    id_to_index = {}
    with open(input_file, 'r') as f:
        for line in f:
            parts = line.strip().split()
            if not parts:
                continue
            locus = int(parts[0])
            ind_id = int(parts[1])
            father_id = int(parts[2])
            mother_id = int(parts[3])
            sex = int(parts[4])
            allele1 = int(parts[5])
            allele2 = int(parts[6])
            idx = len(individuals)
            id_to_index[ind_id] = idx
            individuals.append({
                'id': ind_id,
                'father_id': father_id,
                'mother_id': mother_id,
                'sex': sex,
                'allele1': allele1,
                'allele2': allele2,
                'index': idx
            })
    m = len(individuals)

    # Determine n (max allele)
    max_allele = 0
    for ind in individuals:
        if ind['allele1'] > 0:
            max_allele = max(max_allele, ind['allele1'])
        if ind['allele2'] > 0:
            max_allele = max(max_allele, ind['allele2'])
    n = max_allele if max_allele > 0 else 1

    # Precompute genotype mapping
    genotype_to_index = {}
    index_to_genotype = []
    for a in range(1, n+1):
        for b in range(a, n+1):
            idx = len(index_to_genotype)
            genotype_to_index[(a, b)] = idx
            index_to_genotype.append((a, b))
    K = len(index_to_genotype)

    # Precompute share_list and ternary_pairs
    share_list = [[] for _ in range(K)]
    ternary_pairs = [[] for _ in range(K)]
    for g_idx, (a, b) in enumerate(index_to_genotype):
        alleles_g = {a, b}
        # share_list
        for h_idx, (c, d) in enumerate(index_to_genotype):
            if {c, d} & alleles_g:
                share_list[g_idx].append(h_idx)
        # ternary_pairs
        for h1_idx, (c1, d1) in enumerate(index_to_genotype):
            for h2_idx, (c2, d2) in enumerate(index_to_genotype):
                # Check ternary condition
                if (a in {c1, d1} and b in {c2, d2}) or (a in {c2, d2} and b in {c1, d1}):
                    ternary_pairs[g_idx].append((h1_idx, h2_idx))

    # Build parent and children lists
    parents = [(-1, -1) for _ in range(m)]
    children = [[] for _ in range(m)]
    for ind in individuals:
        idx = ind['index']
        father_id = ind['father_id']
        mother_id = ind['mother_id']
        father_idx = id_to_index.get(father_id, -1) if father_id != 0 else -1
        mother_idx = id_to_index.get(mother_id, -1) if mother_id != 0 else -1
        parents[idx] = (father_idx, mother_idx)
        if father_idx != -1:
            children[father_idx].append(idx)
        if mother_idx != -1:
            children[mother_idx].append(idx)

    # Compute unary costs
    unary_costs = np.zeros((m, K), dtype=float)
    for ind in individuals:
        idx = ind['index']
        a1 = ind['allele1']
        a2 = ind['allele2']
        for g_idx, (g1, g2) in enumerate(index_to_genotype):
            if a1 == 0 and a2 == 0:
                cost = 0.0
            elif a1 != 0 and a2 != 0:
                # Both observed: must match exactly
                if (a1 == g1 and a2 == g2) or (a1 == g2 and a2 == g1):
                    cost = 0.0
                else:
                    cost = 1.0
            else:
                # One observed
                observed = a1 if a1 != 0 else a2
                if observed in {g1, g2}:
                    count = 0.0
                else:
                    count = 1.0
                cost = count
            unary_costs[idx, g_idx] = cost

    # Initialize factors and data structures
    factors_for_var = [[] for _ in range(m)]
    for i in range(m):
        factors_for_var[i].append(Factor(variables=[i], table=unary_costs[i].copy()))

    children_count = [len(children[i]) for i in range(m)]
    eliminated = [False] * m
    queue = deque([i for i in range(m) if children_count[i] == 0])
    elimination_records = []

    # Helper to remove factor from factors_for_var
    def remove_factor(factor: Factor):
        for var in factor.variables:
            if not eliminated[var]:
                try:
                    factors_for_var[var].remove(factor)
                except ValueError:
                    pass

    # Main elimination loop
    while queue:
        i = queue.popleft()
        if eliminated[i]:
            continue
        eliminated[i] = True

        # Collect factors involving i
        factors_i = factors_for_var[i][:]
        for factor in factors_i:
            remove_factor(factor)

        father, mother = parents[i]
        if father != -1 or mother != -1:
            # Eliminate as child
            unary_i = factors_i[0].table  # should be the only factor
            if father != -1 and mother != -1:
                # Both parents
                M = np.full((K, K), np.inf)
                best_i = np.full((K, K), -1, dtype=int)
                for g_i in range(K):
                    cost = unary_i[g_i]
                    if cost == np.inf:
                        continue
                    for g_f, g_m in ternary_pairs[g_i]:
                        if cost < M[g_f, g_m]:
                            M[g_f, g_m] = cost
                            best_i[g_f, g_m] = g_i
                        elif cost == M[g_f, g_m] and best_i[g_f, g_m] == -1:
                            best_i[g_f, g_m] = g_i
                new_factor = Factor(variables=[father, mother], table=M)
                factors_for_var[father].append(new_factor)
                factors_for_var[mother].append(new_factor)
                rec = EliminationRecord(i, [father, mother], best_i)
                elimination_records.append(rec)
            else:
                # One parent
                parent = father if father != -1 else mother
                V = np.full(K, np.inf)
                best_i = np.full(K, -1, dtype=int)
                for g_i in range(K):
                    cost = unary_i[g_i]
                    if cost == np.inf:
                        continue
                    for g_p in share_list[g_i]:
                        if cost < V[g_p]:
                            V[g_p] = cost
                            best_i[g_p] = g_i
                        elif cost == V[g_p] and best_i[g_p] == -1:
                            best_i[g_p] = g_i
                new_factor = Factor(variables=[parent], table=V)
                factors_for_var[parent].append(new_factor)
                rec = EliminationRecord(i, [parent], best_i)
                elimination_records.append(rec)
        else:
            # Eliminate as founder
            # Group factors by other variables
            groups = defaultdict(list)
            for factor in factors_i:
                other_vars = tuple(v for v in factor.variables if v != i)
                groups[other_vars].append(factor)
            combined_factors = []
            for other_vars, factor_list in groups.items():
                table_sum = sum(f.table for f in factor_list)
                combined_factors.append(Factor(variables=list(other_vars) + [i], table=table_sum))
            # Determine other variables
            other_vars_set = set()
            for factor in combined_factors:
                for v in factor.variables:
                    if v != i:
                        other_vars_set.add(v)
            other_vars_list = sorted(other_vars_set)
            if not other_vars_list:
                # No other variables
                vector_i = combined_factors[0].table
                min_cost = np.min(vector_i)
                best_i_index = np.argmin(vector_i)
                new_factor = Factor(variables=[], table=np.array(min_cost))
                rec = EliminationRecord(i, [], np.array(best_i_index))
                elimination_records.append(rec)
            else:
                # Assume one other variable
                j = other_vars_list[0]
                vector_i = None
                matrix_ij = None
                for factor in combined_factors:
                    if len(factor.variables) == 1 and factor.variables[0] == i:
                        vector_i = factor.table
                    elif len(factor.variables) == 2 and i in factor.variables and j in factor.variables:
                        matrix_ij = factor.table
                if vector_i is None:
                    vector_i = np.zeros(K)
                if matrix_ij is None:
                    matrix_ij = np.zeros((K, K))
                V_j = np.full(K, np.inf)
                best_i_for_j = np.full(K, -1, dtype=int)
                for g_i in range(K):
                    if vector_i[g_i] == np.inf:
                        continue
                    for g_j in range(K):
                        if matrix_ij[g_i, g_j] == np.inf:
                            continue
                        total = vector_i[g_i] + matrix_ij[g_i, g_j]
                        if total < V_j[g_j]:
                            V_j[g_j] = total
                            best_i_for_j[g_j] = g_i
                new_factor = Factor(variables=[j], table=V_j)
                factors_for_var[j].append(new_factor)
                rec = EliminationRecord(i, [j], best_i_for_j)
                elimination_records.append(rec)

        # Update children_count for parents
        for parent in parents[i]:
            if parent != -1 and not eliminated[parent]:
                children_count[parent] -= 1
                if children_count[parent] == 0:
                    queue.append(parent)

    # After elimination, get minimum cost from the last factor (should be constant)
    # The last factor is stored in the last elimination record's new_factor? Actually, we didn't store it globally.
    # Instead, we can compute the minimum cost from the final factor that remains.
    # Since all individuals are eliminated, there should be no factors left? Actually, the last factor is added to no variable.
    # We can keep track of the final factor during elimination.
    # Alternatively, we can compute the minimum cost from the last elimination record's backpointer? Not directly.
    # Let's modify: during elimination, when we create a new factor with empty variables, we store it as final_factor.
    final_factor = None
    for rec in elimination_records:
        if not rec.other_vars:
            # This is the final factor
            final_factor = rec.backpointer  # actually backpointer is the best genotype index, not the cost.
            break
    # Actually, we need the minimum cost. We can compute it from the final factor's table.
    # But we didn't store the final factor's table. Let's change: in the founder elimination with no other variables,
    # we created new_factor with table = min_cost. We should store that.
    # We'll recompute: after elimination, the minimum cost is the value of the last factor created.
    # We can keep a variable min_cost updated during elimination.
    # Instead, let's compute the minimum cost from the unary costs and constraints by evaluating the final assignment.
    # We'll compute the cost after backtracking.

    # Backtracking to assign genotypes
    assignment = [-1] * m
    for rec in reversed(elimination_records):
        i = rec.i
        if not rec.other_vars:
            # Founder alone
            assignment[i] = rec.backpointer.item() if isinstance(rec.backpointer, np.ndarray) else rec.backpointer
        elif len(rec.other_vars) == 1:
            j = rec.other_vars[0]
            g_j = assignment[j]
            if rec.backpointer.ndim == 1:
                assignment[i] = rec.backpointer[g_j]
            else:
                # This case shouldn't happen
                assignment[i] = rec.backpointer[g_j]
        elif len(rec.other_vars) == 2:
            father, mother = rec.other_vars
            g_f = assignment[father]
            g_m = assignment[mother]
            assignment[i] = rec.backpointer[g_f, g_m]

    # Compute the total cost of the assignment
    total_cost = 0.0
    for i in range(m):
        g_idx = assignment[i]
        total_cost += unary_costs[i, g_idx]
    # Note: binary and ternary constraints are satisfied by construction, so no infinite cost.

    # Convert assignment indices to genotype indices (already are)
    # Write output
    with open(solution_file, 'w') as f:
        f.write(' '.join(str(idx) for idx in assignment) + '\n')

if __name__ == "__main__":
    solve("input.pre", "output.txt")

