def solve(input_file: str, solution_file: str):
    from dataclasses import dataclass
    from typing import Dict, List, Tuple
    import os
    import math
    import random
    import time
    from copy import deepcopy

    @dataclass
    class Node:
        index: int
        x: float
        y: float
        demand: float
        earliest_time: float
        latest_time: float
        service_time: float
        pickup_sibling: int
        delivery_sibling: int
        is_pickup: bool

    @dataclass
    class Instance:
        name: str
        type: str
        dimension: int
        vehicles: int
        capacity: float
        edge_weight_type: str
        nodes: Dict[int, Node]
        depot_node: List[int]

    def read_instance(file_path: str) -> Instance:
        with open(file_path, "r") as file:
            lines = file.readlines()
        name = type_ = ""
        dimension = vehicles = 0
        capacity = 0.0
        edge_weight_type = ""
        nodes = {}
        depot_node = []
        section = None
        for line in lines:
            line = line.strip()
            if not line:
                continue
            if line.startswith("NAME"):
                name = line.split(":")[1].strip()
            elif line.startswith("TYPE"):
                type_ = line.split(":")[1].strip()
            elif line.startswith("DIMENSION"):
                dimension = int(line.split(":")[1].strip())
            elif line.startswith("VEHICLES"):
                vehicles = int(line.split(":")[1].strip())
            elif line.startswith("CAPACITY"):
                capacity = float(line.split(":")[1].strip())
            elif line.startswith("EDGE_WEIGHT_TYPE"):
                edge_weight_type = line.split(":")[1].strip()
            elif line == "NODE_COORD_SECTION":
                section = "NODE"
            elif line == "PICKUP_AND_DELIVERY_SECTION":
                section = "PD"
            elif line == "DEPOT_SECTION":
                section = "DEPOT"
            elif line == "EOF":
                break
            elif section == "NODE":
                parts = line.split()
                idx = int(parts[0])
                nodes[idx] = Node(idx, float(parts[1]), float(parts[2]),
                                  0, 0, 0, 0, 0, 0, False)
            elif section == "PD":
                parts = line.split()
                idx = int(parts[0])
                if idx in nodes:
                    n = nodes[idx]
                    n.demand = float(parts[1])
                    n.earliest_time = float(parts[2])
                    n.latest_time = float(parts[3])
                    n.service_time = float(parts[4])
                    n.pickup_sibling = int(parts[5])
                    n.delivery_sibling = int(parts[6])
                    n.is_pickup = (n.pickup_sibling == 0)
            elif section == "DEPOT":
                if line != "-1":
                    depot_node.append(int(line))
        return Instance(name, type_, dimension, vehicles, capacity,
                        edge_weight_type, nodes, depot_node)

    inst = read_instance(input_file)
    nodes = inst.nodes
    depot = inst.depot_node[0]
    cap = inst.capacity
    max_v = inst.vehicles

    # Distance matrix
    dist = {}
    for i in nodes:
        for j in nodes:
            dx = nodes[i].x - nodes[j].x
            dy = nodes[i].y - nodes[j].y
            dist[(i, j)] = round(math.sqrt(dx * dx + dy * dy))

    # Pickup-delivery pairs
    requests = []
    for idx, n in nodes.items():
        if n.is_pickup and n.delivery_sibling > 0 and idx != depot:
            d = n.delivery_sibling
            if d in nodes and d != depot:
                requests.append((idx, d))
    requests.sort(key=lambda r: nodes[r[0]].earliest_time)

    def check_route(route):
        """Return (feasible, distance)."""
        if len(route) < 2:
            return True, 0.0
        td = 0.0
        cl = 0.0
        ct = 0.0
        for i, nid in enumerate(route):
            nd = nodes[nid]
            if i > 0:
                td += dist[(route[i - 1], nid)]
                ct += dist[(route[i - 1], nid)]
            if ct > nd.latest_time + 1e-9:
                return False, float('inf')
            ct = max(ct, nd.earliest_time) + nd.service_time
            cl += nd.demand
            if cl < -1e-9 or cl > cap + 1e-9:
                return False, float('inf')
        return True, td

    def rdist(route):
        _, d = check_route(route)
        return d

    # Greedy construction
    def construct():
        routes = []
        for p, d in requests:
            bi, bj, br, bc = -1, -1, None, float('inf')
            for ri, r in enumerate(routes):
                for i in range(1, len(r)):
                    for j in range(i, len(r)):
                        nr = r[:i] + [p] + r[i:j] + [d] + r[j:]
                        ok, c = check_route(nr)
                        if ok and c < bc:
                            bi, bj, br, bc = ri, -1, nr, c
            if br is not None and bc < float('inf'):
                routes[bi] = br
            elif len(routes) < max_v:
                nr = [depot, p, d, depot]
                ok, _ = check_route(nr)
                if ok:
                    routes.append(nr)
                else:
                    # Try harder: insert into any existing route at any position
                    placed = False
                    for ri, r in enumerate(routes):
                        for i in range(1, len(r)):
                            for j in range(i, len(r)):
                                nr = r[:i] + [p] + r[i:j] + [d] + r[j:]
                                ok2, _ = check_route(nr)
                                if ok2:
                                    routes[ri] = nr
                                    placed = True
                                    break
                            if placed:
                                break
                        if placed:
                            break
            else:
                # No new route allowed, force into existing
                for ri, r in enumerate(routes):
                    placed = False
                    for i in range(1, len(r)):
                        for j in range(i, len(r)):
                            nr = r[:i] + [p] + r[i:j] + [d] + r[j:]
                            ok, _ = check_route(nr)
                            if ok:
                                routes[ri] = nr
                                placed = True
                                break
                        if placed:
                            break
                    if placed:
                        break
        return routes

    # Local search with simulated annealing
    def sa(routes, tl):
        st = time.time()
        cr = deepcopy(routes)
        cc = sum(rdist(r) for r in cr)
        br = deepcopy(cr)
        bc = cc
        T = 80.0

        def get_reqs(route):
            out = []
            for i, n in enumerate(route):
                if nodes[n].is_pickup and n != depot:
                    dn = nodes[n].delivery_sibling
                    for j in range(i + 1, len(route)):
                        if route[j] == dn:
                            out.append((i, j, n, dn))
                            break
            return out

        while time.time() - st < tl:
            if not cr:
                break
            ri = random.randrange(len(cr))
            r = cr[ri]
            reqs = get_reqs(r)
            if not reqs:
                T *= 0.999
                continue
            pi, di, pn, dn = random.choice(reqs)

            # Remove request
            tmp = r[:pi] + r[pi + 1:di] + r[di + 1:]

            # Try reinsertion
            best_nr = None
            best_nc = float('inf')
            for ti in range(len(cr)):
                tr = tmp if ti == ri else cr[ti]
                for ii in range(1, len(tr)):
                    for jj in range(ii, len(tr)):
                        cand = tr[:ii] + [pn] + tr[ii:jj] + [dn] + tr[jj:]
                        ok, c = check_route(cand)
                        if ok:
                            if ti == ri:
                                tc = c + sum(rdist(cr[k]) for k in range(len(cr)) if k != ri)
                            else:
                                ok2, c2 = check_route(tmp)
                                if not ok2:
                                    continue
                                tc = c + c2 + sum(rdist(cr[k]) for k in range(len(cr)) if k != ri and k != ti)
                            if tc < best_nc:
                                best_nc = tc
                                if ti == ri:
                                    best_nr = deepcopy(cr)
                                    best_nr[ri] = cand
                                else:
                                    best_nr = deepcopy(cr)
                                    best_nr[ri] = tmp
                                    best_nr[ti] = cand

            if best_nr is not None:
                delta = best_nc - cc
                if delta < 0 or random.random() < math.exp(-delta / max(T, 0.01)):
                    cr = best_nr
                    cc = best_nc
                    if cc < bc:
                        br = deepcopy(cr)
                        bc = cc
            T *= 0.9995

        return br

    routes = construct()
    elapsed = time.time()
    routes = sa(routes, max(1.0, 55.0 - (time.time() - elapsed)))

    # Ensure depot at start/end
    final = []
    for r in routes:
        if len(r) >= 2:
            if r[0] != depot:
                r = [depot] + r
            if r[-1] != depot:
                r = r + [depot]
            ok, _ = check_route(r)
            if ok:
                final.append(r)

    with open(solution_file, 'w') as f:
        f.write(f"{inst.name}\n")
        for r in final:
            f.write(" ".join(map(str, r)) + "\n")

