import json
import heapq

def solve(input_file: str, solution_file: str):
    # Read input
    with open(input_file, 'r') as f:
        data = json.load(f)

    delay = data['delay']
    resource_limit = data['resource']
    nodes = data['nodes']
    edges = data['edges']

    # Build graph
    node_ids = [node[0] for node in nodes]
    node_type = {node[0]: node[1] for node in nodes}
    preds = {nid: [] for nid in node_ids}
    succs = {nid: [] for nid in node_ids}
    for src, tgt, _ in edges:
        preds[tgt].append(src)
        succs[src].append(tgt)

    # Topological order (Kahn's algorithm)
    in_degree = {nid: len(preds[nid]) for nid in node_ids}
    queue = [nid for nid in node_ids if in_degree[nid] == 0]
    topo_order = []
    while queue:
        nid = queue.pop()
        topo_order.append(nid)
        for succ in succs[nid]:
            in_degree[succ] -= 1
            if in_degree[succ] == 0:
                queue.append(succ)

    # ASAP times
    asap = {nid: 0 for nid in node_ids}
    for nid in topo_order:
        for pred in preds[nid]:
            asap[nid] = max(asap[nid], asap[pred] + delay[node_type[pred]])

    # Bottom level (longest path to exit)
    bottom = {nid: 0 for nid in node_ids}
    for nid in reversed(topo_order):
        d = delay[node_type[nid]]
        if succs[nid]:
            bottom[nid] = d + max(bottom[succ] for succ in succs[nid])
        else:
            bottom[nid] = d

    # Helper to compute schedule given a fixed order
    def compute_schedule(order):
        heaps = {}
        for r, G in resource_limit.items():
            heaps[r] = [0] * G
            heapq.heapify(heaps[r])
        schedule = {}
        for nid in order:
            # earliest start due to precedence
            earliest = 0
            for pred in preds[nid]:
                earliest = max(earliest, schedule[pred] + delay[node_type[pred]])
            r = node_type[nid]
            d = delay[r]
            heap = heaps[r]
            t_res = heapq.heappop(heap)
            start = max(earliest, t_res)
            schedule[nid] = start
            heapq.heappush(heap, start + d)
        return schedule

    # Try several ordering heuristics and keep the best
    best_schedule = None
    best_makespan = float('inf')
    orders = [
        sorted(node_ids, key=lambda nid: (-bottom[nid],)),
        sorted(node_ids, key=lambda nid: (asap[nid], -bottom[nid])),
        sorted(node_ids, key=lambda nid: (asap[nid],)),
    ]
    for order in orders:
        sched = compute_schedule(order)
        makespan = max(sched[nid] + delay[node_type[nid]] for nid in node_ids)
        if makespan < best_makespan:
            best_makespan = makespan
            best_schedule = sched

    # Local improvement: try to shift each operation earlier
    def is_feasible(nid, t, sched):
        # Precedence check
        for pred in preds[nid]:
            if sched[pred] + delay[node_type[pred]] > t:
                return False
        r = node_type[nid]
        d = delay[r]
        G = resource_limit[r]
        cnt = 0
        for other in node_ids:
            if other == nid or node_type[other] != r:
                continue
            s_other = sched[other]
            if s_other < t + d and s_other + delay[node_type[other]] > t:
                cnt += 1
                if cnt >= G:
                    return False
        return True

    improved = True
    max_passes = 5
    passes = 0
    while improved and passes < max_passes:
        improved = False
        passes += 1
        for nid in reversed(topo_order):
            current = best_schedule[nid]
            earliest = 0
            for pred in preds[nid]:
                earliest = max(earliest, best_schedule[pred] + delay[node_type[pred]])
            if earliest >= current:
                continue
            lo, hi = earliest, current - 1
            best_t = current
            while lo <= hi:
                mid = (lo + hi) // 2
                if is_feasible(nid, mid, best_schedule):
                    best_t = mid
                    hi = mid - 1
                else:
                    lo = mid + 1
            if best_t < current:
                best_schedule[nid] = best_t
                improved = True

    # Write output
    with open(solution_file, 'w') as f:
        for node in nodes:
            nid = node[0]
            f.write(f"{nid}:{best_schedule[nid]}\n")

