import sys
from collections import deque

def solve(input_file: str, solution_file: str):
    # Parse input
    individuals = []
    id_to_index = {}
    with open(input_file, 'r') as f:
        for line in f:
            parts = list(map(int, line.strip().split()))
            if not parts:
                continue
            locus, ind_id, father_id, mother_id, sex, a1, a2 = parts
            individuals.append((ind_id, father_id, mother_id, sex, a1, a2))
            id_to_index[ind_id] = len(individuals) - 1

    m = len(individuals)
    if m == 0:
        open(solution_file, 'w').close()
        return

    # Build pedigree structure
    parents = [(-1, -1) for _ in range(m)]
    children = [[] for _ in range(m)]
    observed = [(0, 0) for _ in range(m)]

    for idx, (ind_id, fid, mid, sex, a1, a2) in enumerate(individuals):
        observed[idx] = (a1, a2)
        if fid != 0:
            fidx = id_to_index[fid]
            parents[idx] = (fidx, parents[idx][1])
            children[fidx].append(idx)
        if mid != 0:
            midx = id_to_index[mid]
            parents[idx] = (parents[idx][0], midx)
            children[midx].append(idx)

    # Determine maximum allele
    max_allele = 0
    for a1, a2 in observed:
        max_allele = max(max_allele, a1, a2)
    n = max(1, max_allele)

    # Generate all possible genotypes
    genotypes = []
    for a in range(1, n + 1):
        for b in range(a, n + 1):
            genotypes.append((a, b))
    K = len(genotypes)

    # Precompute unary costs
    unary_cost = [[0] * K for _ in range(m)]
    for i in range(m):
        oa, ob = observed[i]
        for g_idx, (a, b) in enumerate(genotypes):
            if oa > 0 and ob > 0:
                if (min(oa, ob), max(oa, ob)) != (a, b):
                    unary_cost[i][g_idx] = 1
            elif oa > 0 and ob == 0:
                if a != oa and b != oa:
                    unary_cost[i][g_idx] = 1
            elif oa == 0 and ob > 0:
                if a != ob and b != ob:
                    unary_cost[i][g_idx] = 1

    # Helper functions
    def share_allele(g1, g2):
        a1, a2 = genotypes[g1]
        b1, b2 = genotypes[g2]
        return a1 == b1 or a1 == b2 or a2 == b1 or a2 == b2

    def ternary_allowed(g1, g2, g3):
        a1, a2 = genotypes[g1]
        b1, b2 = genotypes[g2]
        c1, c2 = genotypes[g3]
        return (c1 == a1 or c1 == a2) and (c2 == b1 or c2 == b2)

    # Backtracking with forward checking
    best_cost = [float('inf')]
    best_assignment = [None]

    # Order by degree heuristic
    constraint_count = [len(parents[i]) + len(children[i]) for i in range(m)]
    order = sorted(range(m), key=lambda i: constraint_count[i])

    def forward_check(assignment, domains, idx, genotype):
        """Forward check after assigning genotype to individual idx"""
        new_domains = [d[:] for d in domains]

        # Check consistency with assigned parents
        father, mother = parents[idx]
        if father != -1 and assignment[father] != -1:
            if not share_allele(assignment[father], genotype):
                return None
        if mother != -1 and assignment[mother] != -1:
            if not share_allele(assignment[mother], genotype):
                return None

        # Filter unassigned parents' domains
        if father != -1 and assignment[father] == -1:
            new_domains[father] = [g for g in new_domains[father] 
                                   if share_allele(genotype, g)]
            if not new_domains[father]:
                return None

        if mother != -1 and assignment[mother] == -1:
            new_domains[mother] = [g for g in new_domains[mother] 
                                   if share_allele(genotype, g)]
            if not new_domains[mother]:
                return None

        # Check consistency with assigned children
        for child in children[idx]:
            if assignment[child] != -1:
                f_child, m_child = parents[child]
                other = m_child if f_child == idx else f_child
                if other != -1 and assignment[other] != -1:
                    if not ternary_allowed(assignment[other], genotype, assignment[child]):
                        return None
                    if not ternary_allowed(genotype, assignment[other], assignment[child]):
                        return None

        # Filter children's domains
        for child in children[idx]:
            if assignment[child] == -1:
                f_child, m_child = parents[child]
                other = m_child if f_child == idx else f_child

                if other != -1 and assignment[other] != -1:
                    # Other parent assigned - check ternary
                    new_domains[child] = [g for g in new_domains[child]
                                         if ternary_allowed(genotype, assignment[other], g)]
                elif other != -1 and assignment[other] == -1:
                    # Other parent unassigned - check if any combination works
                    other_domain = new_domains[other]
                    new_child_domain = []
                    for gc in new_domains[child]:
                        c1, c2 = genotypes[gc]
                        # Check if there exists some g_other in other_domain
                        # such that ternary_allowed(genotype, g_other, gc) or
                        # ternary_allowed(g_other, genotype, gc)
                        valid = False
                        for g_other in other_domain:
                            if ternary_allowed(genotype, g_other, gc) or ternary_allowed(g_other, genotype, gc):
                                valid = True
                                break
                        if valid:
                            new_child_domain.append(gc)
                    new_domains[child] = new_child_domain
                else:
                    # No other parent - just binary check
                    new_domains[child] = [g for g in new_domains[child]
                                         if share_allele(genotype, g)]

                if not new_domains[child]:
                    return None

        # Also filter other parent's domain for children
        for child in children[idx]:
            if assignment[child] == -1:
                f_child, m_child = parents[child]
                other = m_child if f_child == idx else f_child
                if other != -1 and assignment[other] == -1:
                    # Filter other parent based on child's domain
                    child_domain = new_domains[child]
                    other_domain = new_domains[other]
                    new_other_domain = []
                    for go in other_domain:
                        valid = False
                        for gc in child_domain:
                            if ternary_allowed(genotype, go, gc) or ternary_allowed(go, genotype, gc):
                                valid = True
                                break
                        if valid:
                            new_other_domain.append(go)
                    new_domains[other] = new_other_domain
                    if not new_other_domain:
                        return None

        return new_domains

    def backtrack(assignment, domains, idx, cost):
        if idx == m:
            if cost < best_cost[0]:
                best_cost[0] = cost
                best_assignment[0] = assignment[:]
            return

        i = order[idx]

        # Try genotypes in order of increasing unary cost
        domain_sorted = sorted(domains[i], key=lambda g: unary_cost[i][g])

        for g in domain_sorted:
            new_cost = cost + unary_cost[i][g]
            if new_cost >= best_cost[0]:
                continue

            new_domains = forward_check(assignment, domains, i, g)
            if new_domains is not None:
                assignment[i] = g
                backtrack(assignment, new_domains, idx + 1, new_cost)
                assignment[i] = -1

    # Start search
    initial_domains = [list(range(K)) for _ in range(m)]
    start_assignment = [-1] * m
    backtrack(start_assignment, initial_domains, 0, 0)

    # Write output
    with open(solution_file, 'w') as f:
        if best_assignment[0] is not None:
            f.write(' '.join(str(x) for x in best_assignment[0]))
        else:
            # Fallback
            fallback = [str(min(range(K), key=lambda g: unary_cost[i][g])) for i in range(m)]
            f.write(' '.join(fallback))

if __name__ == "__main__":
    solve("input.pre", "output.txt")
